{
  "name": "Smart Collage Studio",
  "description": "An intelligent image stitching web app that automatically organizes multiple JPGs into optimized grids (like 2x3 or 3x2) based on aspect ratios, featuring AI-powered captioning and high-quality exports.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface ImageFile {
  id: string;
  file: File;
  preview: string;
  width: number;
  height: number;
  aspectRatio: number;
}

export interface CollageSettings {
  columns: number;
  rows: number;
  gap: number;
  padding: number;
  backgroundColor: string;
  targetRatio: '5:4' | '4:5' | 'auto';
  quality: number;
}

export interface GridDimensions {
  cols: number;
  rows: number;
  cellWidth: number;
  cellHeight: number;
  totalWidth: number;
  totalHeight: number;
}

import { GoogleGenAI } from "@google/genai";

export const generateCollageCaption = async (collageDataUrl: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const base64Data = collageDataUrl.split(',')[1];

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        {
          parts: [
            { text: "Look at this image collage. Provide a short, poetic, and creative title or caption (max 10 words) that describes the overall vibe or theme of these images combined. Answer in Chinese if the content seems local to Taiwan/China, otherwise English." },
            {
              inlineData: {
                mimeType: 'image/jpeg',
                data: base64Data
              }
            }
          ]
        }
      ]
    });

    return response.text?.trim() || "My New Collage";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Beautiful Moments";
  }
};

import { ImageFile, CollageSettings, GridDimensions } from '../types';

export const loadImage = (url: string): Promise<HTMLImageElement> => {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => resolve(img);
    img.onerror = reject;
    img.src = url;
  });
};

export const calculateBestGrid = (
  count: number,
  avgAspectRatio: number,
  targetRatio: '5:4' | '4:5' | 'auto'
): { cols: number; rows: number } => {
  if (count === 0) return { cols: 1, rows: 1 };

  // If user specified 5:4 (landscape overall)
  // TotalW / TotalH = (cols * w) / (rows * h) = (cols/rows) * avgAspectRatio ≈ 1.25
  // cols * rows >= count

  let bestCols = 1;
  let bestRows = count;
  let minDiff = Infinity;

  const targetValue = targetRatio === '5:4' ? 1.25 : targetRatio === '4:5' ? 0.8 : 1.0;

  for (let cols = 1; cols <= count; cols++) {
    const rows = Math.ceil(count / cols);
    const currentRatio = (cols / rows) * avgAspectRatio;
    const diff = Math.abs(currentRatio - targetValue);

    if (diff < minDiff) {
      minDiff = diff;
      bestCols = cols;
      bestRows = rows;
    }
  }

  // Handle specific user request: "6 images: 2x3 for 5:4 (portrait-leaning source?) or inverse"
  // Actually, if we have 6 vertical images (say 2:3 ratio), 2 wide x 3 high gives total ratio (2*2)/(3*3) = 4/9.
  // The user's example 2x3 might be optimized for specific visual balance.

  return { cols: bestCols, rows: bestRows };
};

export const getDimensions = (
  images: ImageFile[],
  settings: CollageSettings
): GridDimensions => {
  const { columns, rows, gap, padding } = settings;

  // Use the first image as a reference for sizing or assume uniform sizing
  const refImg = images[0] || { width: 1000, height: 1000 };
  const cellWidth = refImg.width;
  const cellHeight = refImg.height;

  const totalWidth = (columns * cellWidth) + ((columns - 1) * gap) + (padding * 2);
  const totalHeight = (rows * cellHeight) + ((rows - 1) * gap) + (padding * 2);

  return {
    cols: columns,
    rows,
    cellWidth,
    cellHeight,
    totalWidth,
    totalHeight
  };
};

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { 
  Upload, 
  Download, 
  Trash2, 
  LayoutGrid, 
  Maximize2, 
  Settings2, 
  Sparkles,
  ChevronRight,
  ChevronLeft,
  X
} from 'lucide-react';
import { ImageFile, CollageSettings } from './types';
import { loadImage, calculateBestGrid, getDimensions } from './utils/image';
import { generateCollageCaption } from './services/gemini';

const App: React.FC = () => {
  const [images, setImages] = useState<ImageFile[]>([]);
  const [settings, setSettings] = useState<CollageSettings>({
    columns: 2,
    rows: 3,
    gap: 20,
    padding: 40,
    backgroundColor: '#ffffff',
    targetRatio: '5:4',
    quality: 0.9
  });
  const [isProcessing, setIsProcessing] = useState(false);
  const [aiCaption, setAiCaption] = useState<string>('');
  const [isGeneratingCaption, setIsGeneratingCaption] = useState(false);

  const canvasRef = useRef<HTMLCanvasElement>(null);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (files.length === 0) return;

    setIsProcessing(true);
    const newImages: ImageFile[] = [];

    for (const file of files) {
      const url = URL.createObjectURL(file);
      const img = await loadImage(url);
      newImages.push({
        id: Math.random().toString(36).substr(2, 9),
        file,
        preview: url,
        width: img.width,
        height: img.height,
        aspectRatio: img.width / img.height
      });
    }

    const updatedImages = [...images, ...newImages];
    setImages(updatedImages);

    // Auto-layout logic
    if (updatedImages.length > 0) {
      const avgRatio = updatedImages.reduce((sum, img) => sum + img.aspectRatio, 0) / updatedImages.length;
      const { cols, rows } = calculateBestGrid(updatedImages.length, avgRatio, settings.targetRatio);
      setSettings(prev => ({ ...prev, columns: cols, rows }));
    }

    setIsProcessing(false);
  };

  const removeImage = (id: string) => {
    setImages(prev => prev.filter(img => img.id !== id));
  };

  const drawCollage = useCallback(async () => {
    if (!canvasRef.current || images.length === 0) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dims = getDimensions(images, settings);
    canvas.width = dims.totalWidth;
    canvas.height = dims.totalHeight;

    // Background
    ctx.fillStyle = settings.backgroundColor;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);

      const x = settings.padding + (col * (dims.cellWidth + settings.gap));
      const y = settings.padding + (row * (dims.cellHeight + settings.gap));

      try {
        const img = await loadImage(images[i].preview);

        // Draw with "Cover" logic (centering)
        const cellAspect = dims.cellWidth / dims.cellHeight;
        const imgAspect = img.width / img.height;

        let drawWidth = dims.cellWidth;
        let drawHeight = dims.cellHeight;
        let offsetX = 0;
        let offsetY = 0;

        if (imgAspect > cellAspect) {
          // Image is wider than cell
          const scale = dims.cellHeight / img.height;
          const scaledWidth = img.width * scale;
          ctx.drawImage(img, x - (scaledWidth - dims.cellWidth) / 2, y, scaledWidth, dims.cellHeight);
        } else {
          // Image is taller than cell
          const scale = dims.cellWidth / img.width;
          const scaledHeight = img.height * scale;
          ctx.drawImage(img, x, y - (scaledHeight - dims.cellHeight) / 2, dims.cellWidth, scaledHeight);
        }

        // Clip the excess
        ctx.strokeStyle = settings.backgroundColor;
        ctx.lineWidth = 2;
        ctx.strokeRect(x, y, dims.cellWidth, dims.cellHeight);

      } catch (err) {
        console.error("Failed to draw image", i, err);
      }
    }
  }, [images, settings]);

  useEffect(() => {
    drawCollage();
  }, [drawCollage]);

  const downloadCollage = () => {
    if (!canvasRef.current) return;
    const link = document.createElement('a');
    link.download = `smart-collage-${Date.now()}.jpg`;
    link.href = canvasRef.current.toDataURL('image/jpeg', settings.quality);
    link.click();
  };

  const handleAiCaption = async () => {
    if (!canvasRef.current || images.length === 0) return;
    setIsGeneratingCaption(true);
    const dataUrl = canvasRef.current.toDataURL('image/jpeg', 0.5);
    const caption = await generateCollageCaption(dataUrl);
    setAiCaption(caption);
    setIsGeneratingCaption(false);
  };

  return (
    <div className="min-h-screen flex flex-col lg:flex-row bg-slate-900 text-slate-100">
      {/* Sidebar Controls */}
      <aside className="w-full lg:w-96 bg-slate-800 border-r border-slate-700 overflow-y-auto p-6 space-y-8 sticky top-0 h-screen hidden lg:block">
        <div className="flex items-center gap-2 mb-8">
          <div className="p-2 bg-indigo-600 rounded-lg">
            <LayoutGrid className="w-6 h-6" />
          </div>
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
            Stitcher Studio
          </h1>
        </div>

        <section className="space-y-4">
          <h2 className="text-sm font-semibold uppercase tracking-wider text-slate-400 flex items-center gap-2">
            <Settings2 className="w-4 h-4" /> Layout Settings
          </h2>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs text-slate-500 mb-1">Columns</label>
              <input 
                type="number" 
                value={settings.columns} 
                onChange={e => setSettings(s => ({ ...s, columns: parseInt(e.target.value) || 1 }))}
                className="w-full bg-slate-900 border border-slate-700 rounded-md p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-xs text-slate-500 mb-1">Rows</label>
              <input 
                type="number" 
                value={settings.rows} 
                onChange={e => setSettings(s => ({ ...s, rows: parseInt(e.target.value) || 1 }))}
                className="w-full bg-slate-900 border border-slate-700 rounded-md p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>
          </div>

          <div>
            <label className="block text-xs text-slate-500 mb-1">Target Ratio Hint</label>
            <div className="flex gap-2">
              {(['5:4', '4:5', 'auto'] as const).map(r => (
                <button
                  key={r}
                  onClick={() => setSettings(s => ({ ...s, targetRatio: r }))}
                  className={`flex-1 py-2 text-xs rounded-md border transition ${
                    settings.targetRatio === r 
                      ? 'bg-indigo-600 border-indigo-500 text-white' 
                      : 'bg-slate-900 border-slate-700 text-slate-400 hover:border-slate-500'
                  }`}
                >
                  {r}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-xs text-slate-500 mb-1">Spacing (Gap)</label>
            <input 
              type="range" min="0" max="100" 
              value={settings.gap} 
              onChange={e => setSettings(s => ({ ...s, gap: parseInt(e.target.value) }))}
              className="w-full h-2 bg-slate-900 rounded-lg appearance-none cursor-pointer accent-indigo-500"
            />
          </div>

          <div>
            <label className="block text-xs text-slate-500 mb-1">Outer Padding</label>
            <input 
              type="range" min="0" max="200" 
              value={settings.padding} 
              onChange={e => setSettings(s => ({ ...s, padding: parseInt(e.target.value) }))}
              className="w-full h-2 bg-slate-900 rounded-lg appearance-none cursor-pointer accent-indigo-500"
            />
          </div>

          <div>
            <label className="block text-xs text-slate-500 mb-1">Background Color</label>
            <div className="flex gap-2">
              <input 
                type="color" 
                value={settings.backgroundColor} 
                onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))}
                className="w-10 h-10 bg-transparent border-none cursor-pointer rounded overflow-hidden"
              />
              <input 
                type="text" 
                value={settings.backgroundColor} 
                onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))}
                className="flex-1 bg-slate-900 border border-slate-700 rounded-md px-3 text-sm"
              />
            </div>
          </div>
        </section>

        <section className="space-y-4">
          <h2 className="text-sm font-semibold uppercase tracking-wider text-slate-400 flex items-center gap-2">
            <Sparkles className="w-4 h-4" /> AI Magic
          </h2>
          <button
            onClick={handleAiCaption}
            disabled={images.length === 0 || isGeneratingCaption}
            className="w-full flex items-center justify-center gap-2 py-3 px-4 rounded-lg bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-500 hover:to-indigo-500 disabled:opacity-50 disabled:cursor-not-allowed font-medium transition shadow-lg shadow-indigo-900/20"
          >
            {isGeneratingCaption ? 'AI is thinking...' : 'Generate AI Caption'}
          </button>
          {aiCaption && (
            <div className="p-4 bg-slate-900 border border-indigo-500/30 rounded-lg italic text-slate-300 text-sm animate-in fade-in slide-in-from-bottom-2">
              "{aiCaption}"
            </div>
          )}
        </section>

        <div className="pt-8 border-t border-slate-700">
          <button
            onClick={downloadCollage}
            disabled={images.length === 0}
            className="w-full flex items-center justify-center gap-2 py-3 px-4 rounded-lg bg-white text-slate-900 hover:bg-slate-200 disabled:opacity-50 disabled:cursor-not-allowed font-bold transition shadow-xl"
          >
            <Download className="w-5 h-5" /> Download JPG
          </button>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden bg-slate-950">
        {/* Header Mobile / Info */}
        <header className="p-4 bg-slate-900 lg:bg-transparent border-b border-slate-800 lg:border-none flex justify-between items-center">
          <div className="lg:hidden flex items-center gap-2">
            <LayoutGrid className="w-5 h-5 text-indigo-500" />
            <span className="font-bold">Stitcher Studio</span>
          </div>
          <div className="text-sm text-slate-400">
            {images.length} image{images.length !== 1 ? 's' : ''} uploaded
          </div>
          <div className="flex gap-2">
             <label className="cursor-pointer group">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <div className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 rounded-full text-sm font-medium transition shadow-lg shadow-indigo-900/40">
                <Upload className="w-4 h-4" />
                <span>Upload Photos</span>
              </div>
            </label>
          </div>
        </header>

        {/* Preview Area */}
        <div className="flex-1 overflow-auto p-4 lg:p-12 flex items-center justify-center relative">
          {images.length === 0 ? (
            <div className="text-center space-y-4 max-w-md animate-in zoom-in duration-500">
              <div className="w-20 h-20 bg-slate-800 rounded-3xl flex items-center justify-center mx-auto border border-slate-700">
                <Upload className="w-10 h-10 text-slate-500" />
              </div>
              <h3 className="text-xl font-bold">Start your masterpiece</h3>
              <p className="text-slate-500 text-sm">
                Upload multiple images to stitch them into a beautiful grid automatically.
              </p>
              <label className="inline-block cursor-pointer px-8 py-4 bg-white text-slate-900 rounded-xl font-bold hover:scale-105 transition active:scale-95 shadow-2xl">
                <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
                Select JPG / PNG files
              </label>
            </div>
          ) : (
            <div className="relative group max-h-full">
              <div className="shadow-[0_0_80px_rgba(0,0,0,0.5)] rounded-lg overflow-hidden border border-slate-800 bg-white/5 backdrop-blur-sm">
                <canvas 
                  ref={canvasRef} 
                  className="max-w-full max-h-[70vh] object-contain mx-auto transition-all duration-300"
                />
              </div>
              <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                <button 
                  onClick={() => setImages([])}
                  className="p-2 bg-red-600/90 hover:bg-red-500 text-white rounded-lg shadow-lg"
                  title="Clear All"
                >
                  <Trash2 className="w-5 h-5" />
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Thumbnail Reel */}
        {images.length > 0 && (
          <div className="h-32 bg-slate-900/80 backdrop-blur-md border-t border-slate-800 p-4 flex gap-4 overflow-x-auto items-center">
            {images.map((img) => (
              <div key={img.id} className="relative flex-shrink-0 group">
                <img 
                  src={img.preview} 
                  alt="Thumbnail" 
                  className="h-24 w-24 object-cover rounded-lg border-2 border-slate-700 group-hover:border-indigo-500 transition cursor-move" 
                />
                <button 
                  onClick={() => removeImage(img.id)}
                  className="absolute -top-2 -right-2 p-1 bg-slate-800 rounded-full border border-slate-700 text-slate-400 hover:text-white transition"
                >
                  <X className="w-3 h-3" />
                </button>
              </div>
            ))}
            <label className="flex-shrink-0 h-24 w-24 flex flex-col items-center justify-center border-2 border-dashed border-slate-700 rounded-lg hover:border-indigo-500 hover:bg-indigo-500/5 cursor-pointer transition text-slate-500 hover:text-indigo-400">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <Upload className="w-5 h-5 mb-1" />
              <span className="text-[10px] uppercase font-bold tracking-tighter">Add More</span>
            </label>
          </div>
        )}
      </main>

      {/* Mobile Drawer Controls Trigger (Simplified for Demo) */}
      <div className="lg:hidden fixed bottom-4 right-4 z-50">
        <button 
          onClick={downloadCollage}
          className="p-4 bg-indigo-600 rounded-full shadow-2xl text-white active:scale-95 transition"
        >
          <Download className="w-6 h-6" />
        </button>
      </div>
    </div>
  );
};

export default App;

