  const canvasRef = useRef<HTMLCanvasElement>(null);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    // Fix: Explicitly cast to File[] to avoid 'unknown' or '{}' type inference errors from FileList
    const files = Array.from(e.target.files || []) as File[];
    if (files.length === 0) return;

    setIsProcessing(true);
    const newImages: ImageFile[] = [];

    for (const file of files) {
      // Fix: 'file' is now correctly typed as File, satisfying URL.createObjectURL requirements
      const url = URL.createObjectURL(file);
      const img = await loadImage(url);
      newImages.push({
        id: Math.random().toString(36).substr(2, 9),
        // Fix: 'file' correctly maps to File type defined in ImageFile interface
        file,
        preview: url,
        width: img.width,
        height: img.height,
        aspectRatio: img.width / img.height
      });
    }

    const updatedImages = [...images, ...newImages];
    setImages(updatedImages);

