      const { cols, rows } = calculateBestGrid(updatedImages.length, avgRatio, settings.targetRatio);
      setSettings(prev => ({ ...prev, columns: cols, rows }));
    }

    setIsProcessing(false);
  };

  const removeImage = (id: string) => {
    setImages(prev => prev.filter(img => img.id !== id));
  };

  const drawCollage = useCallback(async () => {
    if (!canvasRef.current || images.length === 0) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dims = getDimensions(images, settings);
    canvas.width = dims.totalWidth;
    canvas.height = dims.totalHeight;

