    ctx.fillStyle = settings.backgroundColor;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);

      const x = settings.padding + (col * (dims.cellWidth + settings.gap));
      const y = settings.padding + (row * (dims.cellHeight + settings.gap));

      try {
        const img = await loadImage(images[i].preview);

        // Draw with "Cover" logic (centering)
        const cellAspect = dims.cellWidth / dims.cellHeight;
        const imgAspect = img.width / img.height;

        let drawWidth = dims.cellWidth;
        let drawHeight = dims.cellHeight;
        let offsetX = 0;
        let offsetY = 0;

        if (imgAspect > cellAspect) {
          // Image is wider than cell
          const scale = dims.cellHeight / img.height;
          const scaledWidth = img.width * scale;
          ctx.drawImage(img, x - (scaledWidth - dims.cellWidth) / 2, y, scaledWidth, dims.cellHeight);
        } else {
          // Image is taller than cell
          const scale = dims.cellWidth / img.width;
          const scaledHeight = img.height * scale;
          ctx.drawImage(img, x, y - (scaledHeight - dims.cellHeight) / 2, dims.cellWidth, scaledHeight);
        }

        // Clip the excess
        ctx.strokeStyle = settings.backgroundColor;
        ctx.lineWidth = 2;
        ctx.strokeRect(x, y, dims.cellWidth, dims.cellHeight);

      } catch (err) {
        console.error("Failed to draw image", i, err);
      }
    }
  }, [images, settings]);

  useEffect(() => {
    drawCollage();
  }, [drawCollage]);

  const downloadCollage = () => {
    if (!canvasRef.current) return;
    const link = document.createElement('a');
    link.download = `smart-collage-${Date.now()}.jpg`;
    link.href = canvasRef.current.toDataURL('image/jpeg', settings.quality);
    link.click();
  };

  const handleAiCaption = async () => {
    if (!canvasRef.current || images.length === 0) return;
    setIsGeneratingCaption(true);
    const dataUrl = canvasRef.current.toDataURL('image/jpeg', 0.5);
    const caption = await generateCollageCaption(dataUrl);
    setAiCaption(caption);
    setIsGeneratingCaption(false);
  };

  return (
    <div className="min-h-screen flex flex-col lg:flex-row bg-slate-900 text-slate-100">
      {/* Sidebar Controls */}
