          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs text-slate-500 mb-1">Columns</label>
              <input 
                type="number" 
                value={settings.columns} 
                onChange={e => setSettings(s => ({ ...s, columns: parseInt(e.target.value) || 1 }))}
                className="w-full bg-slate-900 border border-slate-700 rounded-md p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-xs text-slate-500 mb-1">Rows</label>
              <input 
                type="number" 
                value={settings.rows} 
                onChange={e => setSettings(s => ({ ...s, rows: parseInt(e.target.value) || 1 }))}
                className="w-full bg-slate-900 border border-slate-700 rounded-md p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>
          </div>

          <div>
            <label className="block text-xs text-slate-500 mb-1">Target Ratio Hint</label>
            <div className="flex gap-2">
              {(['5:4', '4:5', 'auto'] as const).map(r => (
                <button
                  key={r}
                  onClick={() => setSettings(s => ({ ...s, targetRatio: r }))}
                  className={`flex-1 py-2 text-xs rounded-md border transition ${
                    settings.targetRatio === r 
                      ? 'bg-indigo-600 border-indigo-500 text-white' 
                      : 'bg-slate-900 border-slate-700 text-slate-400 hover:border-slate-500'
                  }`}
                >
                  {r}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-xs text-slate-500 mb-1">Spacing (Gap)</label>
            <input 
              type="range" min="0" max="100" 
              value={settings.gap} 
              onChange={e => setSettings(s => ({ ...s, gap: parseInt(e.target.value) }))}
              className="w-full h-2 bg-slate-900 rounded-lg appearance-none cursor-pointer accent-indigo-500"
            />
          </div>

          <div>
            <label className="block text-xs text-slate-500 mb-1">Outer Padding</label>
            <input 
              type="range" min="0" max="200" 
              value={settings.padding} 
              onChange={e => setSettings(s => ({ ...s, padding: parseInt(e.target.value) }))}
              className="w-full h-2 bg-slate-900 rounded-lg appearance-none cursor-pointer accent-indigo-500"
            />
          </div>

          <div>
            <label className="block text-xs text-slate-500 mb-1">Background Color</label>
            <div className="flex gap-2">
              <input 
                type="color" 
                value={settings.backgroundColor} 
                onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))}
                className="w-10 h-10 bg-transparent border-none cursor-pointer rounded overflow-hidden"
              />
              <input 
                type="text" 
                value={settings.backgroundColor} 
                onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))}
                className="flex-1 bg-slate-900 border border-slate-700 rounded-md px-3 text-sm"
              />
            </div>
          </div>
        </section>

        <section className="space-y-4">
          <h2 className="text-sm font-semibold uppercase tracking-wider text-slate-400 flex items-center gap-2">
            <Sparkles className="w-4 h-4" /> AI Magic
          </h2>
          <button
            onClick={handleAiCaption}
            disabled={images.length === 0 || isGeneratingCaption}
            className="w-full flex items-center justify-center gap-2 py-3 px-4 rounded-lg bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-500 hover:to-indigo-500 disabled:opacity-50 disabled:cursor-not-allowed font-medium transition shadow-lg shadow-indigo-900/20"
          >
            {isGeneratingCaption ? 'AI is thinking...' : 'Generate AI Caption'}
          </button>
          {aiCaption && (
            <div className="p-4 bg-slate-900 border border-indigo-500/30 rounded-lg italic text-slate-300 text-sm animate-in fade-in slide-in-from-bottom-2">
              "{aiCaption}"
            </div>
          )}
        </section>

        <div className="pt-8 border-t border-slate-700">
          <button
            onClick={downloadCollage}
            disabled={images.length === 0}
            className="w-full flex items-center justify-center gap-2 py-3 px-4 rounded-lg bg-white text-slate-900 hover:bg-slate-200 disabled:opacity-50 disabled:cursor-not-allowed font-bold transition shadow-xl"
          >
            <Download className="w-5 h-5" /> Download JPG
          </button>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden bg-slate-950">
        {/* Header Mobile / Info */}
        <header className="p-4 bg-slate-900 lg:bg-transparent border-b border-slate-800 lg:border-none flex justify-between items-center">
          <div className="lg:hidden flex items-center gap-2">
            <LayoutGrid className="w-5 h-5 text-indigo-500" />
            <span className="font-bold">Stitcher Studio</span>
          </div>
          <div className="text-sm text-slate-400">
            {images.length} image{images.length !== 1 ? 's' : ''} uploaded
          </div>
          <div className="flex gap-2">
             <label className="cursor-pointer group">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <div className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 rounded-full text-sm font-medium transition shadow-lg shadow-indigo-900/40">
                <Upload className="w-4 h-4" />
                <span>Upload Photos</span>
              </div>
            </label>
          </div>
        </header>

        {/* Preview Area */}
        <div className="flex-1 overflow-auto p-4 lg:p-12 flex items-center justify-center relative">
          {images.length === 0 ? (
            <div className="text-center space-y-4 max-w-md animate-in zoom-in duration-500">
              <div className="w-20 h-20 bg-slate-800 rounded-3xl flex items-center justify-center mx-auto border border-slate-700">
                <Upload className="w-10 h-10 text-slate-500" />
              </div>
              <h3 className="text-xl font-bold">Start your masterpiece</h3>
              <p className="text-slate-500 text-sm">
                Upload multiple images to stitch them into a beautiful grid automatically.
              </p>
              <label className="inline-block cursor-pointer px-8 py-4 bg-white text-slate-900 rounded-xl font-bold hover:scale-105 transition active:scale-95 shadow-2xl">
                <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
                Select JPG / PNG files
              </label>
            </div>
          ) : (
            <div className="relative group max-h-full">
              <div className="shadow-[0_0_80px_rgba(0,0,0,0.5)] rounded-lg overflow-hidden border border-slate-800 bg-white/5 backdrop-blur-sm">
                <canvas 
                  ref={canvasRef} 
                  className="max-w-full max-h-[70vh] object-contain mx-auto transition-all duration-300"
                />
              </div>
              <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                <button 
                  onClick={() => setImages([])}
                  className="p-2 bg-red-600/90 hover:bg-red-500 text-white rounded-lg shadow-lg"
                  title="Clear All"
                >
                  <Trash2 className="w-5 h-5" />
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Thumbnail Reel */}
        {images.length > 0 && (
          <div className="h-32 bg-slate-900/80 backdrop-blur-md border-t border-slate-800 p-4 flex gap-4 overflow-x-auto items-center">
            {images.map((img) => (
              <div key={img.id} className="relative flex-shrink-0 group">
                <img 
                  src={img.preview} 
                  alt="Thumbnail" 
                  className="h-24 w-24 object-cover rounded-lg border-2 border-slate-700 group-hover:border-indigo-500 transition cursor-move" 
                />
                <button 
                  onClick={() => removeImage(img.id)}
                  className="absolute -top-2 -right-2 p-1 bg-slate-800 rounded-full border border-slate-700 text-slate-400 hover:text-white transition"
                >
                  <X className="w-3 h-3" />
                </button>
              </div>
            ))}
            <label className="flex-shrink-0 h-24 w-24 flex flex-col items-center justify-center border-2 border-dashed border-slate-700 rounded-lg hover:border-indigo-500 hover:bg-indigo-500/5 cursor-pointer transition text-slate-500 hover:text-indigo-400">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <Upload className="w-5 h-5 mb-1" />
              <span className="text-[10px] uppercase font-bold tracking-tighter">Add More</span>
            </label>
          </div>
        )}
      </main>

      {/* Mobile Drawer Controls Trigger (Simplified for Demo) */}
      <div className="lg:hidden fixed bottom-4 right-4 z-50">
        <button 
          onClick={downloadCollage}
          className="p-4 bg-indigo-600 rounded-full shadow-2xl text-white active:scale-95 transition"
        >
          <Download className="w-6 h-6" />
        </button>
      </div>
    </div>
  );
};

export default App;

export interface ImageTransform {
  scale: number;
  translateX: number;
  translateY: number;
}

export interface ImageFile {
  id: string;
  file: File;
  preview: string;
  width: number;
  height: number;
  aspectRatio: number;
  transform: ImageTransform;
}

export interface CollageSettings {
  columns: number;
  rows: number;
  gap: number;
  padding: number;
  backgroundColor: string;
  targetRatio: '5:4' | '4:5' | 'auto';
  quality: number;
}

export interface GridDimensions {
  cols: number;
  rows: number;
  cellWidth: number;
  cellHeight: number;
  totalWidth: number;
  totalHeight: number;
}

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { 
  Upload, 
  Download, 
  Trash2, 
  LayoutGrid, 
  Settings2, 
  Sparkles,
  X,
  RotateCcw,
  Move,
  ZoomIn
} from 'lucide-react';
import { ImageFile, CollageSettings, ImageTransform } from './types';
import { loadImage, calculateBestGrid, getDimensions } from './utils/image';
import { generateCollageCaption } from './services/gemini';

const App: React.FC = () => {
  const [images, setImages] = useState<ImageFile[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [settings, setSettings] = useState<CollageSettings>({
    columns: 2,
    rows: 3,
    gap: 20,
    padding: 40,
    backgroundColor: '#ffffff',
    targetRatio: '5:4',
    quality: 0.9
  });
  const [isProcessing, setIsProcessing] = useState(false);
  const [aiCaption, setAiCaption] = useState<string>('');
  const [isGeneratingCaption, setIsGeneratingCaption] = useState(false);

  const canvasRef = useRef<HTMLCanvasElement>(null);

  const selectedImage = images.find(img => img.id === selectedId);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    if (files.length === 0) return;

    setIsProcessing(true);
    const newImages: ImageFile[] = [];

    for (const file of files) {
      const url = URL.createObjectURL(file);
      const img = await loadImage(url);
      newImages.push({
        id: Math.random().toString(36).substr(2, 9),
        file,
        preview: url,
        width: img.width,
        height: img.height,
        aspectRatio: img.width / img.height,
        transform: {
          scale: 1,
          translateX: 0,
          translateY: 0
        }
      });
    }

    const updatedImages = [...images, ...newImages];
    setImages(updatedImages);

    if (updatedImages.length > 0) {
      const avgRatio = updatedImages.reduce((sum, img) => sum + img.aspectRatio, 0) / updatedImages.length;
      const { cols, rows } = calculateBestGrid(updatedImages.length, avgRatio, settings.targetRatio);
      setSettings(prev => ({ ...prev, columns: cols, rows }));
    }

    setIsProcessing(false);
  };

  const updateImageTransform = (id: string, updates: Partial<ImageTransform>) => {
    setImages(prev => prev.map(img => 
      img.id === id ? { ...img, transform: { ...img.transform, ...updates } } : img
    ));
  };

  const resetTransform = (id: string) => {
    updateImageTransform(id, { scale: 1, translateX: 0, translateY: 0 });
  };

  const removeImage = (id: string) => {
    if (selectedId === id) setSelectedId(null);
    setImages(prev => prev.filter(img => img.id !== id));
  };

  const drawCollage = useCallback(async () => {
    if (!canvasRef.current || images.length === 0) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dims = getDimensions(images, settings);
    canvas.width = dims.totalWidth;
    canvas.height = dims.totalHeight;

    // Background
    ctx.fillStyle = settings.backgroundColor;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);

      const x = settings.padding + (col * (dims.cellWidth + settings.gap));
      const y = settings.padding + (row * (dims.cellHeight + settings.gap));

      try {
        const imgObj = images[i];
        const img = await loadImage(imgObj.preview);

        ctx.save();

        // Create clipping mask for the cell
        ctx.beginPath();
        ctx.rect(x, y, dims.cellWidth, dims.cellHeight);
        ctx.clip();

        const cellAspect = dims.cellWidth / dims.cellHeight;
        const imgAspect = img.width / img.height;

        // Base scale for "Cover" fit
        let baseScale = 1;
        if (imgAspect > cellAspect) {
          baseScale = dims.cellHeight / img.height;
        } else {
          baseScale = dims.cellWidth / img.width;
        }

        const finalScale = baseScale * imgObj.transform.scale;
        const drawWidth = img.width * finalScale;
        const drawHeight = img.height * finalScale;

        // Calculate centering offset + user manual translation
        const centerX = x + (dims.cellWidth - drawWidth) / 2;
        const centerY = y + (dims.cellHeight - drawHeight) / 2;

        const finalX = centerX + imgObj.transform.translateX;
        const finalY = centerY + imgObj.transform.translateY;

        ctx.drawImage(img, finalX, finalY, drawWidth, drawHeight);

        ctx.restore();

        // Stroke border if it's the same as background to clean up edges
        ctx.strokeStyle = settings.backgroundColor;
        ctx.lineWidth = 1;
        ctx.strokeRect(x, y, dims.cellWidth, dims.cellHeight);

      } catch (err) {
        console.error("Failed to draw image", i, err);
      }
    }
  }, [images, settings]);

  useEffect(() => {
    drawCollage();
  }, [drawCollage]);

  const downloadCollage = () => {
    if (!canvasRef.current) return;
    const link = document.createElement('a');
    link.download = `stitched-collage-${Date.now()}.jpg`;
    link.href = canvasRef.current.toDataURL('image/jpeg', settings.quality);
    link.click();
  };

  const handleAiCaption = async () => {
    if (!canvasRef.current || images.length === 0) return;
    setIsGeneratingCaption(true);
    const dataUrl = canvasRef.current.toDataURL('image/jpeg', 0.5);
    const caption = await generateCollageCaption(dataUrl);
    setAiCaption(caption);
    setIsGeneratingCaption(false);
  };

  return (
    <div className="min-h-screen flex flex-col lg:flex-row bg-slate-900 text-slate-100">
      {/* Sidebar Controls */}
      <aside className="w-full lg:w-96 bg-slate-800 border-r border-slate-700 overflow-y-auto p-6 space-y-8 sticky top-0 h-screen hidden lg:block scrollbar-hide">
        <div className="flex items-center gap-2 mb-4">
          <div className="p-2 bg-indigo-600 rounded-lg">
            <LayoutGrid className="w-6 h-6" />
          </div>
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
            Stitcher Studio
          </h1>
        </div>

        {/* Global Layout Settings */}
        <section className="space-y-4">
          <h2 className="text-sm font-semibold uppercase tracking-wider text-slate-400 flex items-center gap-2">
            <Settings2 className="w-4 h-4" /> Global Layout
          </h2>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs text-slate-500 mb-1">Columns</label>
              <input 
                type="number" 
                value={settings.columns} 
                onChange={e => setSettings(s => ({ ...s, columns: parseInt(e.target.value) || 1 }))}
                className="w-full bg-slate-900 border border-slate-700 rounded-md p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-xs text-slate-500 mb-1">Rows</label>
              <input 
                type="number" 
                value={settings.rows} 
                onChange={e => setSettings(s => ({ ...s, rows: parseInt(e.target.value) || 1 }))}
                className="w-full bg-slate-900 border border-slate-700 rounded-md p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>
          </div>

          <div>
            <label className="block text-xs text-slate-500 mb-1">Target Ratio</label>
            <div className="flex gap-2">
              {(['5:4', '4:5', 'auto'] as const).map(r => (
                <button
                  key={r}
                  onClick={() => setSettings(s => ({ ...s, targetRatio: r }))}
                  className={`flex-1 py-2 text-xs rounded-md border transition ${
                    settings.targetRatio === r 
                      ? 'bg-indigo-600 border-indigo-500 text-white' 
                      : 'bg-slate-900 border-slate-700 text-slate-400 hover:border-slate-500'
                  }`}
                >
                  {r}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-xs text-slate-500 mb-1">Gap & Padding</label>
            <div className="space-y-4">
              <input 
                type="range" min="0" max="100" 
                value={settings.gap} 
                onChange={e => setSettings(s => ({ ...s, gap: parseInt(e.target.value) }))}
                className="w-full h-1.5 bg-slate-900 rounded-lg appearance-none cursor-pointer accent-indigo-500"
              />
              <input 
                type="range" min="0" max="200" 
                value={settings.padding} 
                onChange={e => setSettings(s => ({ ...s, padding: parseInt(e.target.value) }))}
                className="w-full h-1.5 bg-slate-900 rounded-lg appearance-none cursor-pointer accent-indigo-500"
              />
            </div>
          </div>

          <div>
            <label className="block text-xs text-slate-500 mb-1">Background</label>
            <div className="flex gap-2">
              <input 
                type="color" 
                value={settings.backgroundColor} 
                onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))}
                className="w-10 h-10 bg-transparent border-none cursor-pointer rounded overflow-hidden"
              />
              <input 
                type="text" 
                value={settings.backgroundColor} 
                onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))}
                className="flex-1 bg-slate-900 border border-slate-700 rounded-md px-3 text-sm font-mono"
              />
            </div>
          </div>
        </section>

        {/* Selected Image Editor */}
        {selectedImage && (
          <section className="p-4 bg-slate-900/50 rounded-xl border border-indigo-500/20 space-y-4 animate-in slide-in-from-right-4 duration-300">
            <div className="flex items-center justify-between">
              <h2 className="text-sm font-semibold text-indigo-400 flex items-center gap-2">
                <Move className="w-4 h-4" /> Image Editor
              </h2>
              <button 
                onClick={() => setSelectedId(null)}
                className="text-slate-500 hover:text-white"
              >
                <X className="w-4 h-4" />
              </button>
            </div>

            <div className="space-y-4">
              <div>
                <label className="flex justify-between text-xs text-slate-500 mb-2 italic">
                  <span>Zoom / Scale</span>
                  <span>{selectedImage.transform.scale.toFixed(2)}x</span>
                </label>
                <div className="flex items-center gap-3">
                  <input 
                    type="range" min="0.5" max="5" step="0.01"
                    value={selectedImage.transform.scale} 
                    onChange={e => updateImageTransform(selectedImage.id, { scale: parseFloat(e.target.value) })}
                    className="flex-1 h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500"
                  />
                </div>
              </div>

              <div>
                <label className="block text-xs text-slate-500 mb-2 italic">Position (X / Y)</label>
                <div className="space-y-3">
                  <input 
                    type="range" min="-1000" max="1000" step="1"
                    value={selectedImage.transform.translateX} 
                    onChange={e => updateImageTransform(selectedImage.id, { translateX: parseInt(e.target.value) })}
                    className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-slate-500"
                  />
                  <input 
                    type="range" min="-1000" max="1000" step="1"
                    value={selectedImage.transform.translateY} 
                    onChange={e => updateImageTransform(selectedImage.id, { translateY: parseInt(e.target.value) })}
                    className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-slate-500"
                  />
                </div>
              </div>

              <button
                onClick={() => resetTransform(selectedImage.id)}
                className="w-full flex items-center justify-center gap-2 py-2 px-4 rounded-lg bg-slate-800 border border-slate-700 hover:bg-slate-700 text-xs text-slate-300 transition"
              >
                <RotateCcw className="w-3 h-3" /> Reset Crop
              </button>
            </div>
          </section>
        )}

        <section className="space-y-4">
          <h2 className="text-sm font-semibold uppercase tracking-wider text-slate-400 flex items-center gap-2">
            <Sparkles className="w-4 h-4" /> AI Magic
          </h2>
          <button
            onClick={handleAiCaption}
            disabled={images.length === 0 || isGeneratingCaption}
            className="w-full flex items-center justify-center gap-2 py-3 px-4 rounded-lg bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-500 hover:to-indigo-500 disabled:opacity-50 disabled:cursor-not-allowed font-medium transition shadow-lg shadow-indigo-900/20"
          >
            {isGeneratingCaption ? 'AI is thinking...' : 'Generate AI Caption'}
          </button>
          {aiCaption && (
            <div className="p-4 bg-slate-900 border border-indigo-500/30 rounded-lg italic text-slate-300 text-sm animate-in fade-in slide-in-from-bottom-2">
              "{aiCaption}"
            </div>
          )}
        </section>

        <div className="pt-8 border-t border-slate-700">
          <button
            onClick={downloadCollage}
            disabled={images.length === 0}
            className="w-full flex items-center justify-center gap-2 py-3 px-4 rounded-lg bg-white text-slate-900 hover:bg-slate-200 disabled:opacity-50 disabled:cursor-not-allowed font-bold transition shadow-xl"
          >
            <Download className="w-5 h-5" /> Download Result
          </button>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden bg-slate-950">
        <header className="p-4 bg-slate-900 lg:bg-transparent border-b border-slate-800 lg:border-none flex justify-between items-center z-10">
          <div className="lg:hidden flex items-center gap-2">
            <LayoutGrid className="w-5 h-5 text-indigo-500" />
            <span className="font-bold tracking-tight">STITCHER STUDIO</span>
          </div>
          <div className="text-sm text-slate-400 font-medium">
            {images.length} item{images.length !== 1 ? 's' : ''} in workspace
          </div>
          <div className="flex gap-2">
             <label className="cursor-pointer">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <div className="flex items-center gap-2 px-5 py-2.5 bg-indigo-600 hover:bg-indigo-500 rounded-full text-sm font-bold transition shadow-lg shadow-indigo-900/40">
                <Upload className="w-4 h-4" />
                <span>Import Images</span>
              </div>
            </label>
          </div>
        </header>

        {/* Preview Area */}
        <div className="flex-1 overflow-auto p-4 lg:p-12 flex items-center justify-center relative bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-slate-900 to-slate-950">
          {images.length === 0 ? (
            <div className="text-center space-y-4 max-w-md animate-in zoom-in duration-700">
              <div className="w-24 h-24 bg-slate-800 rounded-full flex items-center justify-center mx-auto border-2 border-slate-700 shadow-inner">
                <LayoutGrid className="w-10 h-10 text-slate-500" />
              </div>
              <h3 className="text-2xl font-black text-white">READY TO STITCH?</h3>
              <p className="text-slate-400 text-sm leading-relaxed px-10">
                Create stunning photo grids with smart auto-layout and precise image-level cropping.
              </p>
              <label className="inline-block cursor-pointer px-10 py-4 bg-white text-slate-900 rounded-2xl font-black hover:scale-105 transition active:scale-95 shadow-2xl mt-4">
                <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
                GET STARTED
              </label>
            </div>
          ) : (
            <div className="relative group max-h-full">
              <div className="shadow-[0_40px_100px_rgba(0,0,0,0.8)] rounded-xl overflow-hidden border border-white/5 bg-slate-800 ring-1 ring-white/10">
                <canvas 
                  ref={canvasRef} 
                  className="max-w-full max-h-[72vh] object-contain mx-auto transition-all duration-500 ease-out"
                />
              </div>
              <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                <button 
                  onClick={() => { setImages([]); setSelectedId(null); }}
                  className="p-3 bg-red-600/90 hover:bg-red-500 text-white rounded-xl shadow-2xl transition backdrop-blur-md"
                  title="Clear All"
                >
                  <Trash2 className="w-5 h-5" />
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Improved Thumbnail Reel with Selection */}
        {images.length > 0 && (
          <div className="h-36 bg-slate-900/95 backdrop-blur-xl border-t border-slate-800/50 p-4 flex gap-4 overflow-x-auto items-center scrollbar-thin scrollbar-thumb-slate-700 scrollbar-track-transparent">
            {images.map((img) => (
              <div key={img.id} className="relative flex-shrink-0 group">
                <button
                  onClick={() => setSelectedId(img.id)}
                  className={`relative block h-24 w-24 overflow-hidden rounded-xl border-2 transition-all duration-200 ${
                    selectedId === img.id 
                      ? 'border-indigo-500 ring-4 ring-indigo-500/20 scale-105' 
                      : 'border-slate-700 hover:border-slate-500'
                  }`}
                >
                  <img 
                    src={img.preview} 
                    alt="Thumbnail" 
                    className="h-full w-full object-cover" 
                  />
                  {selectedId === img.id && (
                    <div className="absolute inset-0 bg-indigo-500/10 flex items-center justify-center">
                      <Settings2 className="w-5 h-5 text-indigo-400" />
                    </div>
                  )}
                </button>
                <button 
                  onClick={(e) => { e.stopPropagation(); removeImage(img.id); }}
                  className="absolute -top-2 -right-2 p-1.5 bg-slate-800 rounded-full border border-slate-700 text-slate-400 hover:text-red-400 hover:border-red-500/50 transition shadow-lg opacity-0 group-hover:opacity-100"
                >
                  <X className="w-3 h-3" />
                </button>
              </div>
            ))}
            <label className="flex-shrink-0 h-24 w-24 flex flex-col items-center justify-center border-2 border-dashed border-slate-700 rounded-xl hover:border-indigo-500 hover:bg-indigo-500/5 cursor-pointer transition text-slate-500 hover:text-indigo-400 bg-slate-800/30">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <Upload className="w-5 h-5 mb-1" />
              <span className="text-[10px] uppercase font-bold tracking-widest">Add</span>
            </label>
          </div>
        )}
      </main>

      {/* Floating Action Button for Mobile Download */}
      <div className="lg:hidden fixed bottom-6 right-6 z-50">
        <button 
          onClick={downloadCollage}
          className="p-5 bg-indigo-600 rounded-2xl shadow-2xl text-white active:scale-90 transition-transform flex items-center gap-2 font-bold"
        >
          <Download className="w-6 h-6" />
        </button>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { 
  Upload, 
  Download, 
  Trash2, 
  LayoutGrid, 
  Settings2, 
  Sparkles,
  X,
  RotateCcw,
  Move
} from 'lucide-react';
import { ImageFile, CollageSettings, ImageTransform } from './types';
import { loadImage, calculateBestGrid, getDimensions } from './utils/image';
import { generateCollageCaption } from './services/gemini';

const App: React.FC = () => {
  const [images, setImages] = useState<ImageFile[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [settings, setSettings] = useState<CollageSettings>({
    columns: 2,
    rows: 3,
    gap: 20,
    padding: 40,
    backgroundColor: '#ffffff',
    targetRatio: '5:4',
    quality: 0.9
  });
  const [isProcessing, setIsProcessing] = useState(false);
  const [aiCaption, setAiCaption] = useState<string>('');
  const [isGeneratingCaption, setIsGeneratingCaption] = useState(false);
  const [isDragging, setIsDragging] = useState(false);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const dragStartRef = useRef<{ x: number, y: number, initialX: number, initialY: number } | null>(null);

  const selectedImage = images.find(img => img.id === selectedId);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    if (files.length === 0) return;

    setIsProcessing(true);
    const newImages: ImageFile[] = [];

    for (const file of files) {
      const url = URL.createObjectURL(file);
      const img = await loadImage(url);
      newImages.push({
        id: Math.random().toString(36).substr(2, 9),
        file,
        preview: url,
        width: img.width,
        height: img.height,
        aspectRatio: img.width / img.height,
        transform: {
          scale: 1,
          translateX: 0,
          translateY: 0
        }
      });
    }

    const updatedImages = [...images, ...newImages];
    setImages(updatedImages);

    if (updatedImages.length > 0) {
      const avgRatio = updatedImages.reduce((sum, img) => sum + img.aspectRatio, 0) / updatedImages.length;
      const { cols, rows } = calculateBestGrid(updatedImages.length, avgRatio, settings.targetRatio);
      setSettings(prev => ({ ...prev, columns: cols, rows }));
    }

    setIsProcessing(false);
  };

  const updateImageTransform = (id: string, updates: Partial<ImageTransform>) => {
    setImages(prev => prev.map(img => 
      img.id === id ? { ...img, transform: { ...img.transform, ...updates } } : img
    ));
  };

  const resetTransform = (id: string) => {
    updateImageTransform(id, { scale: 1, translateX: 0, translateY: 0 });
  };

  const removeImage = (id: string) => {
    if (selectedId === id) setSelectedId(null);
    setImages(prev => prev.filter(img => img.id !== id));
  };

  const getCanvasMousePos = (e: React.MouseEvent | React.TouchEvent) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;

    // Calculate position relative to display size
    const x = clientX - rect.left;
    const y = clientY - rect.top;

    // Scale to internal canvas coordinates
    const scaleX = canvasRef.current.width / rect.width;
    const scaleY = canvasRef.current.height / rect.height;

    return { x: x * scaleX, y: y * scaleY };
  };

  const handleCanvasMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!canvasRef.current || images.length === 0) return;
    const pos = getCanvasMousePos(e);
    const dims = getDimensions(images, settings);

    // Determine which cell was clicked
    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);
      const x = settings.padding + (col * (dims.cellWidth + settings.gap));
      const y = settings.padding + (row * (dims.cellHeight + settings.gap));

      if (pos.x >= x && pos.x <= x + dims.cellWidth && pos.y >= y && pos.y <= y + dims.cellHeight) {
        setSelectedId(images[i].id);
        setIsDragging(true);
        dragStartRef.current = {
          x: pos.x,
          y: pos.y,
          initialX: images[i].transform.translateX,
          initialY: images[i].transform.translateY
        };
        break;
      }
    }
  };

  const handleCanvasMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDragging || !dragStartRef.current || !selectedId) return;
    const pos = getCanvasMousePos(e);

    const deltaX = pos.x - dragStartRef.current.x;
    const deltaY = pos.y - dragStartRef.current.y;

    updateImageTransform(selectedId, {
      translateX: dragStartRef.current.initialX + deltaX,
      translateY: dragStartRef.current.initialY + deltaY
    });
  };

  const handleCanvasMouseUp = () => {
    setIsDragging(false);
    dragStartRef.current = null;
  };

  const drawCollage = useCallback(async () => {
    if (!canvasRef.current || images.length === 0) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dims = getDimensions(images, settings);
    canvas.width = dims.totalWidth;
    canvas.height = dims.totalHeight;

    // Background
    ctx.fillStyle = settings.backgroundColor;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);

      const x = settings.padding + (col * (dims.cellWidth + settings.gap));
      const y = settings.padding + (row * (dims.cellHeight + settings.gap));

      try {
        const imgObj = images[i];
        const img = await loadImage(imgObj.preview);

        ctx.save();

        // Create clipping mask for the cell
        ctx.beginPath();
        ctx.rect(x, y, dims.cellWidth, dims.cellHeight);
        ctx.clip();

        const cellAspect = dims.cellWidth / dims.cellHeight;
        const imgAspect = img.width / img.height;

        // Base scale for "Cover" fit
        let baseScale = 1;
        if (imgAspect > cellAspect) {
          baseScale = dims.cellHeight / img.height;
        } else {
          baseScale = dims.cellWidth / img.width;
        }

        const finalScale = baseScale * imgObj.transform.scale;
        const drawWidth = img.width * finalScale;
        const drawHeight = img.height * finalScale;

        // Calculate centering offset + user manual translation
        const centerX = x + (dims.cellWidth - drawWidth) / 2;
        const centerY = y + (dims.cellHeight - drawHeight) / 2;

        const finalX = centerX + imgObj.transform.translateX;
        const finalY = centerY + imgObj.transform.translateY;

        ctx.drawImage(img, finalX, finalY, drawWidth, drawHeight);

        // Visual indicator for selection
        if (selectedId === imgObj.id) {
          ctx.strokeStyle = 'rgba(79, 70, 229, 0.5)';
          ctx.lineWidth = 10;
          ctx.strokeRect(x + 5, y + 5, dims.cellWidth - 10, dims.cellHeight - 10);
        }

        ctx.restore();

        // Stroke border
        ctx.strokeStyle = settings.backgroundColor;
        ctx.lineWidth = 1;
        ctx.strokeRect(x, y, dims.cellWidth, dims.cellHeight);

      } catch (err) {
        console.error("Failed to draw image", i, err);
      }
    }
  }, [images, settings, selectedId]);

  useEffect(() => {
    drawCollage();
  }, [drawCollage]);

  const downloadCollage = () => {
    if (!canvasRef.current) return;
    const link = document.createElement('a');
    link.download = `stitched-collage-${Date.now()}.jpg`;
    link.href = canvasRef.current.toDataURL('image/jpeg', settings.quality);
    link.click();
  };

  const handleAiCaption = async () => {
    if (!canvasRef.current || images.length === 0) return;
    setIsGeneratingCaption(true);
    const dataUrl = canvasRef.current.toDataURL('image/jpeg', 0.5);
    const caption = await generateCollageCaption(dataUrl);
    setAiCaption(caption);
    setIsGeneratingCaption(false);
  };

  return (
    <div className="min-h-screen flex flex-col lg:flex-row bg-slate-900 text-slate-100">
      {/* Sidebar Controls */}
      <aside className="w-full lg:w-96 bg-slate-800 border-r border-slate-700 overflow-y-auto p-6 space-y-8 sticky top-0 h-screen hidden lg:block scrollbar-hide">
        <div className="flex items-center gap-2 mb-4">
          <div className="p-2 bg-indigo-600 rounded-lg">
            <LayoutGrid className="w-6 h-6" />
          </div>
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
            Stitcher Studio
          </h1>
        </div>

        {/* Global Layout Settings */}
        <section className="space-y-4">
          <h2 className="text-sm font-semibold uppercase tracking-wider text-slate-400 flex items-center gap-2">
            <Settings2 className="w-4 h-4" /> Global Layout
          </h2>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs text-slate-500 mb-1">Columns</label>
              <input 
                type="number" 
                value={settings.columns} 
                onChange={e => setSettings(s => ({ ...s, columns: parseInt(e.target.value) || 1 }))}
                className="w-full bg-slate-900 border border-slate-700 rounded-md p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-xs text-slate-500 mb-1">Rows</label>
              <input 
                type="number" 
                value={settings.rows} 
                onChange={e => setSettings(s => ({ ...s, rows: parseInt(e.target.value) || 1 }))}
                className="w-full bg-slate-900 border border-slate-700 rounded-md p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>
          </div>

          <div>
            <label className="block text-xs text-slate-500 mb-1">Target Ratio</label>
            <div className="flex gap-2">
              {(['5:4', '4:5', 'auto'] as const).map(r => (
                <button
                  key={r}
                  onClick={() => setSettings(s => ({ ...s, targetRatio: r }))}
                  className={`flex-1 py-2 text-xs rounded-md border transition ${
                    settings.targetRatio === r 
                      ? 'bg-indigo-600 border-indigo-500 text-white' 
                      : 'bg-slate-900 border-slate-700 text-slate-400 hover:border-slate-500'
                  }`}
                >
                  {r}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-xs text-slate-500 mb-1">Gap & Padding</label>
            <div className="space-y-4">
              <input 
                type="range" min="0" max="100" 
                value={settings.gap} 
                onChange={e => setSettings(s => ({ ...s, gap: parseInt(e.target.value) }))}
                className="w-full h-1.5 bg-slate-900 rounded-lg appearance-none cursor-pointer accent-indigo-500"
              />
              <input 
                type="range" min="0" max="200" 
                value={settings.padding} 
                onChange={e => setSettings(s => ({ ...s, padding: parseInt(e.target.value) }))}
                className="w-full h-1.5 bg-slate-900 rounded-lg appearance-none cursor-pointer accent-indigo-500"
              />
            </div>
          </div>

          <div>
            <label className="block text-xs text-slate-500 mb-1">Background</label>
            <div className="flex gap-2">
              <input 
                type="color" 
                value={settings.backgroundColor} 
                onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))}
                className="w-10 h-10 bg-transparent border-none cursor-pointer rounded overflow-hidden"
              />
              <input 
                type="text" 
                value={settings.backgroundColor} 
                onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))}
                className="flex-1 bg-slate-900 border border-slate-700 rounded-md px-3 text-sm font-mono"
              />
            </div>
          </div>
        </section>

        {/* Selected Image Editor */}
        {selectedImage && (
          <section className="p-4 bg-slate-900/50 rounded-xl border border-indigo-500/20 space-y-4 animate-in slide-in-from-right-4 duration-300">
            <div className="flex items-center justify-between">
              <h2 className="text-sm font-semibold text-indigo-400 flex items-center gap-2">
                <Move className="w-4 h-4" /> Image Editor
              </h2>
              <button 
                onClick={() => setSelectedId(null)}
                className="text-slate-500 hover:text-white"
              >
                <X className="w-4 h-4" />
              </button>
            </div>

            <div className="space-y-4 text-xs text-slate-400 italic">
              Tip: Drag directly on the image to pan
            </div>

            <div className="space-y-4">
              <div>
                <label className="flex justify-between text-xs text-slate-500 mb-2 italic">
                  <span>Zoom / Scale</span>
                  <span>{selectedImage.transform.scale.toFixed(2)}x</span>
                </label>
                <div className="flex items-center gap-3">
                  <input 
                    type="range" min="0.5" max="5" step="0.01"
                    value={selectedImage.transform.scale} 
                    onChange={e => updateImageTransform(selectedImage.id, { scale: parseFloat(e.target.value) })}
                    className="flex-1 h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500"
                  />
                </div>
              </div>

              <button
                onClick={() => resetTransform(selectedImage.id)}
                className="w-full flex items-center justify-center gap-2 py-2 px-4 rounded-lg bg-slate-800 border border-slate-700 hover:bg-slate-700 text-xs text-slate-300 transition"
              >
                <RotateCcw className="w-3 h-3" /> Reset Crop
              </button>
            </div>
          </section>
        )}

        <section className="space-y-4">
          <h2 className="text-sm font-semibold uppercase tracking-wider text-slate-400 flex items-center gap-2">
            <Sparkles className="w-4 h-4" /> AI Magic
          </h2>
          <button
            onClick={handleAiCaption}
            disabled={images.length === 0 || isGeneratingCaption}
            className="w-full flex items-center justify-center gap-2 py-3 px-4 rounded-lg bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-500 hover:to-indigo-500 disabled:opacity-50 disabled:cursor-not-allowed font-medium transition shadow-lg shadow-indigo-900/20"
          >
            {isGeneratingCaption ? 'AI is thinking...' : 'Generate AI Caption'}
          </button>
          {aiCaption && (
            <div className="p-4 bg-slate-900 border border-indigo-500/30 rounded-lg italic text-slate-300 text-sm animate-in fade-in slide-in-from-bottom-2">
              "{aiCaption}"
            </div>
          )}
        </section>

        <div className="pt-8 border-t border-slate-700">
          <button
            onClick={downloadCollage}
            disabled={images.length === 0}
            className="w-full flex items-center justify-center gap-2 py-3 px-4 rounded-lg bg-white text-slate-900 hover:bg-slate-200 disabled:opacity-50 disabled:cursor-not-allowed font-bold transition shadow-xl"
          >
            <Download className="w-5 h-5" /> Download Result
          </button>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden bg-slate-950">
        <header className="p-4 bg-slate-900 lg:bg-transparent border-b border-slate-800 lg:border-none flex justify-between items-center z-10">
          <div className="lg:hidden flex items-center gap-2">
            <LayoutGrid className="w-5 h-5 text-indigo-500" />
            <span className="font-bold tracking-tight">STITCHER STUDIO</span>
          </div>
          <div className="text-sm text-slate-400 font-medium">
            {images.length} item{images.length !== 1 ? 's' : ''} in workspace
          </div>
          <div className="flex gap-2">
             <label className="cursor-pointer">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <div className="flex items-center gap-2 px-5 py-2.5 bg-indigo-600 hover:bg-indigo-500 rounded-full text-sm font-bold transition shadow-lg shadow-indigo-900/40">
                <Upload className="w-4 h-4" />
                <span>Import Images</span>
              </div>
            </label>
          </div>
        </header>

        {/* Preview Area */}
        <div className="flex-1 overflow-auto p-4 lg:p-12 flex items-center justify-center relative bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-slate-900 to-slate-950">
          {images.length === 0 ? (
            <div className="text-center space-y-4 max-w-md animate-in zoom-in duration-700">
              <div className="w-24 h-24 bg-slate-800 rounded-full flex items-center justify-center mx-auto border-2 border-slate-700 shadow-inner">
                <LayoutGrid className="w-10 h-10 text-slate-500" />
              </div>
              <h3 className="text-2xl font-black text-white">READY TO STITCH?</h3>
              <p className="text-slate-400 text-sm leading-relaxed px-10">
                Create stunning photo grids with smart auto-layout and precise image-level cropping.
              </p>
              <label className="inline-block cursor-pointer px-10 py-4 bg-white text-slate-900 rounded-2xl font-black hover:scale-105 transition active:scale-95 shadow-2xl mt-4">
                <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
                GET STARTED
              </label>
            </div>
          ) : (
            <div className="relative group max-h-full">
              <div className="shadow-[0_40px_100px_rgba(0,0,0,0.8)] rounded-xl overflow-hidden border border-white/5 bg-slate-800 ring-1 ring-white/10">
                <canvas 
                  ref={canvasRef} 
                  onMouseDown={handleCanvasMouseDown}
                  onMouseMove={handleCanvasMouseMove}
                  onMouseUp={handleCanvasMouseUp}
                  onMouseLeave={handleCanvasMouseUp}
                  onTouchStart={handleCanvasMouseDown}
                  onTouchMove={handleCanvasMouseMove}
                  onTouchEnd={handleCanvasMouseUp}
                  style={{ cursor: isDragging ? 'grabbing' : 'grab' }}
                  className="max-w-full max-h-[72vh] object-contain mx-auto transition-shadow duration-500 ease-out select-none touch-none"
                />
              </div>
              <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                <button 
                  onClick={() => { setImages([]); setSelectedId(null); }}
                  className="p-3 bg-red-600/90 hover:bg-red-500 text-white rounded-xl shadow-2xl transition backdrop-blur-md"
                  title="Clear All"
                >
                  <Trash2 className="w-5 h-5" />
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Improved Thumbnail Reel with Selection */}
        {images.length > 0 && (
          <div className="h-36 bg-slate-900/95 backdrop-blur-xl border-t border-slate-800/50 p-4 flex gap-4 overflow-x-auto items-center scrollbar-thin scrollbar-thumb-slate-700 scrollbar-track-transparent">
            {images.map((img) => (
              <div key={img.id} className="relative flex-shrink-0 group">
                <button
                  onClick={() => setSelectedId(img.id)}
                  className={`relative block h-24 w-24 overflow-hidden rounded-xl border-2 transition-all duration-200 ${
                    selectedId === img.id 
                      ? 'border-indigo-500 ring-4 ring-indigo-500/20 scale-105' 
                      : 'border-slate-700 hover:border-slate-500'
                  }`}
                >
                  <img 
                    src={img.preview} 
                    alt="Thumbnail" 
                    className="h-full w-full object-cover" 
                  />
                  {selectedId === img.id && (
                    <div className="absolute inset-0 bg-indigo-500/10 flex items-center justify-center">
                      <Settings2 className="w-5 h-5 text-indigo-400" />
                    </div>
                  )}
                </button>
                <button 
                  onClick={(e) => { e.stopPropagation(); removeImage(img.id); }}
                  className="absolute -top-2 -right-2 p-1.5 bg-slate-800 rounded-full border border-slate-700 text-slate-400 hover:text-red-400 hover:border-red-500/50 transition shadow-lg opacity-0 group-hover:opacity-100"
                >
                  <X className="w-3 h-3" />
                </button>
              </div>
            ))}
            <label className="flex-shrink-0 h-24 w-24 flex flex-col items-center justify-center border-2 border-dashed border-slate-700 rounded-xl hover:border-indigo-500 hover:bg-indigo-500/5 cursor-pointer transition text-slate-500 hover:text-indigo-400 bg-slate-800/30">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <Upload className="w-5 h-5 mb-1" />
              <span className="text-[10px] uppercase font-bold tracking-widest">Add</span>
            </label>
          </div>
        )}
      </main>

      {/* Floating Action Button for Mobile Download */}
      <div className="lg:hidden fixed bottom-6 right-6 z-50">
        <button 
          onClick={downloadCollage}
          className="p-5 bg-indigo-600 rounded-2xl shadow-2xl text-white active:scale-90 transition-transform flex items-center gap-2 font-bold"
        >
          <Download className="w-6 h-6" />
        </button>
      </div>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";

export interface DesignSuggestion {
  backgroundColor: string;
  designTip: string;
}

export const generateDesignStyle = async (collageDataUrl: string): Promise<DesignSuggestion> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const base64Data = collageDataUrl.split(',')[1];

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { text: "Analyze the colors and mood of these images in the collage. Suggest a single best background hex color that complements all images. Also provide one short professional design tip (max 15 words) for this specific set of photos. Return the response in JSON format. Use Chinese for the designTip." },
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Data
            }
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            backgroundColor: { 
              type: Type.STRING,
              description: "The hex color code (e.g. #F5F5F5) recommended for the background."
            },
            designTip: { 
              type: Type.STRING,
              description: "A short design tip in Chinese."
            }
          },
          required: ["backgroundColor", "designTip"]
        }
      }
    });

    return JSON.parse(response.text || "{}") as DesignSuggestion;
  } catch (error) {
    console.error("Gemini Error:", error);
    return { 
      backgroundColor: "#ffffff", 
      designTip: "AI 暫時無法連線，建議手動調整背景色以突顯照片。" 
    };
  }
};

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { 
  Upload, 
  Download, 
  Trash2, 
  LayoutGrid, 
  Settings2, 
  Sparkles,
  X,
  RotateCcw,
  Move,
  Palette
} from 'lucide-react';
import { ImageFile, CollageSettings, ImageTransform } from './types';
import { loadImage, calculateBestGrid, getDimensions } from './utils/image';
import { generateDesignStyle, DesignSuggestion } from './services/gemini';

const App: React.FC = () => {
  const [images, setImages] = useState<ImageFile[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [settings, setSettings] = useState<CollageSettings>({
    columns: 2,
    rows: 3,
    gap: 20,
    padding: 40,
    backgroundColor: '#ffffff',
    targetRatio: '5:4',
    quality: 0.9
  });
  const [isProcessing, setIsProcessing] = useState(false);
  const [designTip, setDesignTip] = useState<string>('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isDragging, setIsDragging] = useState(false);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const dragStartRef = useRef<{ x: number, y: number, initialX: number, initialY: number } | null>(null);

  const selectedImage = images.find(img => img.id === selectedId);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    if (files.length === 0) return;

    setIsProcessing(true);
    const newImages: ImageFile[] = [];

    for (const file of files) {
      const url = URL.createObjectURL(file);
      const img = await loadImage(url);
      newImages.push({
        id: Math.random().toString(36).substr(2, 9),
        file,
        preview: url,
        width: img.width,
        height: img.height,
        aspectRatio: img.width / img.height,
        transform: {
          scale: 1,
          translateX: 0,
          translateY: 0
        }
      });
    }

    const updatedImages = [...images, ...newImages];
    setImages(updatedImages);

    if (updatedImages.length > 0) {
      const avgRatio = updatedImages.reduce((sum, img) => sum + img.aspectRatio, 0) / updatedImages.length;
      const { cols, rows } = calculateBestGrid(updatedImages.length, avgRatio, settings.targetRatio);
      setSettings(prev => ({ ...prev, columns: cols, rows }));
    }

    setIsProcessing(false);
  };

  const updateImageTransform = (id: string, updates: Partial<ImageTransform>) => {
    setImages(prev => prev.map(img => 
      img.id === id ? { ...img, transform: { ...img.transform, ...updates } } : img
    ));
  };

  const resetTransform = (id: string) => {
    updateImageTransform(id, { scale: 1, translateX: 0, translateY: 0 });
  };

  const removeImage = (id: string) => {
    if (selectedId === id) setSelectedId(null);
    setImages(prev => prev.filter(img => img.id !== id));
  };

  const getCanvasMousePos = (e: React.MouseEvent | React.TouchEvent) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;

    const x = clientX - rect.left;
    const y = clientY - rect.top;

    const scaleX = canvasRef.current.width / rect.width;
    const scaleY = canvasRef.current.height / rect.height;

    return { x: x * scaleX, y: y * scaleY };
  };

  const handleCanvasMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!canvasRef.current || images.length === 0) return;
    const pos = getCanvasMousePos(e);
    const dims = getDimensions(images, settings);

    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);
      const x = settings.padding + (col * (dims.cellWidth + settings.gap));
      const y = settings.padding + (row * (dims.cellHeight + settings.gap));

      if (pos.x >= x && pos.x <= x + dims.cellWidth && pos.y >= y && pos.y <= y + dims.cellHeight) {
        setSelectedId(images[i].id);
        setIsDragging(true);
        dragStartRef.current = {
          x: pos.x,
          y: pos.y,
          initialX: images[i].transform.translateX,
          initialY: images[i].transform.translateY
        };
        break;
      }
    }
  };

  const handleCanvasMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDragging || !dragStartRef.current || !selectedId) return;
    const pos = getCanvasMousePos(e);

    const deltaX = pos.x - dragStartRef.current.x;
    const deltaY = pos.y - dragStartRef.current.y;

    updateImageTransform(selectedId, {
      translateX: dragStartRef.current.initialX + deltaX,
      translateY: dragStartRef.current.initialY + deltaY
    });
  };

  const handleCanvasMouseUp = () => {
    setIsDragging(false);
    dragStartRef.current = null;
  };

  const drawCollage = useCallback(async () => {
    if (!canvasRef.current || images.length === 0) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dims = getDimensions(images, settings);
    canvas.width = dims.totalWidth;
    canvas.height = dims.totalHeight;

    ctx.fillStyle = settings.backgroundColor;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);

      const x = settings.padding + (col * (dims.cellWidth + settings.gap));
      const y = settings.padding + (row * (dims.cellHeight + settings.gap));

      try {
        const imgObj = images[i];
        const img = await loadImage(imgObj.preview);

        ctx.save();
        ctx.beginPath();
        ctx.rect(x, y, dims.cellWidth, dims.cellHeight);
        ctx.clip();

        const cellAspect = dims.cellWidth / dims.cellHeight;
        const imgAspect = img.width / img.height;

        let baseScale = 1;
        if (imgAspect > cellAspect) {
          baseScale = dims.cellHeight / img.height;
        } else {
          baseScale = dims.cellWidth / img.width;
        }

        const finalScale = baseScale * imgObj.transform.scale;
        const drawWidth = img.width * finalScale;
        const drawHeight = img.height * finalScale;

        const centerX = x + (dims.cellWidth - drawWidth) / 2;
        const centerY = y + (dims.cellHeight - drawHeight) / 2;

        const finalX = centerX + imgObj.transform.translateX;
        const finalY = centerY + imgObj.transform.translateY;

        ctx.drawImage(img, finalX, finalY, drawWidth, drawHeight);

        if (selectedId === imgObj.id) {
          ctx.strokeStyle = 'rgba(79, 70, 229, 0.6)';
          ctx.lineWidth = 12;
          ctx.strokeRect(x + 6, y + 6, dims.cellWidth - 12, dims.cellHeight - 12);
        }

        ctx.restore();
        ctx.strokeStyle = settings.backgroundColor;
        ctx.lineWidth = 1;
        ctx.strokeRect(x, y, dims.cellWidth, dims.cellHeight);

      } catch (err) {
        console.error("Failed to draw image", i, err);
      }
    }
  }, [images, settings, selectedId]);

  useEffect(() => {
    drawCollage();
  }, [drawCollage]);

  const downloadCollage = () => {
    if (!canvasRef.current) return;
    const link = document.createElement('a');
    link.download = `stitched-collage-${Date.now()}.jpg`;
    link.href = canvasRef.current.toDataURL('image/jpeg', settings.quality);
    link.click();
  };

  const handleAiDesign = async () => {
    if (!canvasRef.current || images.length === 0) return;
    setIsAnalyzing(true);
    // Use a smaller version for analysis
    const dataUrl = canvasRef.current.toDataURL('image/jpeg', 0.4);
    const suggestion = await generateDesignStyle(dataUrl);

    setSettings(prev => ({ ...prev, backgroundColor: suggestion.backgroundColor }));
    setDesignTip(suggestion.designTip);
    setIsAnalyzing(false);
  };

  return (
    <div className="min-h-screen flex flex-col lg:flex-row bg-slate-900 text-slate-100">
      {/* Sidebar Controls */}
      <aside className="w-full lg:w-96 bg-slate-800 border-r border-slate-700 overflow-y-auto p-6 space-y-8 sticky top-0 h-screen hidden lg:block scrollbar-hide">
        <div className="flex items-center gap-2 mb-4">
          <div className="p-2 bg-indigo-600 rounded-lg">
            <LayoutGrid className="w-6 h-6" />
          </div>
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
            Stitcher Studio
          </h1>
        </div>

        <section className="space-y-4">
          <h2 className="text-sm font-semibold uppercase tracking-wider text-slate-400 flex items-center gap-2">
            <Settings2 className="w-4 h-4" /> Global Layout
          </h2>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs text-slate-500 mb-1">Columns</label>
              <input 
                type="number" 
                value={settings.columns} 
                onChange={e => setSettings(s => ({ ...s, columns: parseInt(e.target.value) || 1 }))}
                className="w-full bg-slate-900 border border-slate-700 rounded-md p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-xs text-slate-500 mb-1">Rows</label>
              <input 
                type="number" 
                value={settings.rows} 
                onChange={e => setSettings(s => ({ ...s, rows: parseInt(e.target.value) || 1 }))}
                className="w-full bg-slate-900 border border-slate-700 rounded-md p-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>
          </div>

          <div>
            <label className="block text-xs text-slate-500 mb-1">Target Ratio</label>
            <div className="flex gap-2">
              {(['5:4', '4:5', 'auto'] as const).map(r => (
                <button
                  key={r}
                  onClick={() => setSettings(s => ({ ...s, targetRatio: r }))}
                  className={`flex-1 py-2 text-xs rounded-md border transition ${
                    settings.targetRatio === r 
                      ? 'bg-indigo-600 border-indigo-500 text-white' 
                      : 'bg-slate-900 border-slate-700 text-slate-400 hover:border-slate-500'
                  }`}
                >
                  {r}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-xs text-slate-500 mb-1">Gap & Padding</label>
            <div className="space-y-4">
              <input 
                type="range" min="0" max="100" 
                value={settings.gap} 
                onChange={e => setSettings(s => ({ ...s, gap: parseInt(e.target.value) }))}
                className="w-full h-1.5 bg-slate-900 rounded-lg appearance-none cursor-pointer accent-indigo-500"
              />
              <input 
                type="range" min="0" max="200" 
                value={settings.padding} 
                onChange={e => setSettings(s => ({ ...s, padding: parseInt(e.target.value) }))}
                className="w-full h-1.5 bg-slate-900 rounded-lg appearance-none cursor-pointer accent-indigo-500"
              />
            </div>
          </div>

          <div>
            <label className="block text-xs text-slate-500 mb-1">Background</label>
            <div className="flex gap-2">
              <input 
                type="color" 
                value={settings.backgroundColor} 
                onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))}
                className="w-10 h-10 bg-transparent border-none cursor-pointer rounded overflow-hidden"
              />
              <input 
                type="text" 
                value={settings.backgroundColor} 
                onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))}
                className="flex-1 bg-slate-900 border border-slate-700 rounded-md px-3 text-sm font-mono"
              />
            </div>
          </div>
        </section>

        {selectedImage && (
          <section className="p-4 bg-slate-900/50 rounded-xl border border-indigo-500/20 space-y-4 animate-in slide-in-from-right-4 duration-300">
            <div className="flex items-center justify-between">
              <h2 className="text-sm font-semibold text-indigo-400 flex items-center gap-2">
                <Move className="w-4 h-4" /> Image Editor
              </h2>
              <button onClick={() => setSelectedId(null)} className="text-slate-500 hover:text-white">
                <X className="w-4 h-4" />
              </button>
            </div>
            <div className="space-y-4">
              <div>
                <label className="flex justify-between text-xs text-slate-500 mb-2 italic">
                  <span>Zoom / Scale</span>
                  <span>{selectedImage.transform.scale.toFixed(2)}x</span>
                </label>
                <input 
                  type="range" min="0.5" max="5" step="0.01"
                  value={selectedImage.transform.scale} 
                  onChange={e => updateImageTransform(selectedImage.id, { scale: parseFloat(e.target.value) })}
                  className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500"
                />
              </div>
              <button
                onClick={() => resetTransform(selectedImage.id)}
                className="w-full flex items-center justify-center gap-2 py-2 px-4 rounded-lg bg-slate-800 border border-slate-700 hover:bg-slate-700 text-xs text-slate-300 transition"
              >
                <RotateCcw className="w-3 h-3" /> Reset Position
              </button>
            </div>
          </section>
        )}

        <section className="space-y-4">
          <h2 className="text-sm font-semibold uppercase tracking-wider text-slate-400 flex items-center gap-2">
            <Sparkles className="w-4 h-4" /> AI Design Assistant
          </h2>
          <button
            onClick={handleAiDesign}
            disabled={images.length === 0 || isAnalyzing}
            className="w-full flex items-center justify-center gap-2 py-3 px-4 rounded-lg bg-gradient-to-r from-violet-600 to-indigo-600 hover:from-violet-500 hover:to-indigo-500 disabled:opacity-50 disabled:cursor-not-allowed font-medium transition shadow-lg shadow-indigo-900/30 group"
          >
            {isAnalyzing ? (
              <div className="flex items-center gap-2">
                <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                <span>分析照片風格中...</span>
              </div>
            ) : (
              <>
                <Palette className="w-4 h-4 group-hover:rotate-12 transition-transform" />
                <span>AI 自動優化風格</span>
              </>
            )}
          </button>
          {designTip && (
            <div className="p-4 bg-slate-900/80 border-l-2 border-indigo-500 rounded-r-lg text-slate-300 text-xs leading-relaxed animate-in fade-in slide-in-from-bottom-2">
              <span className="text-indigo-400 font-bold block mb-1 tracking-wider uppercase text-[10px]">AI Pro Tip</span>
              {designTip}
            </div>
          )}
        </section>

        <div className="pt-8 border-t border-slate-700">
          <button
            onClick={downloadCollage}
            disabled={images.length === 0}
            className="w-full flex items-center justify-center gap-2 py-3 px-4 rounded-lg bg-white text-slate-900 hover:bg-slate-200 disabled:opacity-50 disabled:cursor-not-allowed font-bold transition shadow-xl"
          >
            <Download className="w-5 h-5" /> Download Result
          </button>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden bg-slate-950">
        <header className="p-4 bg-slate-900 lg:bg-transparent border-b border-slate-800 lg:border-none flex justify-between items-center z-10">
          <div className="lg:hidden flex items-center gap-2">
            <LayoutGrid className="w-5 h-5 text-indigo-500" />
            <span className="font-bold tracking-tight">STITCHER STUDIO</span>
          </div>
          <div className="text-sm text-slate-400 font-medium">
            {images.length} items in workspace
          </div>
          <div className="flex gap-2">
             <label className="cursor-pointer">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <div className="flex items-center gap-2 px-5 py-2.5 bg-indigo-600 hover:bg-indigo-500 rounded-full text-sm font-bold transition shadow-lg shadow-indigo-900/40">
                <Upload className="w-4 h-4" />
                <span>Import Images</span>
              </div>
            </label>
          </div>
        </header>

        <div className="flex-1 overflow-auto p-4 lg:p-12 flex items-center justify-center relative bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-slate-900 to-slate-950">
          {images.length === 0 ? (
            <div className="text-center space-y-4 max-w-md animate-in zoom-in duration-700">
              <div className="w-24 h-24 bg-slate-800 rounded-full flex items-center justify-center mx-auto border-2 border-slate-700 shadow-inner">
                <LayoutGrid className="w-10 h-10 text-slate-500" />
              </div>
              <h3 className="text-2xl font-black text-white">READY TO STITCH?</h3>
              <p className="text-slate-400 text-sm leading-relaxed px-10">
                Upload images, drag to pan, and use AI Design Assistant to match colors perfectly.
              </p>
              <label className="inline-block cursor-pointer px-10 py-4 bg-white text-slate-900 rounded-2xl font-black hover:scale-105 transition active:scale-95 shadow-2xl mt-4">
                <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
                GET STARTED
              </label>
            </div>
          ) : (
            <div className="relative group max-h-full">
              <div className="shadow-[0_40px_100px_rgba(0,0,0,0.8)] rounded-xl overflow-hidden border border-white/5 bg-slate-800 ring-1 ring-white/10">
                <canvas 
                  ref={canvasRef} 
                  onMouseDown={handleCanvasMouseDown}
                  onMouseMove={handleCanvasMouseMove}
                  onMouseUp={handleCanvasMouseUp}
                  onMouseLeave={handleCanvasMouseUp}
                  onTouchStart={handleCanvasMouseDown}
                  onTouchMove={handleCanvasMouseMove}
                  onTouchEnd={handleCanvasMouseUp}
                  style={{ cursor: isDragging ? 'grabbing' : 'grab' }}
                  className="max-w-full max-h-[72vh] object-contain mx-auto transition-shadow duration-500 ease-out select-none touch-none"
                />
              </div>
              <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                <button 
                  onClick={() => { setImages([]); setSelectedId(null); setDesignTip(''); }}
                  className="p-3 bg-red-600/90 hover:bg-red-500 text-white rounded-xl shadow-2xl transition backdrop-blur-md"
                >
                  <Trash2 className="w-5 h-5" />
                </button>
              </div>
            </div>
          )}
        </div>

        {images.length > 0 && (
          <div className="h-36 bg-slate-900/95 backdrop-blur-xl border-t border-slate-800/50 p-4 flex gap-4 overflow-x-auto items-center">
            {images.map((img) => (
              <div key={img.id} className="relative flex-shrink-0 group">
                <button
                  onClick={() => setSelectedId(img.id)}
                  className={`relative block h-24 w-24 overflow-hidden rounded-xl border-2 transition-all duration-200 ${
                    selectedId === img.id 
                      ? 'border-indigo-500 ring-4 ring-indigo-500/20 scale-105' 
                      : 'border-slate-700 hover:border-slate-500'
                  }`}
                >
                  <img src={img.preview} alt="Thumbnail" className="h-full w-full object-cover" />
                </button>
                <button 
                  onClick={(e) => { e.stopPropagation(); removeImage(img.id); }}
                  className="absolute -top-2 -right-2 p-1.5 bg-slate-800 rounded-full border border-slate-700 text-slate-400 hover:text-red-400 transition shadow-lg opacity-0 group-hover:opacity-100"
                >
                  <X className="w-3 h-3" />
                </button>
              </div>
            ))}
            <label className="flex-shrink-0 h-24 w-24 flex flex-col items-center justify-center border-2 border-dashed border-slate-700 rounded-xl hover:border-indigo-500 hover:bg-indigo-500/5 cursor-pointer transition text-slate-500 hover:text-indigo-400 bg-slate-800/30">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <Upload className="w-5 h-5 mb-1" />
              <span className="text-[10px] uppercase font-bold tracking-widest">Add</span>
            </label>
          </div>
        )}
      </main>

      <div className="lg:hidden fixed bottom-6 right-6 z-50">
        <button onClick={downloadCollage} className="p-5 bg-indigo-600 rounded-2xl shadow-2xl text-white">
          <Download className="w-6 h-6" />
        </button>
      </div>
    </div>
  );
};

export default App;

export interface ImageTransform {
  scale: number;
  translateX: number;
  translateY: number;
}

export interface ImageFile {
  id: string;
  file: File;
  preview: string;
  width: number;
  height: number;
  aspectRatio: number;
  transform: ImageTransform;
}

export interface CollageSettings {
  columns: number;
  rows: number;
  gap: number;
  padding: number;
  backgroundColor: string;
  targetRatio: '5:4' | '4:5' | '1:1' | 'auto';
  quality: number;
  borderRadius: number;
  borderWidth: number;
  borderColor: string;
}

export interface GridDimensions {
  cols: number;
  rows: number;
  cellWidth: number;
  cellHeight: number;
  totalWidth: number;
  totalHeight: number;
}

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { 
  Upload, 
  Download, 
  Trash2, 
  LayoutGrid, 
  Settings2, 
  Sparkles,
  X,
  RotateCcw,
  Move,
  Palette,
  Square,
  Zap,
  Columns2
} from 'lucide-react';
import { ImageFile, CollageSettings, ImageTransform } from './types';
import { loadImage, calculateBestGrid, getDimensions } from './utils/image';
import { generateDesignStyle } from './services/gemini';

const PRESETS = {
  POLAROID: {
    backgroundColor: '#ffffff',
    gap: 30,
    padding: 60,
    borderRadius: 8,
    borderWidth: 0,
    targetRatio: '1:1' as const,
  },
  VINTAGE_90S: {
    backgroundColor: '#f4f1ea',
    gap: 40,
    padding: 50,
    borderRadius: 20,
    borderWidth: 0,
    targetRatio: '4:5' as const,
  },
  COMIC: {
    backgroundColor: '#000000',
    gap: 15,
    padding: 30,
    borderRadius: 0,
    borderWidth: 4,
    borderColor: '#ffffff',
    targetRatio: 'auto' as const,
  },
  FOUR_PANEL: {
    backgroundColor: '#ffffff',
    gap: 10,
    padding: 20,
    borderRadius: 0,
    borderWidth: 2,
    borderColor: '#000000',
    columns: 1,
    targetRatio: 'auto' as const,
  }
};

const App: React.FC = () => {
  const [images, setImages] = useState<ImageFile[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [settings, setSettings] = useState<CollageSettings>({
    columns: 2,
    rows: 3,
    gap: 20,
    padding: 40,
    backgroundColor: '#ffffff',
    targetRatio: '5:4',
    quality: 0.9,
    borderRadius: 0,
    borderWidth: 0,
    borderColor: '#ffffff'
  });
  const [isProcessing, setIsProcessing] = useState(false);
  const [designTip, setDesignTip] = useState<string>('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isDragging, setIsDragging] = useState(false);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const dragStartRef = useRef<{ x: number, y: number, initialX: number, initialY: number } | null>(null);

  const selectedImage = images.find(img => img.id === selectedId);

  const applyPreset = (preset: Partial<CollageSettings>) => {
    setSettings(prev => {
      const newSettings = { ...prev, ...preset };
      if (preset.columns) {
        newSettings.rows = Math.ceil(images.length / preset.columns);
      } else if (images.length > 0) {
        const avgRatio = images.reduce((sum, img) => sum + img.aspectRatio, 0) / images.length;
        const { cols, rows } = calculateBestGrid(images.length, avgRatio, newSettings.targetRatio);
        newSettings.columns = cols;
        newSettings.rows = rows;
      }
      return newSettings;
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    if (files.length === 0) return;

    setIsProcessing(true);
    const newImages: ImageFile[] = [];

    for (const file of files) {
      const url = URL.createObjectURL(file);
      const img = await loadImage(url);
      newImages.push({
        id: Math.random().toString(36).substr(2, 9),
        file,
        preview: url,
        width: img.width,
        height: img.height,
        aspectRatio: img.width / img.height,
        transform: {
          scale: 1,
          translateX: 0,
          translateY: 0
        }
      });
    }

    const updatedImages = [...images, ...newImages];
    setImages(updatedImages);

    if (updatedImages.length > 0) {
      const avgRatio = updatedImages.reduce((sum, img) => sum + img.aspectRatio, 0) / updatedImages.length;
      const { cols, rows } = calculateBestGrid(updatedImages.length, avgRatio, settings.targetRatio);
      setSettings(prev => ({ ...prev, columns: cols, rows }));
    }

    setIsProcessing(false);
  };

  const updateImageTransform = (id: string, updates: Partial<ImageTransform>) => {
    setImages(prev => prev.map(img => 
      img.id === id ? { ...img, transform: { ...img.transform, ...updates } } : img
    ));
  };

  const resetTransform = (id: string) => {
    updateImageTransform(id, { scale: 1, translateX: 0, translateY: 0 });
  };

  const removeImage = (id: string) => {
    if (selectedId === id) setSelectedId(null);
    setImages(prev => prev.filter(img => img.id !== id));
  };

  const getCanvasMousePos = (e: React.MouseEvent | React.TouchEvent) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;

    const x = clientX - rect.left;
    const y = clientY - rect.top;

    const scaleX = canvasRef.current.width / rect.width;
    const scaleY = canvasRef.current.height / rect.height;

    return { x: x * scaleX, y: y * scaleY };
  };

  const handleCanvasMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!canvasRef.current || images.length === 0) return;
    const pos = getCanvasMousePos(e);
    const dims = getDimensions(images, settings);

    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);
      const x = settings.padding + (col * (dims.cellWidth + settings.gap));
      const y = settings.padding + (row * (dims.cellHeight + settings.gap));

      if (pos.x >= x && pos.x <= x + dims.cellWidth && pos.y >= y && pos.y <= y + dims.cellHeight) {
        setSelectedId(images[i].id);
        setIsDragging(true);
        dragStartRef.current = {
          x: pos.x,
          y: pos.y,
          initialX: images[i].transform.translateX,
          initialY: images[i].transform.translateY
        };
        break;
      }
    }
  };

  const handleCanvasMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDragging || !dragStartRef.current || !selectedId) return;
    const pos = getCanvasMousePos(e);

    const deltaX = pos.x - dragStartRef.current.x;
    const deltaY = pos.y - dragStartRef.current.y;

    updateImageTransform(selectedId, {
      translateX: dragStartRef.current.initialX + deltaX,
      translateY: dragStartRef.current.initialY + deltaY
    });
  };

  const handleCanvasMouseUp = () => {
    setIsDragging(false);
    dragStartRef.current = null;
  };

  const drawCollage = useCallback(async () => {
    if (!canvasRef.current || images.length === 0) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dims = getDimensions(images, settings);
    canvas.width = dims.totalWidth;
    canvas.height = dims.totalHeight;

    ctx.fillStyle = settings.backgroundColor;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);

      const x = settings.padding + (col * (dims.cellWidth + settings.gap));
      const y = settings.padding + (row * (dims.cellHeight + settings.gap));

      try {
        const imgObj = images[i];
        const img = await loadImage(imgObj.preview);

        ctx.save();

        // Use path for rounded rectangles if supported
        if (ctx.roundRect) {
          ctx.beginPath();
          ctx.roundRect(x, y, dims.cellWidth, dims.cellHeight, settings.borderRadius);
          ctx.clip();
        } else {
          ctx.beginPath();
          ctx.rect(x, y, dims.cellWidth, dims.cellHeight);
          ctx.clip();
        }

        const cellAspect = dims.cellWidth / dims.cellHeight;
        const imgAspect = img.width / img.height;

        let baseScale = 1;
        if (imgAspect > cellAspect) {
          baseScale = dims.cellHeight / img.height;
        } else {
          baseScale = dims.cellWidth / img.width;
        }

        const finalScale = baseScale * imgObj.transform.scale;
        const drawWidth = img.width * finalScale;
        const drawHeight = img.height * finalScale;

        const centerX = x + (dims.cellWidth - drawWidth) / 2;
        const centerY = y + (dims.cellHeight - drawHeight) / 2;

        const finalX = centerX + imgObj.transform.translateX;
        const finalY = centerY + imgObj.transform.translateY;

        ctx.drawImage(img, finalX, finalY, drawWidth, drawHeight);

        if (selectedId === imgObj.id) {
          ctx.strokeStyle = 'rgba(79, 70, 229, 0.7)';
          ctx.lineWidth = 15;
          ctx.strokeRect(x + 7.5, y + 7.5, dims.cellWidth - 15, dims.cellHeight - 15);
        }

        ctx.restore();

        // Stroke for border styles (Comic/Panel)
        if (settings.borderWidth > 0) {
          ctx.strokeStyle = settings.borderColor;
          ctx.lineWidth = settings.borderWidth;
          if (ctx.roundRect) {
            ctx.beginPath();
            ctx.roundRect(x, y, dims.cellWidth, dims.cellHeight, settings.borderRadius);
            ctx.stroke();
          } else {
            ctx.strokeRect(x, y, dims.cellWidth, dims.cellHeight);
          }
        }

      } catch (err) {
        console.error("Failed to draw image", i, err);
      }
    }
  }, [images, settings, selectedId]);

  useEffect(() => {
    drawCollage();
  }, [drawCollage]);

  const downloadCollage = () => {
    if (!canvasRef.current) return;
    const link = document.createElement('a');
    link.download = `stitched-collage-${Date.now()}.jpg`;
    link.href = canvasRef.current.toDataURL('image/jpeg', settings.quality);
    link.click();
  };

  const handleAiDesign = async () => {
    if (!canvasRef.current || images.length === 0) return;
    setIsAnalyzing(true);
    const dataUrl = canvasRef.current.toDataURL('image/jpeg', 0.4);
    const suggestion = await generateDesignStyle(dataUrl);

    setSettings(prev => ({ ...prev, backgroundColor: suggestion.backgroundColor }));
    setDesignTip(suggestion.designTip);
    setIsAnalyzing(false);
  };

  return (
    <div className="min-h-screen flex flex-col lg:flex-row bg-slate-900 text-slate-100">
      {/* Sidebar Controls */}
      <aside className="w-full lg:w-96 bg-slate-800 border-r border-slate-700 overflow-y-auto p-6 space-y-8 sticky top-0 h-screen hidden lg:block scrollbar-hide">
        <div className="flex items-center gap-2 mb-4">
          <div className="p-2 bg-indigo-600 rounded-lg">
            <LayoutGrid className="w-6 h-6" />
          </div>
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
            Stitcher Studio
          </h1>
        </div>

        {/* Presets Section */}
        <section className="space-y-4">
          <h2 className="text-sm font-semibold uppercase tracking-wider text-slate-400 flex items-center gap-2">
            <Zap className="w-4 h-4 text-amber-400" /> Style Presets
          </h2>
          <div className="grid grid-cols-2 gap-2">
            <button 
              onClick={() => applyPreset(PRESETS.POLAROID)}
              className="flex items-center gap-2 p-2 bg-slate-900 border border-slate-700 rounded-lg hover:border-indigo-500 transition text-xs"
            >
              <Square className="w-3 h-3" /> 拍立得
            </button>
            <button 
              onClick={() => applyPreset(PRESETS.VINTAGE_90S)}
              className="flex items-center gap-2 p-2 bg-slate-900 border border-slate-700 rounded-lg hover:border-indigo-500 transition text-xs"
            >
              <Sparkles className="w-3 h-3" /> 90s 復古
            </button>
            <button 
              onClick={() => applyPreset(PRESETS.COMIC)}
              className="flex items-center gap-2 p-2 bg-slate-900 border border-slate-700 rounded-lg hover:border-indigo-500 transition text-xs"
            >
              <LayoutGrid className="w-3 h-3" /> 美式漫畫
            </button>
            <button 
              onClick={() => applyPreset(PRESETS.FOUR_PANEL)}
              className="flex items-center gap-2 p-2 bg-slate-900 border border-slate-700 rounded-lg hover:border-indigo-500 transition text-xs"
            >
              <Columns2 className="w-3 h-3" /> 四格漫畫
            </button>
          </div>
        </section>

        <section className="space-y-4">
          <h2 className="text-sm font-semibold uppercase tracking-wider text-slate-400 flex items-center gap-2">
            <Sparkles className="w-4 h-4" /> AI Visual Assistant
          </h2>
          <button
            onClick={handleAiDesign}
            disabled={images.length === 0 || isAnalyzing}
            className="w-full flex items-center justify-center gap-2 py-3 px-4 rounded-lg bg-gradient-to-r from-violet-600 to-indigo-600 hover:from-violet-500 hover:to-indigo-500 disabled:opacity-50 disabled:cursor-not-allowed font-medium transition shadow-lg shadow-indigo-900/30 group"
          >
            {isAnalyzing ? (
              <div className="flex items-center gap-2">
                <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                <span>優化中...</span>
              </div>
            ) : (
              <>
                <Palette className="w-4 h-4" />
                <span>AI 自動優化色彩</span>
              </>
            )}
          </button>
          {designTip && (
            <div className="p-3 bg-indigo-500/10 border border-indigo-500/30 rounded-lg text-slate-300 text-[11px] leading-relaxed animate-in fade-in">
              <span className="text-indigo-400 font-bold block mb-1">DESIGN TIP</span>
              {designTip}
            </div>
          )}
        </section>

        <section className="space-y-4">
          <h2 className="text-sm font-semibold uppercase tracking-wider text-slate-400 flex items-center gap-2">
            <Settings2 className="w-4 h-4" /> Global Layout
          </h2>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-[10px] text-slate-500 mb-1 uppercase">Columns</label>
              <input 
                type="number" 
                value={settings.columns} 
                onChange={e => setSettings(s => ({ ...s, columns: Math.max(1, parseInt(e.target.value) || 1) }))}
                className="w-full bg-slate-900 border border-slate-700 rounded-md p-2 text-sm focus:ring-1 focus:ring-indigo-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-[10px] text-slate-500 mb-1 uppercase">Rows</label>
              <input 
                type="number" 
                value={settings.rows} 
                onChange={e => setSettings(s => ({ ...s, rows: Math.max(1, parseInt(e.target.value) || 1) }))}
                className="w-full bg-slate-900 border border-slate-700 rounded-md p-2 text-sm focus:ring-1 focus:ring-indigo-500 outline-none"
              />
            </div>
          </div>

          <div>
            <label className="block text-[10px] text-slate-500 mb-1 uppercase">Target Ratio</label>
            <div className="grid grid-cols-4 gap-1">
              {(['5:4', '4:5', '1:1', 'auto'] as const).map(r => (
                <button
                  key={r}
                  onClick={() => applyPreset({ targetRatio: r })}
                  className={`py-1.5 text-[10px] rounded border transition ${
                    settings.targetRatio === r 
                      ? 'bg-indigo-600 border-indigo-500 text-white' 
                      : 'bg-slate-900 border-slate-700 text-slate-400'
                  }`}
                >
                  {r}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-3">
            <div>
              <label className="flex justify-between text-[10px] text-slate-500 mb-1 uppercase">
                <span>Gap</span>
                <span>{settings.gap}px</span>
              </label>
              <input 
                type="range" min="0" max="100" 
                value={settings.gap} 
                onChange={e => setSettings(s => ({ ...s, gap: parseInt(e.target.value) }))}
                className="w-full h-1 bg-slate-900 rounded-lg appearance-none cursor-pointer accent-indigo-500"
              />
            </div>
            <div>
              <label className="flex justify-between text-[10px] text-slate-500 mb-1 uppercase">
                <span>Roundness</span>
                <span>{settings.borderRadius}px</span>
              </label>
              <input 
                type="range" min="0" max="100" 
                value={settings.borderRadius} 
                onChange={e => setSettings(s => ({ ...s, borderRadius: parseInt(e.target.value) }))}
                className="w-full h-1 bg-slate-900 rounded-lg appearance-none cursor-pointer accent-indigo-500"
              />
            </div>
          </div>
        </section>

        {selectedImage && (
          <section className="p-4 bg-indigo-500/5 rounded-xl border border-indigo-500/20 space-y-4 animate-in slide-in-from-right-4 duration-300">
            <div className="flex items-center justify-between">
              <h2 className="text-sm font-semibold text-indigo-400 flex items-center gap-2 uppercase tracking-tighter">
                <Move className="w-3 h-3" /> Edit Mode
              </h2>
              <button onClick={() => setSelectedId(null)} className="text-slate-500 hover:text-white">
                <X className="w-4 h-4" />
              </button>
            </div>
            <div className="space-y-4">
              <div>
                <label className="flex justify-between text-[10px] text-slate-500 mb-1 uppercase">
                  <span>Zoom</span>
                  <span>{selectedImage.transform.scale.toFixed(2)}x</span>
                </label>
                <input 
                  type="range" min="0.5" max="5" step="0.01"
                  value={selectedImage.transform.scale} 
                  onChange={e => updateImageTransform(selectedImage.id, { scale: parseFloat(e.target.value) })}
                  className="w-full h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-indigo-400"
                />
              </div>
              <button
                onClick={() => resetTransform(selectedImage.id)}
                className="w-full py-2 bg-slate-900 border border-slate-700 hover:bg-slate-700 text-[10px] uppercase font-bold text-slate-300 transition"
              >
                Reset Image
              </button>
            </div>
          </section>
        )}

        <div className="pt-8 border-t border-slate-700">
          <button
            onClick={downloadCollage}
            disabled={images.length === 0}
            className="w-full flex items-center justify-center gap-2 py-3 px-4 rounded-lg bg-white text-slate-900 hover:bg-slate-200 disabled:opacity-50 disabled:cursor-not-allowed font-bold transition shadow-xl"
          >
            <Download className="w-5 h-5" /> Download
          </button>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden bg-slate-950">
        <header className="p-4 bg-slate-900 border-b border-slate-800 flex justify-between items-center z-10">
          <div className="flex items-center gap-2">
            <LayoutGrid className="w-5 h-5 text-indigo-500" />
            <span className="font-bold tracking-tight text-sm uppercase">Stitcher Studio</span>
          </div>
          <div className="flex gap-2">
             <label className="cursor-pointer">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <div className="flex items-center gap-2 px-5 py-2.5 bg-indigo-600 hover:bg-indigo-500 rounded-full text-xs font-bold transition shadow-lg shadow-indigo-900/40">
                <Upload className="w-4 h-4" />
                <span>Import Images</span>
              </div>
            </label>
          </div>
        </header>

        <div className="flex-1 overflow-auto p-4 lg:p-12 flex items-center justify-center relative bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-slate-900 to-slate-950">
          {images.length === 0 ? (
            <div className="text-center space-y-4 max-w-md animate-in zoom-in duration-700">
              <div className="w-20 h-20 bg-slate-800 rounded-full flex items-center justify-center mx-auto border-2 border-slate-700">
                <LayoutGrid className="w-8 h-8 text-slate-500" />
              </div>
              <h3 className="text-xl font-bold text-white uppercase tracking-widest">Upload to start</h3>
              <p className="text-slate-400 text-xs leading-relaxed px-10">
                Choose multiple images. We'll handle the grid, you handle the style.
              </p>
            </div>
          ) : (
            <div className="relative group max-h-full">
              <div className="shadow-[0_50px_100px_rgba(0,0,0,0.9)] rounded-sm overflow-hidden border border-white/5 bg-slate-800">
                <canvas 
                  ref={canvasRef} 
                  onMouseDown={handleCanvasMouseDown}
                  onMouseMove={handleCanvasMouseMove}
                  onMouseUp={handleCanvasMouseUp}
                  onMouseLeave={handleCanvasMouseUp}
                  onTouchStart={handleCanvasMouseDown}
                  onTouchMove={handleCanvasMouseMove}
                  onTouchEnd={handleCanvasMouseUp}
                  style={{ cursor: isDragging ? 'grabbing' : 'grab' }}
                  className="max-w-full max-h-[75vh] object-contain mx-auto select-none touch-none"
                />
              </div>
              <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                <button 
                  onClick={() => { setImages([]); setSelectedId(null); setDesignTip(''); }}
                  className="p-3 bg-red-600/90 hover:bg-red-500 text-white rounded-xl shadow-2xl transition"
                >
                  <Trash2 className="w-5 h-5" />
                </button>
              </div>
            </div>
          )}
        </div>

        {images.length > 0 && (
          <div className="h-32 bg-slate-900/95 backdrop-blur-xl border-t border-slate-800 p-4 flex gap-4 overflow-x-auto items-center">
            {images.map((img) => (
              <div key={img.id} className="relative flex-shrink-0 group">
                <button
                  onClick={() => setSelectedId(img.id)}
                  className={`relative block h-20 w-20 overflow-hidden rounded-lg border-2 transition-all ${
                    selectedId === img.id 
                      ? 'border-indigo-500 scale-105' 
                      : 'border-slate-700 hover:border-slate-500'
                  }`}
                >
                  <img src={img.preview} alt="Thumbnail" className="h-full w-full object-cover" />
                </button>
                <button 
                  onClick={(e) => { e.stopPropagation(); removeImage(img.id); }}
                  className="absolute -top-1 -right-1 p-1 bg-slate-800 rounded-full border border-slate-700 text-slate-400 hover:text-red-400 transition opacity-0 group-hover:opacity-100"
                >
                  <X className="w-3 h-3" />
                </button>
              </div>
            ))}
            <label className="flex-shrink-0 h-20 w-20 flex flex-col items-center justify-center border-2 border-dashed border-slate-700 rounded-lg hover:border-indigo-500 hover:bg-indigo-500/5 cursor-pointer transition text-slate-500 hover:text-indigo-400 bg-slate-800/30">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <Upload className="w-4 h-4 mb-1" />
              <span className="text-[8px] uppercase font-bold tracking-widest">More</span>
            </label>
          </div>
        )}
      </main>

      <div className="lg:hidden fixed bottom-6 right-6 z-50">
        <button onClick={downloadCollage} className="p-4 bg-indigo-600 rounded-2xl shadow-2xl text-white">
          <Download className="w-6 h-6" />
        </button>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { 
  Upload, 
  Download, 
  Trash2, 
  LayoutGrid, 
  Settings2, 
  X,
  RotateCcw,
  Move,
  Square,
  Zap,
  Columns2,
  Image as ImageIcon
} from 'lucide-react';
import { ImageFile, CollageSettings, ImageTransform } from './types';
import { loadImage, calculateBestGrid, getDimensions } from './utils/image';

const PRESETS = {
  POLAROID: {
    backgroundColor: '#ffffff',
    gap: 25,
    padding: 60,
    borderRadius: 8,
    borderWidth: 0,
    targetRatio: '1:1' as const,
    label: '正方形拍立得'
  },
  VINTAGE_90S: {
    backgroundColor: '#f4f1ea',
    gap: 40,
    padding: 50,
    borderRadius: 24,
    borderWidth: 0,
    targetRatio: '4:5' as const,
    label: '90s 拍立得'
  },
  COMIC: {
    backgroundColor: '#000000',
    gap: 12,
    padding: 24,
    borderRadius: 0,
    borderWidth: 4,
    borderColor: '#ffffff',
    targetRatio: 'auto' as const,
    label: '美式漫畫格'
  },
  FOUR_PANEL: {
    backgroundColor: '#ffffff',
    gap: 8,
    padding: 20,
    borderRadius: 0,
    borderWidth: 2,
    borderColor: '#000000',
    columns: 1,
    targetRatio: 'auto' as const,
    label: '直條四格'
  }
};

const App: React.FC = () => {
  const [images, setImages] = useState<ImageFile[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [settings, setSettings] = useState<CollageSettings>({
    columns: 2,
    rows: 3,
    gap: 20,
    padding: 40,
    backgroundColor: '#ffffff',
    targetRatio: '5:4',
    quality: 0.9,
    borderRadius: 0,
    borderWidth: 0,
    borderColor: '#ffffff'
  });
  const [isDragging, setIsDragging] = useState(false);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const dragStartRef = useRef<{ x: number, y: number, initialX: number, initialY: number } | null>(null);

  const selectedImage = images.find(img => img.id === selectedId);

  const applyPreset = (preset: any) => {
    setSettings(prev => {
      const newSettings = { ...prev, ...preset };
      if (preset.columns) {
        newSettings.rows = Math.ceil(images.length / preset.columns);
      } else if (images.length > 0) {
        const avgRatio = images.reduce((sum, img) => sum + img.aspectRatio, 0) / images.length;
        const { cols, rows } = calculateBestGrid(images.length, avgRatio, newSettings.targetRatio);
        newSettings.columns = cols;
        newSettings.rows = rows;
      }
      return newSettings;
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    if (files.length === 0) return;

    const newImages: ImageFile[] = [];

    for (const file of files) {
      const url = URL.createObjectURL(file);
      const img = await loadImage(url);
      newImages.push({
        id: Math.random().toString(36).substr(2, 9),
        file,
        preview: url,
        width: img.width,
        height: img.height,
        aspectRatio: img.width / img.height,
        transform: {
          scale: 1,
          translateX: 0,
          translateY: 0
        }
      });
    }

    const updatedImages = [...images, ...newImages];
    setImages(updatedImages);

    if (updatedImages.length > 0) {
      const avgRatio = updatedImages.reduce((sum, img) => sum + img.aspectRatio, 0) / updatedImages.length;
      const { cols, rows } = calculateBestGrid(updatedImages.length, avgRatio, settings.targetRatio);
      setSettings(prev => ({ ...prev, columns: cols, rows }));
    }
  };

  const updateImageTransform = (id: string, updates: Partial<ImageTransform>) => {
    setImages(prev => prev.map(img => 
      img.id === id ? { ...img, transform: { ...img.transform, ...updates } } : img
    ));
  };

  const resetTransform = (id: string) => {
    updateImageTransform(id, { scale: 1, translateX: 0, translateY: 0 });
  };

  const removeImage = (id: string) => {
    if (selectedId === id) setSelectedId(null);
    setImages(prev => prev.filter(img => img.id !== id));
  };

  const getCanvasMousePos = (e: React.MouseEvent | React.TouchEvent) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;

    const x = clientX - rect.left;
    const y = clientY - rect.top;

    const scaleX = canvasRef.current.width / rect.width;
    const scaleY = canvasRef.current.height / rect.height;

    return { x: x * scaleX, y: y * scaleY };
  };

  const handleCanvasMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!canvasRef.current || images.length === 0) return;
    const pos = getCanvasMousePos(e);
    const dims = getDimensions(images, settings);

    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);
      const x = settings.padding + (col * (dims.cellWidth + settings.gap));
      const y = settings.padding + (row * (dims.cellHeight + settings.gap));

      if (pos.x >= x && pos.x <= x + dims.cellWidth && pos.y >= y && pos.y <= y + dims.cellHeight) {
        setSelectedId(images[i].id);
        setIsDragging(true);
        dragStartRef.current = {
          x: pos.x,
          y: pos.y,
          initialX: images[i].transform.translateX,
          initialY: images[i].transform.translateY
        };
        break;
      }
    }
  };

  const handleCanvasMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDragging || !dragStartRef.current || !selectedId) return;
    const pos = getCanvasMousePos(e);

    const deltaX = pos.x - dragStartRef.current.x;
    const deltaY = pos.y - dragStartRef.current.y;

    updateImageTransform(selectedId, {
      translateX: dragStartRef.current.initialX + deltaX,
      translateY: dragStartRef.current.initialY + deltaY
    });
  };

  const handleCanvasMouseUp = () => {
    setIsDragging(false);
    dragStartRef.current = null;
  };

  const drawCollage = useCallback(async () => {
    if (!canvasRef.current || images.length === 0) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dims = getDimensions(images, settings);
    canvas.width = dims.totalWidth;
    canvas.height = dims.totalHeight;

    ctx.fillStyle = settings.backgroundColor;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);

      const x = settings.padding + (col * (dims.cellWidth + settings.gap));
      const y = settings.padding + (row * (dims.cellHeight + settings.gap));

      try {
        const imgObj = images[i];
        const img = await loadImage(imgObj.preview);

        ctx.save();

        // Use path for rounded rectangles
        if (ctx.roundRect) {
          ctx.beginPath();
          ctx.roundRect(x, y, dims.cellWidth, dims.cellHeight, settings.borderRadius);
          ctx.clip();
        } else {
          ctx.beginPath();
          ctx.rect(x, y, dims.cellWidth, dims.cellHeight);
          ctx.clip();
        }

        const cellAspect = dims.cellWidth / dims.cellHeight;
        const imgAspect = img.width / img.height;

        let baseScale = 1;
        if (imgAspect > cellAspect) {
          baseScale = dims.cellHeight / img.height;
        } else {
          baseScale = dims.cellWidth / img.width;
        }

        const finalScale = baseScale * imgObj.transform.scale;
        const drawWidth = img.width * finalScale;
        const drawHeight = img.height * finalScale;

        const centerX = x + (dims.cellWidth - drawWidth) / 2;
        const centerY = y + (dims.cellHeight - drawHeight) / 2;

        const finalX = centerX + imgObj.transform.translateX;
        const finalY = centerY + imgObj.transform.translateY;

        ctx.drawImage(img, finalX, finalY, drawWidth, drawHeight);

        if (selectedId === imgObj.id) {
          ctx.strokeStyle = 'rgba(129, 140, 248, 0.8)';
          ctx.lineWidth = 15;
          ctx.strokeRect(x + 7.5, y + 7.5, dims.cellWidth - 15, dims.cellHeight - 15);
        }

        ctx.restore();

        // Stroke for border styles
        if (settings.borderWidth > 0) {
          ctx.strokeStyle = settings.borderColor || '#000000';
          ctx.lineWidth = settings.borderWidth;
          if (ctx.roundRect) {
            ctx.beginPath();
            ctx.roundRect(x, y, dims.cellWidth, dims.cellHeight, settings.borderRadius);
            ctx.stroke();
          } else {
            ctx.strokeRect(x, y, dims.cellWidth, dims.cellHeight);
          }
        }

      } catch (err) {
        console.error("Failed to draw image", i, err);
      }
    }
  }, [images, settings, selectedId]);

  useEffect(() => {
    drawCollage();
  }, [drawCollage]);

  const downloadCollage = () => {
    if (!canvasRef.current) return;
    const link = document.createElement('a');
    link.download = `stitched-collage-${Date.now()}.jpg`;
    link.href = canvasRef.current.toDataURL('image/jpeg', settings.quality);
    link.click();
  };

  return (
    <div className="min-h-screen flex flex-col lg:flex-row bg-[#0B0E14] text-slate-100">
      {/* Sidebar Controls */}
      <aside className="w-full lg:w-80 bg-[#161B22] border-r border-slate-800 overflow-y-auto p-5 space-y-6 sticky top-0 h-screen hidden lg:block scrollbar-hide">
        <div className="flex items-center gap-3 mb-6">
          <div className="p-2 bg-indigo-500 rounded-xl shadow-lg shadow-indigo-500/20">
            <LayoutGrid className="w-5 h-5 text-white" />
          </div>
          <h1 className="text-lg font-black tracking-tighter uppercase text-white">Stitcher</h1>
        </div>

        {/* Style Presets Section */}
        <section className="space-y-3">
          <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-slate-500 flex items-center gap-2">
            <Zap className="w-3 h-3 text-amber-400 fill-amber-400" /> 風格預設 Presets
          </h2>
          <div className="grid grid-cols-1 gap-2">
            <button 
              onClick={() => applyPreset(PRESETS.POLAROID)}
              className="flex items-center justify-between px-3 py-2.5 bg-slate-800/50 border border-slate-700 rounded-xl hover:border-indigo-500 hover:bg-slate-800 transition group text-xs font-medium"
            >
              <div className="flex items-center gap-2">
                <Square className="w-4 h-4 text-slate-400 group-hover:text-indigo-400" />
                <span>正方形拍立得</span>
              </div>
              <div className="w-1.5 h-1.5 rounded-full bg-slate-600 group-hover:bg-indigo-500" />
            </button>
            <button 
              onClick={() => applyPreset(PRESETS.VINTAGE_90S)}
              className="flex items-center justify-between px-3 py-2.5 bg-slate-800/50 border border-slate-700 rounded-xl hover:border-indigo-500 hover:bg-slate-800 transition group text-xs font-medium"
            >
              <div className="flex items-center gap-2">
                <ImageIcon className="w-4 h-4 text-slate-400 group-hover:text-indigo-400" />
                <span>90s 拍立得拼貼</span>
              </div>
              <div className="w-1.5 h-1.5 rounded-full bg-slate-600 group-hover:bg-indigo-500" />
            </button>
            <button 
              onClick={() => applyPreset(PRESETS.COMIC)}
              className="flex items-center justify-between px-3 py-2.5 bg-slate-800/50 border border-slate-700 rounded-xl hover:border-indigo-500 hover:bg-slate-800 transition group text-xs font-medium"
            >
              <div className="flex items-center gap-2">
                <LayoutGrid className="w-4 h-4 text-slate-400 group-hover:text-indigo-400" />
                <span>美式漫畫格</span>
              </div>
              <div className="w-1.5 h-1.5 rounded-full bg-slate-600 group-hover:bg-indigo-500" />
            </button>
            <button 
              onClick={() => applyPreset(PRESETS.FOUR_PANEL)}
              className="flex items-center justify-between px-3 py-2.5 bg-slate-800/50 border border-slate-700 rounded-xl hover:border-indigo-500 hover:bg-slate-800 transition group text-xs font-medium"
            >
              <div className="flex items-center gap-2">
                <Columns2 className="w-4 h-4 text-slate-400 group-hover:text-indigo-400" />
                <span>直條四格漫畫</span>
              </div>
              <div className="w-1.5 h-1.5 rounded-full bg-slate-600 group-hover:bg-indigo-500" />
            </button>
          </div>
        </section>

        <section className="space-y-4 pt-2">
          <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-slate-500 flex items-center gap-2">
            <Settings2 className="w-3 h-3" /> 版面參數 Layout
          </h2>

          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-1">
              <label className="text-[10px] text-slate-500 uppercase font-bold">Cols 欄</label>
              <input 
                type="number" 
                value={settings.columns} 
                onChange={e => setSettings(s => ({ ...s, columns: Math.max(1, parseInt(e.target.value) || 1) }))}
                className="w-full bg-[#0D1117] border border-slate-700 rounded-lg p-2 text-sm focus:ring-1 focus:ring-indigo-500 outline-none"
              />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] text-slate-500 uppercase font-bold">Rows 列</label>
              <input 
                type="number" 
                value={settings.rows} 
                onChange={e => setSettings(s => ({ ...s, rows: Math.max(1, parseInt(e.target.value) || 1) }))}
                className="w-full bg-[#0D1117] border border-slate-700 rounded-lg p-2 text-sm focus:ring-1 focus:ring-indigo-500 outline-none"
              />
            </div>
          </div>

          <div className="space-y-3">
            <div>
              <div className="flex justify-between items-center mb-1">
                <label className="text-[10px] text-slate-500 uppercase font-bold">Gap 間距</label>
                <span className="text-[10px] font-mono text-indigo-400">{settings.gap}px</span>
              </div>
              <input 
                type="range" min="0" max="100" 
                value={settings.gap} 
                onChange={e => setSettings(s => ({ ...s, gap: parseInt(e.target.value) }))}
                className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500"
              />
            </div>
            <div>
              <div className="flex justify-between items-center mb-1">
                <label className="text-[10px] text-slate-500 uppercase font-bold">Radius 圓角</label>
                <span className="text-[10px] font-mono text-indigo-400">{settings.borderRadius}px</span>
              </div>
              <input 
                type="range" min="0" max="120" 
                value={settings.borderRadius} 
                onChange={e => setSettings(s => ({ ...s, borderRadius: parseInt(e.target.value) }))}
                className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500"
              />
            </div>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] text-slate-500 uppercase font-bold">BG Color 背景</label>
            <div className="flex gap-2 p-1.5 bg-[#0D1117] border border-slate-700 rounded-lg">
              <input 
                type="color" 
                value={settings.backgroundColor} 
                onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))}
                className="w-8 h-8 bg-transparent border-none cursor-pointer rounded-md overflow-hidden"
              />
              <input 
                type="text" 
                value={settings.backgroundColor.toUpperCase()} 
                onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))}
                className="flex-1 bg-transparent border-none text-xs font-mono focus:outline-none"
              />
            </div>
          </div>
        </section>

        {selectedImage && (
          <section className="p-4 bg-indigo-500/5 rounded-2xl border border-indigo-500/20 space-y-4 animate-in slide-in-from-right-4">
            <div className="flex items-center justify-between">
              <h2 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest flex items-center gap-2">
                <Move className="w-3 h-3" /> 圖層調整 Layer
              </h2>
              <button onClick={() => setSelectedId(null)} className="text-slate-500 hover:text-white">
                <X className="w-4 h-4" />
              </button>
            </div>
            <div className="space-y-3">
              <div>
                <div className="flex justify-between text-[10px] text-slate-500 mb-1 uppercase font-bold">
                  <span>Zoom 縮放</span>
                  <span className="text-indigo-400 font-mono">{selectedImage.transform.scale.toFixed(2)}x</span>
                </div>
                <input 
                  type="range" min="0.5" max="5" step="0.01"
                  value={selectedImage.transform.scale} 
                  onChange={e => updateImageTransform(selectedImage.id, { scale: parseFloat(e.target.value) })}
                  className="w-full h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-indigo-400"
                />
              </div>
              <button
                onClick={() => resetTransform(selectedImage.id)}
                className="w-full py-2 bg-slate-800 hover:bg-slate-700 text-[10px] uppercase font-black tracking-widest text-slate-300 transition rounded-lg"
              >
                Reset Position
              </button>
            </div>
          </section>
        )}

        <div className="pt-6 border-t border-slate-800">
          <button
            onClick={downloadCollage}
            disabled={images.length === 0}
            className="w-full flex items-center justify-center gap-2 py-4 px-4 rounded-2xl bg-indigo-500 hover:bg-indigo-400 disabled:opacity-30 disabled:cursor-not-allowed font-black text-white transition shadow-xl shadow-indigo-500/20"
          >
            <Download className="w-5 h-5" /> 匯出作品 Export
          </button>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden bg-[#0D1117]">
        <header className="px-6 py-4 bg-[#161B22] border-b border-slate-800 flex justify-between items-center z-10">
          <div className="flex items-center gap-3">
            <LayoutGrid className="w-5 h-5 text-indigo-500 lg:hidden" />
            <span className="font-black tracking-tighter text-sm uppercase">Studio Canvas</span>
          </div>
          <div className="flex items-center gap-4">
            <span className="text-[10px] font-bold text-slate-500 hidden md:inline">
              WORKSPACE: {images.length} IMAGES
            </span>
             <label className="cursor-pointer">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <div className="flex items-center gap-2 px-6 py-2.5 bg-indigo-500 hover:bg-indigo-400 rounded-full text-xs font-black transition shadow-lg shadow-indigo-500/20">
                <Upload className="w-4 h-4" />
                <span>上傳照片</span>
              </div>
            </label>
          </div>
        </header>

        {/* Viewport */}
        <div className="flex-1 overflow-auto p-4 lg:p-12 flex items-center justify-center relative bg-[radial-gradient(circle_at_center,_#1c2128_0%,_#0d1117_100%)]">
          {images.length === 0 ? (
            <div className="text-center space-y-4 max-w-sm animate-in zoom-in duration-500">
              <div className="w-20 h-20 bg-[#161B22] rounded-3xl flex items-center justify-center mx-auto border border-slate-700 shadow-2xl">
                <ImageIcon className="w-8 h-8 text-slate-600" />
              </div>
              <h3 className="text-lg font-black text-white uppercase tracking-[0.2em]">Start Stitching</h3>
              <p className="text-slate-500 text-xs leading-relaxed px-10">
                上傳多張 JPG，拖動調整構圖，秒速套用經典拍立得或漫畫風格。
              </p>
            </div>
          ) : (
            <div className="relative group max-h-full">
              <div className="shadow-[0_60px_120px_-20px_rgba(0,0,0,1)] rounded-sm overflow-hidden border border-white/5 bg-[#161B22]">
                <canvas 
                  ref={canvasRef} 
                  onMouseDown={handleCanvasMouseDown}
                  onMouseMove={handleCanvasMouseMove}
                  onMouseUp={handleCanvasMouseUp}
                  onMouseLeave={handleCanvasMouseUp}
                  onTouchStart={handleCanvasMouseDown}
                  onTouchMove={handleCanvasMouseMove}
                  onTouchEnd={handleCanvasMouseUp}
                  style={{ cursor: isDragging ? 'grabbing' : 'grab' }}
                  className="max-w-full max-h-[78vh] object-contain mx-auto select-none touch-none"
                />
              </div>
              <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                <button 
                  onClick={() => { setImages([]); setSelectedId(null); }}
                  className="p-3 bg-red-500/90 hover:bg-red-500 text-white rounded-xl shadow-2xl transition backdrop-blur-md"
                >
                  <Trash2 className="w-5 h-5" />
                </button>
              </div>

              <div className="absolute bottom-4 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/60 backdrop-blur-xl rounded-full text-[10px] font-bold text-white/50 border border-white/10 opacity-0 group-hover:opacity-100 transition-opacity">
                TIP: 直接拖動圖片調整位置
              </div>
            </div>
          )}
        </div>

        {/* Thumbnail Bar */}
        {images.length > 0 && (
          <div className="h-28 bg-[#161B22]/95 backdrop-blur-xl border-t border-slate-800 p-4 flex gap-4 overflow-x-auto items-center scrollbar-hide">
            {images.map((img) => (
              <div key={img.id} className="relative flex-shrink-0 group">
                <button
                  onClick={() => setSelectedId(img.id)}
                  className={`relative block h-16 w-16 overflow-hidden rounded-xl border-2 transition-all duration-300 ${
                    selectedId === img.id 
                      ? 'border-indigo-500 scale-110 ring-4 ring-indigo-500/10' 
                      : 'border-slate-800 hover:border-slate-600'
                  }`}
                >
                  <img src={img.preview} alt="Thumbnail" className="h-full w-full object-cover" />
                </button>
                <button 
                  onClick={(e) => { e.stopPropagation(); removeImage(img.id); }}
                  className="absolute -top-1.5 -right-1.5 p-1 bg-red-500 rounded-full text-white transition opacity-0 group-hover:opacity-100 scale-75 group-hover:scale-100"
                >
                  <X className="w-3 h-3" />
                </button>
              </div>
            ))}
            <label className="flex-shrink-0 h-16 w-16 flex flex-col items-center justify-center border-2 border-dashed border-slate-800 rounded-xl hover:border-indigo-500 hover:bg-indigo-500/5 cursor-pointer transition text-slate-600 hover:text-indigo-400">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <Upload className="w-4 h-4" />
            </label>
          </div>
        )}
      </main>

      {/* Mobile Floating Action */}
      <div className="lg:hidden fixed bottom-6 right-6 z-50">
        <button onClick={downloadCollage} className="p-5 bg-indigo-500 rounded-2xl shadow-2xl text-white active:scale-95 transition-transform">
          <Download className="w-6 h-6" />
        </button>
      </div>
    </div>
  );
};

export default App;

import { ImageFile, CollageSettings, GridDimensions } from '../types';

export const loadImage = (url: string): Promise<HTMLImageElement> => {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => resolve(img);
    img.onerror = reject;
    img.src = url;
  });
};

export const calculateBestGrid = (
  count: number,
  avgAspectRatio: number,
  targetRatio: '5:4' | '4:5' | '1:1' | 'auto'
): { cols: number; rows: number } => {
  if (count === 0) return { cols: 1, rows: 1 };

  let bestCols = 1;
  let bestRows = count;
  let minDiff = Infinity;

  const targetValue = 
    targetRatio === '5:4' ? 1.25 : 
    targetRatio === '4:5' ? 0.8 : 
    targetRatio === '1:1' ? 1.0 : 1.0;

  for (let cols = 1; cols <= count; cols++) {
    const rows = Math.ceil(count / cols);
    const currentRatio = (cols / rows) * avgAspectRatio;
    const diff = Math.abs(currentRatio - targetValue);

    if (diff < minDiff) {
      minDiff = diff;
      bestCols = cols;
      bestRows = rows;
    }
  }

  return { cols: bestCols, rows: bestRows };
};

export const getDimensions = (
  images: ImageFile[],
  settings: CollageSettings
): GridDimensions => {
  const { columns, rows, gap, padding } = settings;

  // Base dimensions on the largest resolution available or a standard high-def base
  const refImg = images[0] || { width: 1200, height: 1200 };
  const cellWidth = refImg.width;
  const cellHeight = refImg.height;

  const totalWidth = (columns * cellWidth) + ((columns - 1) * gap) + (padding * 2);
  const totalHeight = (rows * cellHeight) + ((rows - 1) * gap) + (padding * 2);

  return {
    cols: columns,
    rows,
    cellWidth,
    cellHeight,
    totalWidth,
    totalHeight
  };
};

export interface ImageTransform {
  scale: number;
  translateX: number;
  translateY: number;
}

export interface ImageFile {
  id: string;
  file: File;
  preview: string;
  width: number;
  height: number;
  aspectRatio: number;
  transform: ImageTransform;
}

export interface CollageSettings {
  columns: number;
  rows: number;
  gap: number;
  padding: number;
  backgroundColor: string;
  targetRatio: '5:4' | '4:5' | '1:1' | 'auto';
  quality: number;
  borderRadius: number;
  borderWidth: number;
  borderColor: string;
  style?: 'standard' | 'comic';
}

export interface GridDimensions {
  cols: number;
  rows: number;
  cellWidth: number;
  cellHeight: number;
  totalWidth: number;
  totalHeight: number;
}

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { 
  Upload, 
  Download, 
  Trash2, 
  LayoutGrid, 
  Settings2, 
  X,
  Move,
  Square,
  Zap,
  Columns2,
  Image as ImageIcon,
  RotateCcw
} from 'lucide-react';
import { ImageFile, CollageSettings, ImageTransform } from './types';
import { loadImage, calculateBestGrid, getDimensions } from './utils/image';

const COMIC_WORDS = ['BOOM!', 'OMG!!', 'SALE', 'WOW!', 'ZAP!', 'POW!', 'BIG CHANCE!'];
const STICKER_COLORS = ['#fde047', '#ef4444', '#3b82f6', '#ffffff'];

const PRESETS = {
  POLAROID: {
    backgroundColor: '#ffffff',
    gap: 25,
    padding: 60,
    borderRadius: 8,
    borderWidth: 0,
    targetRatio: '1:1' as const,
    style: 'standard' as const
  },
  VINTAGE_90S: {
    backgroundColor: '#f4f1ea',
    gap: 40,
    padding: 50,
    borderRadius: 24,
    borderWidth: 0,
    targetRatio: '4:5' as const,
    style: 'standard' as const
  },
  COMIC: {
    backgroundColor: '#000000',
    gap: 12,
    padding: 30,
    borderRadius: 0,
    borderWidth: 10,
    borderColor: '#000000',
    targetRatio: 'auto' as const,
    style: 'comic' as const
  },
  FOUR_PANEL: {
    backgroundColor: '#ffffff',
    gap: 8,
    padding: 20,
    borderRadius: 0,
    borderWidth: 3,
    borderColor: '#000000',
    columns: 1,
    targetRatio: 'auto' as const,
    style: 'standard' as const
  }
};

const App: React.FC = () => {
  const [images, setImages] = useState<ImageFile[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [settings, setSettings] = useState<CollageSettings>({
    columns: 2,
    rows: 3,
    gap: 20,
    padding: 40,
    backgroundColor: '#ffffff',
    targetRatio: '5:4',
    quality: 0.9,
    borderRadius: 0,
    borderWidth: 0,
    borderColor: '#ffffff',
    style: 'standard'
  });
  const [isDragging, setIsDragging] = useState(false);
  const [stickerSeed, setStickerSeed] = useState(Date.now());

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const dragStartRef = useRef<{ x: number, y: number, initialX: number, initialY: number } | null>(null);

  const applyPreset = (preset: any) => {
    setSettings(prev => {
      const newSettings = { ...prev, ...preset };
      if (preset.columns) {
        newSettings.rows = Math.ceil(images.length / preset.columns);
      } else if (images.length > 0) {
        const avgRatio = images.reduce((sum, img) => sum + img.aspectRatio, 0) / images.length;
        const { cols, rows } = calculateBestGrid(images.length, avgRatio, newSettings.targetRatio);
        newSettings.columns = cols;
        newSettings.rows = rows;
      }
      return newSettings;
    });
    setStickerSeed(Date.now());
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    if (files.length === 0) return;

    const newImages: ImageFile[] = [];
    for (const file of files) {
      const url = URL.createObjectURL(file);
      const img = await loadImage(url);
      newImages.push({
        id: Math.random().toString(36).substr(2, 9),
        file, preview: url, width: img.width, height: img.height, aspectRatio: img.width / img.height,
        transform: { scale: 1, translateX: 0, translateY: 0 }
      });
    }

    const updatedImages = [...images, ...newImages];
    setImages(updatedImages);
    if (updatedImages.length > 0) {
      const avgRatio = updatedImages.reduce((sum, img) => sum + img.aspectRatio, 0) / updatedImages.length;
      const { cols, rows } = calculateBestGrid(updatedImages.length, avgRatio, settings.targetRatio);
      setSettings(prev => ({ ...prev, columns: cols, rows }));
    }
  };

  const updateImageTransform = (id: string, updates: Partial<ImageTransform>) => {
    setImages(prev => prev.map(img => 
      img.id === id ? { ...img, transform: { ...img.transform, ...updates } } : img
    ));
  };

  const resetTransform = (id: string) => {
    updateImageTransform(id, { scale: 1, translateX: 0, translateY: 0 });
  };

  const removeImage = (id: string) => {
    if (selectedId === id) setSelectedId(null);
    setImages(prev => prev.filter(img => img.id !== id));
  };

  // Drawing helpers for Comic Style
  const drawComicBurst = (ctx: CanvasRenderingContext2D, x: number, y: number, radius: number, text: string, color: string) => {
    ctx.save();
    ctx.translate(x, y);
    ctx.rotate((Math.random() - 0.5) * 0.4);

    // Draw Spikey Background
    ctx.beginPath();
    const spikes = 14 + Math.floor(Math.random() * 6);
    for (let i = 0; i < spikes * 2; i++) {
      const r = i % 2 === 0 ? radius : radius * 0.65;
      const angle = (i * Math.PI) / spikes;
      ctx.lineTo(Math.cos(angle) * r, Math.sin(angle) * r);
    }
    ctx.closePath();
    ctx.fillStyle = color;
    ctx.fill();
    ctx.strokeStyle = 'black';
    ctx.lineWidth = radius * 0.1;
    ctx.stroke();

    // Text with stroke
    ctx.font = `italic black ${radius * 0.45}px Impact, Arial Black, sans-serif`;
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.strokeStyle = 'white';
    ctx.lineWidth = radius * 0.05;
    ctx.strokeText(text, 0, 0);
    ctx.fillStyle = 'black';
    ctx.fillText(text, 0, 0);

    ctx.restore();
  };

  const drawHalftone = (ctx: CanvasRenderingContext2D, w: number, h: number) => {
    ctx.save();
    ctx.globalAlpha = 0.15;
    ctx.fillStyle = '#000000';
    const dotSize = 2;
    const spacing = 8;
    for (let x = 0; x < w; x += spacing) {
      for (let y = 0; y < h; y += spacing) {
        ctx.beginPath();
        ctx.arc(x, y, dotSize, 0, Math.PI * 2);
        ctx.fill();
      }
    }
    ctx.restore();
  };

  const drawCollage = useCallback(async () => {
    if (!canvasRef.current || images.length === 0) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dims = getDimensions(images, settings);
    canvas.width = dims.totalWidth;
    canvas.height = dims.totalHeight;

    ctx.fillStyle = settings.backgroundColor;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Generate grid points for dynamic slanted frames
    const jitter = settings.style === 'comic' ? Math.min(dims.cellWidth, dims.cellHeight) * 0.15 : 0;
    const points: {x: number, y: number}[][] = [];

    // Simple deterministic random based on stickerSeed to keep jitter stable during dragging
    const rng = (i: number) => {
      const x = Math.sin(stickerSeed + i) * 10000;
      return x - Math.floor(x);
    };

    for (let r = 0; r <= settings.rows; r++) {
      points[r] = [];
      for (let c = 0; c <= settings.columns; c++) {
        let px = settings.padding + c * (dims.cellWidth + settings.gap);
        let py = settings.padding + r * (dims.cellHeight + settings.gap);

        // Jitter internal points
        if (c > 0 && c < settings.columns) px += (rng(r * 10 + c) - 0.5) * jitter;
        if (r > 0 && r < settings.rows) py += (rng(c * 10 + r + 100) - 0.5) * jitter;

        points[r][c] = { x: px, y: py };
      }
    }

    // Draw images into polygons
    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);
      const imgObj = images[i];

      const p1 = points[row][col];
      const p2 = points[row][col+1];
      const p3 = points[row+1][col+1];
      const p4 = points[row+1][col];

      try {
        const img = await loadImage(imgObj.preview);
        ctx.save();

        // Path for clipping
        ctx.beginPath();
        if (settings.style === 'comic') {
          // Adjust points slightly for gaps
          const g = settings.gap / 2;
          ctx.moveTo(p1.x + g, p1.y + g);
          ctx.lineTo(p2.x - g, p2.y + g);
          ctx.lineTo(p3.x - g, p3.y - g);
          ctx.lineTo(p4.x + g, p4.y - g);
        } else if (settings.borderRadius > 0 && ctx.roundRect) {
          const rx = settings.padding + (col * (dims.cellWidth + settings.gap));
          const ry = settings.padding + (row * (dims.cellHeight + settings.gap));
          ctx.roundRect(rx, ry, dims.cellWidth, dims.cellHeight, settings.borderRadius);
        } else {
          const rx = settings.padding + (col * (dims.cellWidth + settings.gap));
          const ry = settings.padding + (row * (dims.cellHeight + settings.gap));
          ctx.rect(rx, ry, dims.cellWidth, dims.cellHeight);
        }
        ctx.clip();

        // Image Drawing Logic (Fill/Cover)
        const cellCenterX = (p1.x + p2.x + p3.x + p4.x) / 4;
        const cellCenterY = (p1.y + p2.y + p3.y + p4.y) / 4;

        const cellAspect = dims.cellWidth / dims.cellHeight;
        const imgAspect = img.width / img.height;
        let baseScale = imgAspect > cellAspect ? dims.cellHeight / img.height : dims.cellWidth / img.width;
        const finalScale = baseScale * imgObj.transform.scale;

        const drawWidth = img.width * finalScale;
        const drawHeight = img.height * finalScale;

        ctx.drawImage(
          img, 
          cellCenterX - drawWidth/2 + imgObj.transform.translateX, 
          cellCenterY - drawHeight/2 + imgObj.transform.translateY, 
          drawWidth, 
          drawHeight
        );

        if (settings.style === 'comic') {
          drawHalftone(ctx, dims.totalWidth, dims.totalHeight);
        }

        if (selectedId === imgObj.id) {
          ctx.restore(); // Undo clip for selection indicator
          ctx.save();
          ctx.strokeStyle = '#6366f1';
          ctx.lineWidth = 12;
          ctx.setLineDash([20, 10]);
          ctx.beginPath();
          ctx.moveTo(p1.x, p1.y); ctx.lineTo(p2.x, p2.y); ctx.lineTo(p3.x, p3.y); ctx.lineTo(p4.x, p4.y);
          ctx.closePath();
          ctx.stroke();
        }

        ctx.restore();

        // Draw Frame Stroke
        if (settings.borderWidth > 0) {
          ctx.strokeStyle = settings.borderColor;
          ctx.lineWidth = settings.borderWidth;
          ctx.lineJoin = 'miter';
          ctx.beginPath();
          ctx.moveTo(p1.x, p1.y); ctx.lineTo(p2.x, p2.y); ctx.lineTo(p3.x, p3.y); ctx.lineTo(p4.x, p4.y);
          ctx.closePath();
          ctx.stroke();
        }

      } catch (err) {
        console.error("Failed image draw", i, err);
      }
    }

    // Add Comic Stickers
    if (settings.style === 'comic' && images.length > 0) {
      const numStickers = 2 + Math.floor(rng(77) * 3);
      for (let s = 0; s < numStickers; s++) {
        const sx = settings.padding + rng(s + 500) * (dims.totalWidth - settings.padding * 2);
        const sy = settings.padding + rng(s + 1000) * (dims.totalHeight - settings.padding * 2);
        const word = COMIC_WORDS[Math.floor(rng(s + 2000) * COMIC_WORDS.length)];
        const color = STICKER_COLORS[Math.floor(rng(s + 3000) * STICKER_COLORS.length)];
        const size = 120 + rng(s + 4000) * 80;
        drawComicBurst(ctx, sx, sy, size, word, color);
      }
    }
  }, [images, settings, selectedId, stickerSeed]);

  useEffect(() => {
    drawCollage();
  }, [drawCollage]);

  const handleCanvasMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!canvasRef.current || images.length === 0) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;

    const scaleX = canvasRef.current.width / rect.width;
    const scaleY = canvasRef.current.height / rect.height;
    const x = (clientX - rect.left) * scaleX;
    const y = (clientY - rect.top) * scaleY;

    // Detection logic
    const dims = getDimensions(images, settings);
    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);
      const rx = settings.padding + (col * (dims.cellWidth + settings.gap));
      const ry = settings.padding + (row * (dims.cellHeight + settings.gap));

      if (x >= rx && x <= rx + dims.cellWidth && y >= ry && y <= ry + dims.cellHeight) {
        setSelectedId(images[i].id);
        setIsDragging(true);
        dragStartRef.current = { x, y, initialX: images[i].transform.translateX, initialY: images[i].transform.translateY };
        break;
      }
    }
  };

  const handleCanvasMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDragging || !dragStartRef.current || !selectedId) return;
    const rect = canvasRef.current!.getBoundingClientRect();
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;

    const scaleX = canvasRef.current!.width / rect.width;
    const scaleY = canvasRef.current!.height / rect.height;
    const x = (clientX - rect.left) * scaleX;
    const y = (clientY - rect.top) * scaleY;

    updateImageTransform(selectedId, {
      translateX: dragStartRef.current.initialX + (x - dragStartRef.current.x),
      translateY: dragStartRef.current.initialY + (y - dragStartRef.current.y)
    });
  };

  const handleCanvasMouseUp = () => {
    setIsDragging(false);
    dragStartRef.current = null;
  };

  const downloadCollage = () => {
    if (!canvasRef.current) return;
    const link = document.createElement('a');
    link.download = `comic-stitch-${Date.now()}.jpg`;
    link.href = canvasRef.current.toDataURL('image/jpeg', settings.quality);
    link.click();
  };

  return (
    <div className="min-h-screen flex flex-col lg:flex-row bg-[#0B0E14] text-slate-100 selection:bg-indigo-500/30">
      <aside className="w-full lg:w-80 bg-[#161B22] border-r border-slate-800 overflow-y-auto p-5 space-y-6 sticky top-0 h-screen hidden lg:block scrollbar-hide">
        <div className="flex items-center gap-3 mb-6">
          <div className="p-2 bg-indigo-500 rounded-xl shadow-lg shadow-indigo-500/20">
            <LayoutGrid className="w-5 h-5 text-white" />
          </div>
          <h1 className="text-lg font-black tracking-tighter uppercase text-white">Stitcher</h1>
        </div>

        <section className="space-y-3">
          <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-slate-500 flex items-center gap-2">
            <Zap className="w-3 h-3 text-amber-400 fill-amber-400" /> 風格預設 Presets
          </h2>
          <div className="grid grid-cols-1 gap-2">
            <button onClick={() => applyPreset(PRESETS.COMIC)} className={`flex items-center justify-between px-3 py-2.5 bg-slate-800/50 border rounded-xl transition group text-xs font-bold ${settings.style === 'comic' ? 'border-indigo-500 bg-slate-800' : 'border-slate-700 hover:border-slate-500'}`}>
              <div className="flex items-center gap-2">
                <Zap className="w-4 h-4 text-amber-400" />
                <span>美式漫畫格</span>
              </div>
              <div className="px-1.5 py-0.5 rounded bg-amber-500/10 text-amber-500 text-[8px]">New!</div>
            </button>
            <button onClick={() => applyPreset(PRESETS.POLAROID)} className="flex items-center justify-between px-3 py-2.5 bg-slate-800/50 border border-slate-700 rounded-xl hover:border-indigo-500 transition group text-xs font-medium">
              <div className="flex items-center gap-2">
                <Square className="w-4 h-4 text-slate-400" />
                <span>正方形拍立得</span>
              </div>
            </button>
            <button onClick={() => applyPreset(PRESETS.VINTAGE_90S)} className="flex items-center justify-between px-3 py-2.5 bg-slate-800/50 border border-slate-700 rounded-xl hover:border-indigo-500 transition group text-xs font-medium">
              <div className="flex items-center gap-2">
                <ImageIcon className="w-4 h-4 text-slate-400" />
                <span>90s 拼貼感</span>
              </div>
            </button>
            <button onClick={() => applyPreset(PRESETS.FOUR_PANEL)} className="flex items-center justify-between px-3 py-2.5 bg-slate-800/50 border border-slate-700 rounded-xl hover:border-indigo-500 transition group text-xs font-medium">
              <div className="flex items-center gap-2">
                <Columns2 className="w-4 h-4 text-slate-400" />
                <span>直條四格</span>
              </div>
            </button>
          </div>
        </section>

        <section className="space-y-4 pt-2">
          <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-slate-500 flex items-center gap-2">
            <Settings2 className="w-3 h-3" /> 版面 Layout
          </h2>

          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-1">
              <label className="text-[10px] text-slate-500 uppercase font-bold">Cols 欄</label>
              <input type="number" value={settings.columns} onChange={e => setSettings(s => ({ ...s, columns: Math.max(1, parseInt(e.target.value) || 1) }))} className="w-full bg-[#0D1117] border border-slate-700 rounded-lg p-2 text-sm outline-none" />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] text-slate-500 uppercase font-bold">Rows 列</label>
              <input type="number" value={settings.rows} onChange={e => setSettings(s => ({ ...s, rows: Math.max(1, parseInt(e.target.value) || 1) }))} className="w-full bg-[#0D1117] border border-slate-700 rounded-lg p-2 text-sm outline-none" />
            </div>
          </div>

          <div className="space-y-3">
            <div>
              <div className="flex justify-between items-center mb-1">
                <label className="text-[10px] text-slate-500 uppercase font-bold">Gap 間距</label>
                <span className="text-[10px] font-mono text-indigo-400">{settings.gap}px</span>
              </div>
              <input type="range" min="0" max="100" value={settings.gap} onChange={e => setSettings(s => ({ ...s, gap: parseInt(e.target.value) }))} className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500" />
            </div>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] text-slate-500 uppercase font-bold">BG Color 背景色</label>
            <div className="flex gap-2 p-1.5 bg-[#0D1117] border border-slate-700 rounded-lg">
              <input type="color" value={settings.backgroundColor} onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))} className="w-8 h-8 bg-transparent border-none cursor-pointer rounded-md overflow-hidden" />
              <input type="text" value={settings.backgroundColor.toUpperCase()} onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))} className="flex-1 bg-transparent border-none text-xs font-mono focus:outline-none uppercase" />
            </div>
          </div>
        </section>

        {selectedImage && (
          <section className="p-4 bg-indigo-500/5 rounded-2xl border border-indigo-500/20 space-y-4 animate-in slide-in-from-right-4">
            <div className="flex items-center justify-between">
              <h2 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest flex items-center gap-2">
                <Move className="w-3 h-3" /> 圖層 Layer
              </h2>
              <button onClick={() => setSelectedId(null)} className="text-slate-500 hover:text-white"><X className="w-4 h-4" /></button>
            </div>
            <div className="space-y-3">
              <label className="text-[10px] text-slate-500 uppercase font-bold block">Scale 縮放</label>
              <input type="range" min="0.5" max="4" step="0.01" value={selectedImage.transform.scale} onChange={e => updateImageTransform(selectedImage.id, { scale: parseFloat(e.target.value) })} className="w-full h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-indigo-400" />
              <button onClick={() => resetTransform(selectedImage.id)} className="w-full py-2 bg-slate-800 hover:bg-slate-700 text-[10px] uppercase font-black text-slate-300 transition rounded-lg">Reset Position</button>
            </div>
          </section>
        )}

        {settings.style === 'comic' && (
          <button onClick={() => setStickerSeed(Date.now())} className="w-full py-3 bg-amber-500/10 hover:bg-amber-500/20 text-amber-500 text-[10px] uppercase font-bold rounded-xl border border-amber-500/20 transition flex items-center justify-center gap-2">
            <RotateCcw className="w-3 h-3" /> 重隨隨機裝飾
          </button>
        )}

        <div className="pt-6 border-t border-slate-800">
          <button onClick={downloadCollage} disabled={images.length === 0} className="w-full flex items-center justify-center gap-2 py-4 px-4 rounded-2xl bg-indigo-500 hover:bg-indigo-400 disabled:opacity-30 disabled:cursor-not-allowed font-black text-white transition shadow-xl shadow-indigo-500/20 uppercase tracking-widest text-sm">
            <Download className="w-5 h-5" /> Export
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col h-screen overflow-hidden bg-[#0D1117]">
        <header className="px-6 py-4 bg-[#161B22] border-b border-slate-800 flex justify-between items-center z-10">
          <div className="flex items-center gap-3">
            <LayoutGrid className="w-5 h-5 text-indigo-500 lg:hidden" />
            <span className="font-black tracking-tighter text-sm uppercase">Studio Canvas</span>
          </div>
          <div className="flex items-center gap-4">
             <label className="cursor-pointer">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <div className="flex items-center gap-2 px-6 py-2.5 bg-indigo-500 hover:bg-indigo-400 rounded-full text-xs font-black transition shadow-lg shadow-indigo-500/20">
                <Upload className="w-4 h-4" />
                <span>上傳照片</span>
              </div>
            </label>
          </div>
        </header>

        <div className="flex-1 overflow-auto p-4 lg:p-12 flex items-center justify-center relative bg-[#0D1117]">
          {images.length === 0 ? (
            <div className="text-center space-y-4 max-w-sm">
              <div className="w-16 h-16 bg-[#161B22] rounded-2xl flex items-center justify-center mx-auto border border-slate-700">
                <ImageIcon className="w-6 h-6 text-slate-600" />
              </div>
              <h3 className="text-md font-black text-white uppercase tracking-widest">Start Stitching</h3>
              <p className="text-slate-500 text-xs px-10">上傳多張 JPG，點擊切換漫畫格風格，直接拖動圖片調整構圖。</p>
            </div>
          ) : (
            <div className="relative group max-h-full">
              <div className="shadow-[0_60px_120px_-20px_rgba(0,0,0,0.8)] rounded-sm overflow-hidden border border-white/5">
                <canvas 
                  ref={canvasRef} 
                  onMouseDown={handleCanvasMouseDown}
                  onMouseMove={handleCanvasMouseMove}
                  onMouseUp={handleCanvasMouseUp}
                  onMouseLeave={handleCanvasMouseUp}
                  onTouchStart={handleCanvasMouseDown}
                  onTouchMove={handleCanvasMouseMove}
                  onTouchEnd={handleCanvasMouseUp}
                  style={{ cursor: isDragging ? 'grabbing' : 'grab' }}
                  className="max-w-full max-h-[78vh] object-contain mx-auto select-none touch-none bg-black"
                />
              </div>
              <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                <button onClick={() => { setImages([]); setSelectedId(null); }} className="p-3 bg-red-500/90 hover:bg-red-500 text-white rounded-xl shadow-2xl transition backdrop-blur-md">
                  <Trash2 className="w-5 h-5" />
                </button>
              </div>
            </div>
          )}
        </div>

        {images.length > 0 && (
          <div className="h-28 bg-[#161B22]/95 backdrop-blur-xl border-t border-slate-800 p-4 flex gap-4 overflow-x-auto items-center scrollbar-hide">
            {images.map((img) => (
              <div key={img.id} className="relative flex-shrink-0 group">
                <button
                  onClick={() => setSelectedId(img.id)}
                  className={`relative block h-16 w-16 overflow-hidden rounded-xl border-2 transition-all duration-300 ${
                    selectedId === img.id ? 'border-indigo-500 scale-110' : 'border-slate-800 hover:border-slate-600'
                  }`}
                >
                  <img src={img.preview} alt="Thumb" className="h-full w-full object-cover" />
                </button>
                <button onClick={(e) => { e.stopPropagation(); removeImage(img.id); }} className="absolute -top-1.5 -right-1.5 p-1 bg-red-500 rounded-full text-white transition opacity-0 group-hover:opacity-100 scale-75">
                  <X className="w-3 h-3" />
                </button>
              </div>
            ))}
            <label className="flex-shrink-0 h-16 w-16 flex items-center justify-center border-2 border-dashed border-slate-800 rounded-xl hover:border-indigo-500 hover:bg-indigo-500/5 cursor-pointer transition">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <Upload className="w-4 h-4 text-slate-600" />
            </label>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { 
  Upload, 
  Download, 
  Trash2, 
  LayoutGrid, 
  Settings2, 
  X,
  Move,
  Square,
  Zap,
  Columns2,
  Image as ImageIcon,
  RotateCcw,
  Sparkles,
  Loader2
} from 'lucide-react';
import { ImageFile, CollageSettings, ImageTransform } from './types';
import { loadImage, calculateBestGrid, getDimensions } from './utils/image';
import { generateDesignStyle } from './services/gemini';

const COMIC_WORDS = ['BOOM!', 'OMG!!', 'SALE', 'WOW!', 'ZAP!', 'POW!', 'BIG CHANCE!'];
const STICKER_COLORS = ['#fde047', '#ef4444', '#3b82f6', '#ffffff'];

const PRESETS = {
  POLAROID: {
    backgroundColor: '#ffffff',
    gap: 25,
    padding: 60,
    borderRadius: 8,
    borderWidth: 0,
    targetRatio: '1:1' as const,
    style: 'standard' as const
  },
  VINTAGE_90S: {
    backgroundColor: '#f4f1ea',
    gap: 40,
    padding: 50,
    borderRadius: 24,
    borderWidth: 0,
    targetRatio: '4:5' as const,
    style: 'standard' as const
  },
  COMIC: {
    backgroundColor: '#000000',
    gap: 12,
    padding: 30,
    borderRadius: 0,
    borderWidth: 10,
    borderColor: '#000000',
    targetRatio: 'auto' as const,
    style: 'comic' as const
  },
  FOUR_PANEL: {
    backgroundColor: '#ffffff',
    gap: 8,
    padding: 20,
    borderRadius: 0,
    borderWidth: 3,
    borderColor: '#000000',
    columns: 1,
    targetRatio: 'auto' as const,
    style: 'standard' as const
  }
};

const App: React.FC = () => {
  const [images, setImages] = useState<ImageFile[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [settings, setSettings] = useState<CollageSettings>({
    columns: 2,
    rows: 3,
    gap: 20,
    padding: 40,
    backgroundColor: '#ffffff',
    targetRatio: '5:4',
    quality: 0.9,
    borderRadius: 0,
    borderWidth: 0,
    borderColor: '#ffffff',
    style: 'standard'
  });
  const [isDragging, setIsDragging] = useState(false);
  const [stickerSeed, setStickerSeed] = useState(Date.now());
  const [isGenerating, setIsGenerating] = useState(false);
  const [designTip, setDesignTip] = useState<string | null>(null);

  // Fix: Define selectedImage variable to be used in the Layer adjustments section
  // This resolves the errors on lines 472, 482, and 483
  const selectedImage = images.find(img => img.id === selectedId);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const dragStartRef = useRef<{ x: number, y: number, initialX: number, initialY: number } | null>(null);

  const applyPreset = (preset: any) => {
    setSettings(prev => {
      const newSettings = { ...prev, ...preset };
      if (preset.columns) {
        newSettings.rows = Math.ceil(images.length / preset.columns);
      } else if (images.length > 0) {
        const avgRatio = images.reduce((sum, img) => sum + img.aspectRatio, 0) / images.length;
        const { cols, rows } = calculateBestGrid(images.length, avgRatio, newSettings.targetRatio);
        newSettings.columns = cols;
        newSettings.rows = rows;
      }
      return newSettings;
    });
    setStickerSeed(Date.now());
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    if (files.length === 0) return;

    const newImages: ImageFile[] = [];
    for (const file of files) {
      const url = URL.createObjectURL(file);
      const img = await loadImage(url);
      newImages.push({
        id: Math.random().toString(36).substr(2, 9),
        file, preview: url, width: img.width, height: img.height, aspectRatio: img.width / img.height,
        transform: { scale: 1, translateX: 0, translateY: 0 }
      });
    }

    const updatedImages = [...images, ...newImages];
    setImages(updatedImages);
    if (updatedImages.length > 0) {
      const avgRatio = updatedImages.reduce((sum, img) => sum + img.aspectRatio, 0) / updatedImages.length;
      const { cols, rows } = calculateBestGrid(updatedImages.length, avgRatio, settings.targetRatio);
      setSettings(prev => ({ ...prev, columns: cols, rows }));
    }
  };

  const updateImageTransform = (id: string, updates: Partial<ImageTransform>) => {
    setImages(prev => prev.map(img => 
      img.id === id ? { ...img, transform: { ...img.transform, ...updates } } : img
    ));
  };

  const resetTransform = (id: string) => {
    updateImageTransform(id, { scale: 1, translateX: 0, translateY: 0 });
  };

  const removeImage = (id: string) => {
    if (selectedId === id) setSelectedId(null);
    setImages(prev => prev.filter(img => img.id !== id));
  };

  // Integration: Trigger Gemini AI analysis to automatically suggest a background color and design tip
  const handleAutoDesign = async () => {
    if (!canvasRef.current || images.length === 0) return;
    setIsGenerating(true);
    try {
      const dataUrl = canvasRef.current.toDataURL('image/jpeg', 0.5);
      const suggestion = await generateDesignStyle(dataUrl);
      setSettings(prev => ({
        ...prev,
        backgroundColor: suggestion.backgroundColor
      }));
      setDesignTip(suggestion.designTip);
    } catch (error) {
      console.error("Auto design error:", error);
    } finally {
      setIsGenerating(false);
    }
  };

  // Drawing helpers for Comic Style
  const drawComicBurst = (ctx: CanvasRenderingContext2D, x: number, y: number, radius: number, text: string, color: string) => {
    ctx.save();
    ctx.translate(x, y);
    ctx.rotate((Math.random() - 0.5) * 0.4);

    // Draw Spikey Background
    ctx.beginPath();
    const spikes = 14 + Math.floor(Math.random() * 6);
    for (let i = 0; i < spikes * 2; i++) {
      const r = i % 2 === 0 ? radius : radius * 0.65;
      const angle = (i * Math.PI) / spikes;
      ctx.lineTo(Math.cos(angle) * r, Math.sin(angle) * r);
    }
    ctx.closePath();
    ctx.fillStyle = color;
    ctx.fill();
    ctx.strokeStyle = 'black';
    ctx.lineWidth = radius * 0.1;
    ctx.stroke();

    // Text with stroke
    ctx.font = `italic black ${radius * 0.45}px Impact, Arial Black, sans-serif`;
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.strokeStyle = 'white';
    ctx.lineWidth = radius * 0.05;
    ctx.strokeText(text, 0, 0);
    ctx.fillStyle = 'black';
    ctx.fillText(text, 0, 0);

    ctx.restore();
  };

  const drawHalftone = (ctx: CanvasRenderingContext2D, w: number, h: number) => {
    ctx.save();
    ctx.globalAlpha = 0.15;
    ctx.fillStyle = '#000000';
    const dotSize = 2;
    const spacing = 8;
    for (let x = 0; x < w; x += spacing) {
      for (let y = 0; y < h; y += spacing) {
        ctx.beginPath();
        ctx.arc(x, y, dotSize, 0, Math.PI * 2);
        ctx.fill();
      }
    }
    ctx.restore();
  };

  const drawCollage = useCallback(async () => {
    if (!canvasRef.current || images.length === 0) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dims = getDimensions(images, settings);
    canvas.width = dims.totalWidth;
    canvas.height = dims.totalHeight;

    ctx.fillStyle = settings.backgroundColor;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Generate grid points for dynamic slanted frames
    const jitter = settings.style === 'comic' ? Math.min(dims.cellWidth, dims.cellHeight) * 0.15 : 0;
    const points: {x: number, y: number}[][] = [];

    // Simple deterministic random based on stickerSeed to keep jitter stable during dragging
    const rng = (i: number) => {
      const x = Math.sin(stickerSeed + i) * 10000;
      return x - Math.floor(x);
    };

    for (let r = 0; r <= settings.rows; r++) {
      points[r] = [];
      for (let c = 0; c <= settings.columns; c++) {
        let px = settings.padding + c * (dims.cellWidth + settings.gap);
        let py = settings.padding + r * (dims.cellHeight + settings.gap);

        // Jitter internal points
        if (c > 0 && c < settings.columns) px += (rng(r * 10 + c) - 0.5) * jitter;
        if (r > 0 && r < settings.rows) py += (rng(c * 10 + r + 100) - 0.5) * jitter;

        points[r][c] = { x: px, y: py };
      }
    }

    // Draw images into polygons
    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);
      const imgObj = images[i];

      const p1 = points[row][col];
      const p2 = points[row][col+1];
      const p3 = points[row+1][col+1];
      const p4 = points[row+1][col];

      try {
        const img = await loadImage(imgObj.preview);
        ctx.save();

        // Path for clipping
        ctx.beginPath();
        if (settings.style === 'comic') {
          // Adjust points slightly for gaps
          const g = settings.gap / 2;
          ctx.moveTo(p1.x + g, p1.y + g);
          ctx.lineTo(p2.x - g, p2.y + g);
          ctx.lineTo(p3.x - g, p3.y - g);
          ctx.lineTo(p4.x + g, p4.y - g);
        } else if (settings.borderRadius > 0 && (ctx as any).roundRect) {
          const rx = settings.padding + (col * (dims.cellWidth + settings.gap));
          const ry = settings.padding + (row * (dims.cellHeight + settings.gap));
          (ctx as any).roundRect(rx, ry, dims.cellWidth, dims.cellHeight, settings.borderRadius);
        } else {
          const rx = settings.padding + (col * (dims.cellWidth + settings.gap));
          const ry = settings.padding + (row * (dims.cellHeight + settings.gap));
          ctx.rect(rx, ry, dims.cellWidth, dims.cellHeight);
        }
        ctx.clip();

        // Image Drawing Logic (Fill/Cover)
        const cellCenterX = (p1.x + p2.x + p3.x + p4.x) / 4;
        const cellCenterY = (p1.y + p2.y + p3.y + p4.y) / 4;

        const cellAspect = dims.cellWidth / dims.cellHeight;
        const imgAspect = img.width / img.height;
        let baseScale = imgAspect > cellAspect ? dims.cellHeight / img.height : dims.cellWidth / img.width;
        const finalScale = baseScale * imgObj.transform.scale;

        const drawWidth = img.width * finalScale;
        const drawHeight = img.height * finalScale;

        ctx.drawImage(
          img, 
          cellCenterX - drawWidth/2 + imgObj.transform.translateX, 
          cellCenterY - drawHeight/2 + imgObj.transform.translateY, 
          drawWidth, 
          drawHeight
        );

        if (settings.style === 'comic') {
          drawHalftone(ctx, dims.totalWidth, dims.totalHeight);
        }

        if (selectedId === imgObj.id) {
          ctx.restore(); // Undo clip for selection indicator
          ctx.save();
          ctx.strokeStyle = '#6366f1';
          ctx.lineWidth = 12;
          ctx.setLineDash([20, 10]);
          ctx.beginPath();
          ctx.moveTo(p1.x, p1.y); ctx.lineTo(p2.x, p2.y); ctx.lineTo(p3.x, p3.y); ctx.lineTo(p4.x, p4.y);
          ctx.closePath();
          ctx.stroke();
        }

        ctx.restore();

        // Draw Frame Stroke
        if (settings.borderWidth > 0) {
          ctx.strokeStyle = settings.borderColor;
          ctx.lineWidth = settings.borderWidth;
          ctx.lineJoin = 'miter';
          ctx.beginPath();
          ctx.moveTo(p1.x, p1.y); ctx.lineTo(p2.x, p2.y); ctx.lineTo(p3.x, p3.y); ctx.lineTo(p4.x, p4.y);
          ctx.closePath();
          ctx.stroke();
        }

      } catch (err) {
        console.error("Failed image draw", i, err);
      }
    }

    // Add Comic Stickers
    if (settings.style === 'comic' && images.length > 0) {
      const numStickers = 2 + Math.floor(rng(77) * 3);
      for (let s = 0; s < numStickers; s++) {
        const sx = settings.padding + rng(s + 500) * (dims.totalWidth - settings.padding * 2);
        const sy = settings.padding + rng(s + 1000) * (dims.totalHeight - settings.padding * 2);
        const word = COMIC_WORDS[Math.floor(rng(s + 2000) * COMIC_WORDS.length)];
        const color = STICKER_COLORS[Math.floor(rng(s + 3000) * STICKER_COLORS.length)];
        const size = 120 + rng(s + 4000) * 80;
        drawComicBurst(ctx, sx, sy, size, word, color);
      }
    }
  }, [images, settings, selectedId, stickerSeed]);

  useEffect(() => {
    drawCollage();
  }, [drawCollage]);

  const handleCanvasMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!canvasRef.current || images.length === 0) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;

    const scaleX = canvasRef.current.width / rect.width;
    const scaleY = canvasRef.current.height / rect.height;
    const x = (clientX - rect.left) * scaleX;
    const y = (clientY - rect.top) * scaleY;

    // Detection logic
    const dims = getDimensions(images, settings);
    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);
      const rx = settings.padding + (col * (dims.cellWidth + settings.gap));
      const ry = settings.padding + (row * (dims.cellHeight + settings.gap));

      if (x >= rx && x <= rx + dims.cellWidth && y >= ry && y <= ry + dims.cellHeight) {
        setSelectedId(images[i].id);
        setIsDragging(true);
        dragStartRef.current = { x, y, initialX: images[i].transform.translateX, initialY: images[i].transform.translateY };
        break;
      }
    }
  };

  const handleCanvasMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDragging || !dragStartRef.current || !selectedId) return;
    const rect = canvasRef.current!.getBoundingClientRect();
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;

    const scaleX = canvasRef.current!.width / rect.width;
    const scaleY = canvasRef.current!.height / rect.height;
    const x = (clientX - rect.left) * scaleX;
    const y = (clientY - rect.top) * scaleY;

    updateImageTransform(selectedId, {
      translateX: dragStartRef.current.initialX + (x - dragStartRef.current.x),
      translateY: dragStartRef.current.initialY + (y - dragStartRef.current.y)
    });
  };

  const handleCanvasMouseUp = () => {
    setIsDragging(false);
    dragStartRef.current = null;
  };

  const downloadCollage = () => {
    if (!canvasRef.current) return;
    const link = document.createElement('a');
    link.download = `comic-stitch-${Date.now()}.jpg`;
    link.href = canvasRef.current.toDataURL('image/jpeg', settings.quality);
    link.click();
  };

  return (
    <div className="min-h-screen flex flex-col lg:flex-row bg-[#0B0E14] text-slate-100 selection:bg-indigo-500/30">
      <aside className="w-full lg:w-80 bg-[#161B22] border-r border-slate-800 overflow-y-auto p-5 space-y-6 sticky top-0 h-screen hidden lg:block scrollbar-hide">
        <div className="flex items-center gap-3 mb-6">
          <div className="p-2 bg-indigo-500 rounded-xl shadow-lg shadow-indigo-500/20">
            <LayoutGrid className="w-5 h-5 text-white" />
          </div>
          <h1 className="text-lg font-black tracking-tighter uppercase text-white">Stitcher</h1>
        </div>

        <section className="space-y-3">
          <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-slate-500 flex items-center gap-2">
            <Zap className="w-3 h-3 text-amber-400 fill-amber-400" /> 風格預設 Presets
          </h2>
          <div className="grid grid-cols-1 gap-2">
            <button onClick={() => applyPreset(PRESETS.COMIC)} className={`flex items-center justify-between px-3 py-2.5 bg-slate-800/50 border rounded-xl transition group text-xs font-bold ${settings.style === 'comic' ? 'border-indigo-500 bg-slate-800' : 'border-slate-700 hover:border-slate-500'}`}>
              <div className="flex items-center gap-2">
                <Zap className="w-4 h-4 text-amber-400" />
                <span>美式漫畫格</span>
              </div>
              <div className="px-1.5 py-0.5 rounded bg-amber-500/10 text-amber-500 text-[8px]">New!</div>
            </button>
            <button onClick={() => applyPreset(PRESETS.POLAROID)} className="flex items-center justify-between px-3 py-2.5 bg-slate-800/50 border border-slate-700 rounded-xl hover:border-indigo-500 transition group text-xs font-medium">
              <div className="flex items-center gap-2">
                <Square className="w-4 h-4 text-slate-400" />
                <span>正方形拍立得</span>
              </div>
            </button>
            <button onClick={() => applyPreset(PRESETS.VINTAGE_90S)} className="flex items-center justify-between px-3 py-2.5 bg-slate-800/50 border border-slate-700 rounded-xl hover:border-indigo-500 transition group text-xs font-medium">
              <div className="flex items-center gap-2">
                <ImageIcon className="w-4 h-4 text-slate-400" />
                <span>90s 拼貼感</span>
              </div>
            </button>
            <button onClick={() => applyPreset(PRESETS.FOUR_PANEL)} className="flex items-center justify-between px-3 py-2.5 bg-slate-800/50 border border-slate-700 rounded-xl hover:border-indigo-500 transition group text-xs font-medium">
              <div className="flex items-center gap-2">
                <Columns2 className="w-4 h-4 text-slate-400" />
                <span>直條四格</span>
              </div>
            </button>
          </div>
        </section>

        <section className="space-y-4 pt-2">
          <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-slate-500 flex items-center gap-2">
            <Settings2 className="w-3 h-3" /> 版面 Layout
          </h2>

          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-1">
              <label className="text-[10px] text-slate-500 uppercase font-bold">Cols 欄</label>
              <input type="number" value={settings.columns} onChange={e => setSettings(s => ({ ...s, columns: Math.max(1, parseInt(e.target.value) || 1) }))} className="w-full bg-[#0D1117] border border-slate-700 rounded-lg p-2 text-sm outline-none" />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] text-slate-500 uppercase font-bold">Rows 列</label>
              <input type="number" value={settings.rows} onChange={e => setSettings(s => ({ ...s, rows: Math.max(1, parseInt(e.target.value) || 1) }))} className="w-full bg-[#0D1117] border border-slate-700 rounded-lg p-2 text-sm outline-none" />
            </div>
          </div>

          <div className="space-y-3">
            <div>
              <div className="flex justify-between items-center mb-1">
                <label className="text-[10px] text-slate-500 uppercase font-bold">Gap 間距</label>
                <span className="text-[10px] font-mono text-indigo-400">{settings.gap}px</span>
              </div>
              <input type="range" min="0" max="100" value={settings.gap} onChange={e => setSettings(s => ({ ...s, gap: parseInt(e.target.value) }))} className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500" />
            </div>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] text-slate-500 uppercase font-bold">BG Color 背景色</label>
            <div className="flex gap-2 p-1.5 bg-[#0D1117] border border-slate-700 rounded-lg">
              <input type="color" value={settings.backgroundColor} onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))} className="w-8 h-8 bg-transparent border-none cursor-pointer rounded-md overflow-hidden" />
              <input type="text" value={settings.backgroundColor.toUpperCase()} onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))} className="flex-1 bg-transparent border-none text-xs font-mono focus:outline-none uppercase" />
            </div>

            {/* AI Assistant UI */}
            <button 
              onClick={handleAutoDesign}
              disabled={isGenerating || images.length === 0}
              className="mt-3 w-full flex items-center justify-center gap-2 py-2.5 px-3 bg-indigo-500/10 hover:bg-indigo-500/20 text-indigo-400 text-[10px] uppercase font-bold rounded-xl border border-indigo-500/20 transition disabled:opacity-50 shadow-sm"
            >
              {isGenerating ? <Loader2 className="w-3 h-3 animate-spin" /> : <Sparkles className="w-3 h-3" />}
              AI 智能配色與建議
            </button>
            {designTip && (
              <div className="mt-3 p-3 bg-indigo-500/5 rounded-xl text-[10px] text-slate-300 italic border-l-2 border-indigo-500 leading-relaxed">
                <span className="text-indigo-400 font-bold not-italic block mb-1">AI 建議:</span>
                {designTip}
              </div>
            )}
          </div>
        </section>

        {selectedImage && (
          <section className="p-4 bg-indigo-500/5 rounded-2xl border border-indigo-500/20 space-y-4 animate-in slide-in-from-right-4">
            <div className="flex items-center justify-between">
              <h2 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest flex items-center gap-2">
                <Move className="w-3 h-3" /> 圖層 Layer
              </h2>
              <button onClick={() => setSelectedId(null)} className="text-slate-500 hover:text-white"><X className="w-4 h-4" /></button>
            </div>
            <div className="space-y-3">
              <label className="text-[10px] text-slate-500 uppercase font-bold block">Scale 縮放</label>
              <input type="range" min="0.5" max="4" step="0.01" value={selectedImage.transform.scale} onChange={e => updateImageTransform(selectedImage.id, { scale: parseFloat(e.target.value) })} className="w-full h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-indigo-400" />
              <button onClick={() => resetTransform(selectedImage.id)} className="w-full py-2 bg-slate-800 hover:bg-slate-700 text-[10px] uppercase font-black text-slate-300 transition rounded-lg">Reset Position</button>
            </div>
          </section>
        )}

        {settings.style === 'comic' && (
          <button onClick={() => setStickerSeed(Date.now())} className="w-full py-3 bg-amber-500/10 hover:bg-amber-500/20 text-amber-500 text-[10px] uppercase font-bold rounded-xl border border-amber-500/20 transition flex items-center justify-center gap-2">
            <RotateCcw className="w-3 h-3" /> 重隨隨機裝飾
          </button>
        )}

        <div className="pt-6 border-t border-slate-800">
          <button onClick={downloadCollage} disabled={images.length === 0} className="w-full flex items-center justify-center gap-2 py-4 px-4 rounded-2xl bg-indigo-500 hover:bg-indigo-400 disabled:opacity-30 disabled:cursor-not-allowed font-black text-white transition shadow-xl shadow-indigo-500/20 uppercase tracking-widest text-sm">
            <Download className="w-5 h-5" /> Export
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col h-screen overflow-hidden bg-[#0D1117]">
        <header className="px-6 py-4 bg-[#161B22] border-b border-slate-800 flex justify-between items-center z-10">
          <div className="flex items-center gap-3">
            <LayoutGrid className="w-5 h-5 text-indigo-500 lg:hidden" />
            <span className="font-black tracking-tighter text-sm uppercase">Studio Canvas</span>
          </div>
          <div className="flex items-center gap-4">
             <label className="cursor-pointer">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <div className="flex items-center gap-2 px-6 py-2.5 bg-indigo-500 hover:bg-indigo-400 rounded-full text-xs font-black transition shadow-lg shadow-indigo-500/20">
                <Upload className="w-4 h-4" />
                <span>上傳照片</span>
              </div>
            </label>
          </div>
        </header>

        <div className="flex-1 overflow-auto p-4 lg:p-12 flex items-center justify-center relative bg-[#0D1117]">
          {images.length === 0 ? (
            <div className="text-center space-y-4 max-w-sm">
              <div className="w-16 h-16 bg-[#161B22] rounded-2xl flex items-center justify-center mx-auto border border-slate-700">
                <ImageIcon className="w-6 h-6 text-slate-600" />
              </div>
              <h3 className="text-md font-black text-white uppercase tracking-widest">Start Stitching</h3>
              <p className="text-slate-500 text-xs px-10">上傳多張 JPG，點擊切換漫畫格風格，直接拖動圖片調整構圖。</p>
            </div>
          ) : (
            <div className="relative group max-h-full">
              <div className="shadow-[0_60px_120px_-20px_rgba(0,0,0,0.8)] rounded-sm overflow-hidden border border-white/5">
                <canvas 
                  ref={canvasRef} 
                  onMouseDown={handleCanvasMouseDown}
                  onMouseMove={handleCanvasMouseMove}
                  onMouseUp={handleCanvasMouseUp}
                  onMouseLeave={handleCanvasMouseUp}
                  onTouchStart={handleCanvasMouseDown}
                  onTouchMove={handleCanvasMouseMove}
                  onTouchEnd={handleCanvasMouseUp}
                  style={{ cursor: isDragging ? 'grabbing' : 'grab' }}
                  className="max-w-full max-h-[78vh] object-contain mx-auto select-none touch-none bg-black"
                />
              </div>
              <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                <button onClick={() => { setImages([]); setSelectedId(null); }} className="p-3 bg-red-500/90 hover:bg-red-500 text-white rounded-xl shadow-2xl transition backdrop-blur-md">
                  <Trash2 className="w-5 h-5" />
                </button>
              </div>
            </div>
          )}
        </div>

        {images.length > 0 && (
          <div className="h-28 bg-[#161B22]/95 backdrop-blur-xl border-t border-slate-800 p-4 flex gap-4 overflow-x-auto items-center scrollbar-hide">
            {images.map((img) => (
              <div key={img.id} className="relative flex-shrink-0 group">
                <button
                  onClick={() => setSelectedId(img.id)}
                  className={`relative block h-16 w-16 overflow-hidden rounded-xl border-2 transition-all duration-300 ${
                    selectedId === img.id ? 'border-indigo-500 scale-110' : 'border-slate-800 hover:border-slate-600'
                  }`}
                >
                  <img src={img.preview} alt="Thumb" className="h-full w-full object-cover" />
                </button>
                <button onClick={(e) => { e.stopPropagation(); removeImage(img.id); }} className="absolute -top-1.5 -right-1.5 p-1 bg-red-500 rounded-full text-white transition opacity-0 group-hover:opacity-100 scale-75">
                  <X className="w-3 h-3" />
                </button>
              </div>
            ))}
            <label className="flex-shrink-0 h-16 w-16 flex items-center justify-center border-2 border-dashed border-slate-800 rounded-xl hover:border-indigo-500 hover:bg-indigo-500/5 cursor-pointer transition">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <Upload className="w-4 h-4 text-slate-600" />
            </label>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

