{
  "name": "Smart Collage Studio",
  "description": "A high-performance image stitching web app using procedural geometry to organize multiple JPGs into optimized grids. Features dynamic slanted comic frames and precise layout controls without AI overhead.",
  "requestFramePermissions": []
}

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { 
  Upload, 
  Download, 
  Trash2, 
  LayoutGrid, 
  Settings2, 
  X,
  Move,
  Square,
  Zap,
  Columns2,
  Image as ImageIcon,
  RotateCcw
} from 'lucide-react';
import { ImageFile, CollageSettings, ImageTransform } from './types';
import { loadImage, calculateBestGrid, getDimensions } from './utils/image';

const COMIC_WORDS = ['BOOM!', 'OMG!!', 'SALE', 'WOW!', 'ZAP!', 'POW!', 'BIG CHANCE!'];
const STICKER_COLORS = ['#fde047', '#ef4444', '#3b82f6', '#ffffff'];

const PRESETS = {
  POLAROID: {
    backgroundColor: '#ffffff',
    gap: 25,
    padding: 60,
    borderRadius: 8,
    borderWidth: 0,
    targetRatio: '1:1' as const,
    style: 'standard' as const
  },
  VINTAGE_90S: {
    backgroundColor: '#f4f1ea',
    gap: 40,
    padding: 50,
    borderRadius: 24,
    borderWidth: 0,
    targetRatio: '4:5' as const,
    style: 'standard' as const
  },
  COMIC: {
    backgroundColor: '#000000',
    gap: 12,
    padding: 30,
    borderRadius: 0,
    borderWidth: 10,
    borderColor: '#000000',
    targetRatio: 'auto' as const,
    style: 'comic' as const
  },
  FOUR_PANEL: {
    backgroundColor: '#ffffff',
    gap: 8,
    padding: 20,
    borderRadius: 0,
    borderWidth: 3,
    borderColor: '#000000',
    columns: 1,
    targetRatio: 'auto' as const,
    style: 'standard' as const
  }
};

const App: React.FC = () => {
  const [images, setImages] = useState<ImageFile[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [settings, setSettings] = useState<CollageSettings>({
    columns: 2,
    rows: 3,
    gap: 20,
    padding: 40,
    backgroundColor: '#ffffff',
    targetRatio: '5:4',
    quality: 0.9,
    borderRadius: 0,
    borderWidth: 0,
    borderColor: '#ffffff',
    style: 'standard'
  });
  const [isDragging, setIsDragging] = useState(false);
  const [stickerSeed, setStickerSeed] = useState(Date.now());

  const selectedImage = images.find(img => img.id === selectedId);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const dragStartRef = useRef<{ x: number, y: number, initialX: number, initialY: number } | null>(null);

  const applyPreset = (preset: any) => {
    setSettings(prev => {
      const newSettings = { ...prev, ...preset };
      if (preset.columns) {
        newSettings.rows = Math.ceil(images.length / preset.columns);
      } else if (images.length > 0) {
        const avgRatio = images.reduce((sum, img) => sum + img.aspectRatio, 0) / images.length;
        const { cols, rows } = calculateBestGrid(images.length, avgRatio, newSettings.targetRatio);
        newSettings.columns = cols;
        newSettings.rows = rows;
      }
      return newSettings;
    });
    setStickerSeed(Date.now());
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    if (files.length === 0) return;

    const newImages: ImageFile[] = [];
    for (const file of files) {
      const url = URL.createObjectURL(file);
      try {
        const img = await loadImage(url);
        newImages.push({
          id: Math.random().toString(36).substr(2, 9),
          file, 
          preview: url, 
          width: img.width, 
          height: img.height, 
          aspectRatio: img.width / img.height,
          transform: { scale: 1, translateX: 0, translateY: 0 }
        });
      } catch (err) {
        console.error("Failed to load image", err);
      }
    }

    setImages(prev => {
      const updated = [...prev, ...newImages];
      if (updated.length > 0) {
        const avgRatio = updated.reduce((sum, img) => sum + img.aspectRatio, 0) / updated.length;
        const { cols, rows } = calculateBestGrid(updated.length, avgRatio, settings.targetRatio);
        setSettings(s => ({ ...s, columns: cols, rows }));
      }
      return updated;
    });
  };

  const updateImageTransform = (id: string, updates: Partial<ImageTransform>) => {
    setImages(prev => prev.map(img => 
      img.id === id ? { ...img, transform: { ...img.transform, ...updates } } : img
    ));
  };

  const resetTransform = (id: string) => {
    updateImageTransform(id, { scale: 1, translateX: 0, translateY: 0 });
  };

  const removeImage = (id: string) => {
    if (selectedId === id) setSelectedId(null);
    setImages(prev => prev.filter(img => img.id !== id));
  };

  const drawComicBurst = (ctx: CanvasRenderingContext2D, x: number, y: number, radius: number, text: string, color: string) => {
    ctx.save();
    ctx.translate(x, y);
    ctx.rotate((Math.random() - 0.5) * 0.4);

    ctx.beginPath();
    const spikes = 14 + Math.floor(Math.random() * 6);
    for (let i = 0; i < spikes * 2; i++) {
      const r = i % 2 === 0 ? radius : radius * 0.65;
      const angle = (i * Math.PI) / spikes;
      ctx.lineTo(Math.cos(angle) * r, Math.sin(angle) * r);
    }
    ctx.closePath();
    ctx.fillStyle = color;
    ctx.fill();
    ctx.strokeStyle = 'black';
    ctx.lineWidth = radius * 0.1;
    ctx.stroke();

    ctx.font = `italic black ${radius * 0.45}px Impact, Arial Black, sans-serif`;
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.strokeStyle = 'white';
    ctx.lineWidth = radius * 0.05;
    ctx.strokeText(text, 0, 0);
    ctx.fillStyle = 'black';
    ctx.fillText(text, 0, 0);

    ctx.restore();
  };

  const drawHalftone = (ctx: CanvasRenderingContext2D, w: number, h: number) => {
    ctx.save();
    ctx.globalAlpha = 0.15;
    ctx.fillStyle = '#000000';
    const dotSize = 2;
    const spacing = 8;
    for (let x = 0; x < w; x += spacing) {
      for (let y = 0; y < h; y += spacing) {
        ctx.beginPath();
        ctx.arc(x, y, dotSize, 0, Math.PI * 2);
        ctx.fill();
      }
    }
    ctx.restore();
  };

  const drawCollage = useCallback(async () => {
    if (!canvasRef.current || images.length === 0) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dims = getDimensions(images, settings);
    canvas.width = dims.totalWidth;
    canvas.height = dims.totalHeight;

    ctx.fillStyle = settings.backgroundColor;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    const jitter = settings.style === 'comic' ? Math.min(dims.cellWidth, dims.cellHeight) * 0.15 : 0;
    const points: {x: number, y: number}[][] = [];

    const rng = (i: number) => {
      const x = Math.sin(stickerSeed + i) * 10000;
      return x - Math.floor(x);
    };

    for (let r = 0; r <= settings.rows; r++) {
      points[r] = [];
      for (let c = 0; c <= settings.columns; c++) {
        let px = settings.padding + c * (dims.cellWidth + settings.gap);
        let py = settings.padding + r * (dims.cellHeight + settings.gap);

        if (c > 0 && c < settings.columns) px += (rng(r * 10 + c) - 0.5) * jitter;
        if (r > 0 && r < settings.rows) py += (rng(c * 10 + r + 100) - 0.5) * jitter;

        points[r][c] = { x: px, y: py };
      }
    }

    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);
      const imgObj = images[i];

      const p1 = points[row][col];
      const p2 = points[row][col+1];
      const p3 = points[row+1][col+1];
      const p4 = points[row+1][col];

      try {
        const img = await loadImage(imgObj.preview);
        ctx.save();

        ctx.beginPath();
        if (settings.style === 'comic') {
          const g = settings.gap / 2;
          ctx.moveTo(p1.x + g, p1.y + g);
          ctx.lineTo(p2.x - g, p2.y + g);
          ctx.lineTo(p3.x - g, p3.y - g);
          ctx.lineTo(p4.x + g, p4.y - g);
        } else if (settings.borderRadius > 0 && (ctx as any).roundRect) {
          const rx = settings.padding + (col * (dims.cellWidth + settings.gap));
          const ry = settings.padding + (row * (dims.cellHeight + settings.gap));
          (ctx as any).roundRect(rx, ry, dims.cellWidth, dims.cellHeight, settings.borderRadius);
        } else {
          const rx = settings.padding + (col * (dims.cellWidth + settings.gap));
          const ry = settings.padding + (row * (dims.cellHeight + settings.gap));
          ctx.rect(rx, ry, dims.cellWidth, dims.cellHeight);
        }
        ctx.clip();

        const cellCenterX = (p1.x + p2.x + p3.x + p4.x) / 4;
        const cellCenterY = (p1.y + p2.y + p3.y + p4.y) / 4;

        const cellAspect = dims.cellWidth / dims.cellHeight;
        const imgAspect = img.width / img.height;
        let baseScale = imgAspect > cellAspect ? dims.cellHeight / img.height : dims.cellWidth / img.width;
        const finalScale = baseScale * imgObj.transform.scale;

        const drawWidth = img.width * finalScale;
        const drawHeight = img.height * finalScale;

        ctx.drawImage(
          img, 
          cellCenterX - drawWidth/2 + imgObj.transform.translateX, 
          cellCenterY - drawHeight/2 + imgObj.transform.translateY, 
          drawWidth, 
          drawHeight
        );

        if (settings.style === 'comic') {
          drawHalftone(ctx, dims.totalWidth, dims.totalHeight);
        }

        if (selectedId === imgObj.id) {
          ctx.restore();
          ctx.save();
          ctx.strokeStyle = '#6366f1';
          ctx.lineWidth = 12;
          ctx.setLineDash([20, 10]);
          ctx.beginPath();
          ctx.moveTo(p1.x, p1.y); ctx.lineTo(p2.x, p2.y); ctx.lineTo(p3.x, p3.y); ctx.lineTo(p4.x, p4.y);
          ctx.closePath();
          ctx.stroke();
        }

        ctx.restore();

        if (settings.borderWidth > 0) {
          ctx.strokeStyle = settings.borderColor;
          ctx.lineWidth = settings.borderWidth;
          ctx.lineJoin = 'miter';
          ctx.beginPath();
          ctx.moveTo(p1.x, p1.y); ctx.lineTo(p2.x, p2.y); ctx.lineTo(p3.x, p3.y); ctx.lineTo(p4.x, p4.y);
          ctx.closePath();
          ctx.stroke();
        }
      } catch (err) {
        console.error("Failed image draw", i, err);
      }
    }

    if (settings.style === 'comic' && images.length > 0) {
      const numStickers = 2 + Math.floor(rng(77) * 3);
      for (let s = 0; s < numStickers; s++) {
        const sx = settings.padding + rng(s + 500) * (dims.totalWidth - settings.padding * 2);
        const sy = settings.padding + rng(s + 1000) * (dims.totalHeight - settings.padding * 2);
        const word = COMIC_WORDS[Math.floor(rng(s + 2000) * COMIC_WORDS.length)];
        const color = STICKER_COLORS[Math.floor(rng(s + 3000) * STICKER_COLORS.length)];
        const size = 120 + rng(s + 4000) * 80;
        drawComicBurst(ctx, sx, sy, size, word, color);
      }
    }
  }, [images, settings, selectedId, stickerSeed]);

  useEffect(() => {
    drawCollage();
  }, [drawCollage]);

  const handleCanvasMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!canvasRef.current || images.length === 0) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;

    const scaleX = canvasRef.current.width / rect.width;
    const scaleY = canvasRef.current.height / rect.height;
    const x = (clientX - rect.left) * scaleX;
    const y = (clientY - rect.top) * scaleY;

    const dims = getDimensions(images, settings);
    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);
      const rx = settings.padding + (col * (dims.cellWidth + settings.gap));
      const ry = settings.padding + (row * (dims.cellHeight + settings.gap));

      if (x >= rx && x <= rx + dims.cellWidth && y >= ry && y <= ry + dims.cellHeight) {
        setSelectedId(images[i].id);
        setIsDragging(true);
        dragStartRef.current = { x, y, initialX: images[i].transform.translateX, initialY: images[i].transform.translateY };
        break;
      }
    }
  };

  const handleCanvasMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDragging || !dragStartRef.current || !selectedId) return;
    const rect = canvasRef.current!.getBoundingClientRect();
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;

    const scaleX = canvasRef.current!.width / rect.width;
    const scaleY = canvasRef.current!.height / rect.height;
    const x = (clientX - rect.left) * scaleX;
    const y = (clientY - rect.top) * scaleY;

    updateImageTransform(selectedId, {
      translateX: dragStartRef.current.initialX + (x - dragStartRef.current.x),
      translateY: dragStartRef.current.initialY + (y - dragStartRef.current.y)
    });
  };

  const handleCanvasMouseUp = () => {
    setIsDragging(false);
    dragStartRef.current = null;
  };

  const downloadCollage = () => {
    if (!canvasRef.current) return;
    const link = document.createElement('a');
    link.download = `stitch-procedural-${Date.now()}.jpg`;
    link.href = canvasRef.current.toDataURL('image/jpeg', settings.quality);
    link.click();
  };

  return (
    <div className="min-h-screen flex flex-col lg:flex-row bg-[#0B0E14] text-slate-100 selection:bg-indigo-500/30">
      <aside className="w-full lg:w-80 bg-[#161B22] border-r border-slate-800 overflow-y-auto p-5 space-y-6 sticky top-0 h-screen hidden lg:block scrollbar-hide">
        <div className="flex items-center gap-3 mb-6">
          <div className="p-2 bg-indigo-500 rounded-xl shadow-lg shadow-indigo-500/20">
            <LayoutGrid className="w-5 h-5 text-white" />
          </div>
          <h1 className="text-lg font-black tracking-tighter uppercase text-white">Stitcher</h1>
        </div>

        <section className="space-y-3">
          <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-slate-500 flex items-center gap-2">
            <Zap className="w-3 h-3 text-amber-400 fill-amber-400" /> 風格預設 Presets
          </h2>
          <div className="grid grid-cols-1 gap-2">
            <button onClick={() => applyPreset(PRESETS.COMIC)} className={`flex items-center justify-between px-3 py-2.5 bg-slate-800/50 border rounded-xl transition group text-xs font-bold ${settings.style === 'comic' ? 'border-indigo-500 bg-slate-800' : 'border-slate-700 hover:border-slate-500'}`}>
              <div className="flex items-center gap-2">
                <Zap className="w-4 h-4 text-amber-400" />
                <span>美式漫畫格</span>
              </div>
            </button>
            <button onClick={() => applyPreset(PRESETS.POLAROID)} className="flex items-center justify-between px-3 py-2.5 bg-slate-800/50 border border-slate-700 rounded-xl hover:border-indigo-500 transition group text-xs font-medium">
              <div className="flex items-center gap-2">
                <Square className="w-4 h-4 text-slate-400" />
                <span>正方形拍立得</span>
              </div>
            </button>
            <button onClick={() => applyPreset(PRESETS.VINTAGE_90S)} className="flex items-center justify-between px-3 py-2.5 bg-slate-800/50 border border-slate-700 rounded-xl hover:border-indigo-500 transition group text-xs font-medium">
              <div className="flex items-center gap-2">
                <ImageIcon className="w-4 h-4 text-slate-400" />
                <span>90s 拼貼感</span>
              </div>
            </button>
            <button onClick={() => applyPreset(PRESETS.FOUR_PANEL)} className="flex items-center justify-between px-3 py-2.5 bg-slate-800/50 border border-slate-700 rounded-xl hover:border-indigo-500 transition group text-xs font-medium">
              <div className="flex items-center gap-2">
                <Columns2 className="w-4 h-4 text-slate-400" />
                <span>直條四格</span>
              </div>
            </button>
          </div>
        </section>

        <section className="space-y-4 pt-2">
          <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-slate-500 flex items-center gap-2">
            <Settings2 className="w-3 h-3" /> 版面 Layout
          </h2>

          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-1">
              <label className="text-[10px] text-slate-500 uppercase font-bold">Cols 欄</label>
              <input type="number" value={settings.columns} onChange={e => setSettings(s => ({ ...s, columns: Math.max(1, parseInt(e.target.value) || 1) }))} className="w-full bg-[#0D1117] border border-slate-700 rounded-lg p-2 text-sm outline-none" />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] text-slate-500 uppercase font-bold">Rows 列</label>
              <input type="number" value={settings.rows} onChange={e => setSettings(s => ({ ...s, rows: Math.max(1, parseInt(e.target.value) || 1) }))} className="w-full bg-[#0D1117] border border-slate-700 rounded-lg p-2 text-sm outline-none" />
            </div>
          </div>

          <div className="space-y-3">
            <div>
              <div className="flex justify-between items-center mb-1">
                <label className="text-[10px] text-slate-500 uppercase font-bold">Gap 間距</label>
                <span className="text-[10px] font-mono text-indigo-400">{settings.gap}px</span>
              </div>
              <input type="range" min="0" max="100" value={settings.gap} onChange={e => setSettings(s => ({ ...s, gap: parseInt(e.target.value) }))} className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500" />
            </div>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] text-slate-500 uppercase font-bold">BG Color 背景色</label>
            <div className="flex gap-2 p-1.5 bg-[#0D1117] border border-slate-700 rounded-lg">
              <input type="color" value={settings.backgroundColor} onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))} className="w-8 h-8 bg-transparent border-none cursor-pointer rounded-md overflow-hidden" />
              <input type="text" value={settings.backgroundColor.toUpperCase()} onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))} className="flex-1 bg-transparent border-none text-xs font-mono focus:outline-none uppercase" />
            </div>
          </div>
        </section>

        {selectedImage && (
          <section className="p-4 bg-indigo-500/5 rounded-2xl border border-indigo-500/20 space-y-4 animate-in slide-in-from-right-4">
            <div className="flex items-center justify-between">
              <h2 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest flex items-center gap-2">
                <Move className="w-3 h-3" /> 圖層 Layer
              </h2>
              <button onClick={() => setSelectedId(null)} className="text-slate-500 hover:text-white"><X className="w-4 h-4" /></button>
            </div>
            <div className="space-y-3">
              <label className="text-[10px] text-slate-500 uppercase font-bold block">Scale 縮放</label>
              <input type="range" min="0.5" max="4" step="0.01" value={selectedImage.transform.scale} onChange={e => updateImageTransform(selectedImage.id, { scale: parseFloat(e.target.value) })} className="w-full h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-indigo-400" />
              <button onClick={() => resetTransform(selectedImage.id)} className="w-full py-2 bg-slate-800 hover:bg-slate-700 text-[10px] uppercase font-black text-slate-300 transition rounded-lg">Reset Position</button>
            </div>
          </section>
        )}

        {settings.style === 'comic' && (
          <button onClick={() => setStickerSeed(Date.now())} className="w-full py-3 bg-amber-500/10 hover:bg-amber-500/20 text-amber-500 text-[10px] uppercase font-bold rounded-xl border border-amber-500/20 transition flex items-center justify-center gap-2">
            <RotateCcw className="w-3 h-3" /> 重隨隨機裝飾
          </button>
        )}

        <div className="pt-6 border-t border-slate-800">
          <button onClick={downloadCollage} disabled={images.length === 0} className="w-full flex items-center justify-center gap-2 py-4 px-4 rounded-2xl bg-indigo-500 hover:bg-indigo-400 disabled:opacity-30 disabled:cursor-not-allowed font-black text-white transition shadow-xl shadow-indigo-500/20 uppercase tracking-widest text-sm">
            <Download className="w-5 h-5" /> Export
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col h-screen overflow-hidden bg-[#0D1117]">
        <header className="px-6 py-4 bg-[#161B22] border-b border-slate-800 flex justify-between items-center z-10">
          <div className="flex items-center gap-3">
            <LayoutGrid className="w-5 h-5 text-indigo-500 lg:hidden" />
            <span className="font-black tracking-tighter text-sm uppercase">Studio Canvas</span>
          </div>
          <div className="flex items-center gap-4">
             <label className="cursor-pointer">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <div className="flex items-center gap-2 px-6 py-2.5 bg-indigo-500 hover:bg-indigo-400 rounded-full text-xs font-black transition shadow-lg shadow-indigo-500/20">
                <Upload className="w-4 h-4" />
                <span>上傳照片</span>
              </div>
            </label>
          </div>
        </header>

        <div className="flex-1 overflow-auto p-4 lg:p-12 flex items-center justify-center relative bg-[#0D1117]">
          {images.length === 0 ? (
            <div className="text-center space-y-4 max-w-sm">
              <div className="w-16 h-16 bg-[#161B22] rounded-2xl flex items-center justify-center mx-auto border border-slate-700">
                <ImageIcon className="w-6 h-6 text-slate-600" />
              </div>
              <h3 className="text-md font-black text-white uppercase tracking-widest">Start Stitching</h3>
              <p className="text-slate-500 text-xs px-10">上傳多張 JPG，點擊切換漫畫格風格，直接拖動圖片調整構圖。</p>
            </div>
          ) : (
            <div className="relative group max-h-full">
              <div className="shadow-[0_60px_120px_-20px_rgba(0,0,0,0.8)] rounded-sm overflow-hidden border border-white/5">
                <canvas 
                  ref={canvasRef} 
                  onMouseDown={handleCanvasMouseDown}
                  onMouseMove={handleCanvasMouseMove}
                  onMouseUp={handleCanvasMouseUp}
                  onMouseLeave={handleCanvasMouseUp}
                  onTouchStart={handleCanvasMouseDown}
                  onTouchMove={handleCanvasMouseMove}
                  onTouchEnd={handleCanvasMouseUp}
                  style={{ cursor: isDragging ? 'grabbing' : 'grab' }}
                  className="max-w-full max-h-[78vh] object-contain mx-auto select-none touch-none bg-black"
                />
              </div>
              <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                <button onClick={() => { setImages([]); setSelectedId(null); }} className="p-3 bg-red-500/90 hover:bg-red-500 text-white rounded-xl shadow-2xl transition backdrop-blur-md">
                  <Trash2 className="w-5 h-5" />
                </button>
              </div>
            </div>
          )}
        </div>

        {images.length > 0 && (
          <div className="h-28 bg-[#161B22]/95 backdrop-blur-xl border-t border-slate-800 p-4 flex gap-4 overflow-x-auto items-center scrollbar-hide">
            {images.map((img) => (
              <div key={img.id} className="relative flex-shrink-0 group">
                <button
                  onClick={() => setSelectedId(img.id)}
                  className={`relative block h-16 w-16 overflow-hidden rounded-xl border-2 transition-all duration-300 ${
                    selectedId === img.id ? 'border-indigo-500 scale-110' : 'border-slate-800 hover:border-slate-600'
                  }`}
                >
                  <img src={img.preview} alt="Thumb" className="h-full w-full object-cover" />
                </button>
                <button onClick={(e) => { e.stopPropagation(); removeImage(img.id); }} className="absolute -top-1.5 -right-1.5 p-1 bg-red-500 rounded-full text-white transition opacity-0 group-hover:opacity-100 scale-75">
                  <X className="w-3 h-3" />
                </button>
              </div>
            ))}
            <label className="flex-shrink-0 h-16 w-16 flex items-center justify-center border-2 border-dashed border-slate-800 rounded-xl hover:border-indigo-500 hover:bg-indigo-500/5 cursor-pointer transition">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <Upload className="w-4 h-4 text-slate-600" />
            </label>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { 
  Upload, 
  Download, 
  Trash2, 
  LayoutGrid, 
  Settings2, 
  X,
  Move,
  Square,
  Zap,
  Columns2,
  Image as ImageIcon,
  RotateCcw
} from 'lucide-react';
import { ImageFile, CollageSettings, ImageTransform } from './types';
import { loadImage, calculateBestGrid, getDimensions } from './utils/image';

const COMIC_WORDS = ['BOOM!', 'OMG!!', 'SALE', 'WOW!', 'ZAP!', 'POW!', 'BIG CHANCE!'];
const STICKER_COLORS = ['#fde047', '#ef4444', '#3b82f6', '#ffffff'];

const PRESETS = {
  POLAROID: {
    backgroundColor: '#ffffff',
    gap: 25,
    padding: 60,
    borderRadius: 8,
    borderWidth: 0,
    targetRatio: '1:1' as const,
    style: 'standard' as const
  },
  VINTAGE_90S: {
    backgroundColor: '#f4f1ea',
    gap: 40,
    padding: 50,
    borderRadius: 24,
    borderWidth: 0,
    targetRatio: '4:5' as const,
    style: 'standard' as const
  },
  COMIC: {
    backgroundColor: '#000000',
    gap: 12,
    padding: 30,
    borderRadius: 0,
    borderWidth: 10,
    borderColor: '#000000',
    targetRatio: 'auto' as const,
    style: 'comic' as const
  },
  FOUR_PANEL: {
    backgroundColor: '#ffffff',
    gap: 8,
    padding: 20,
    borderRadius: 0,
    borderWidth: 3,
    borderColor: '#000000',
    columns: 1,
    targetRatio: 'auto' as const,
    style: 'standard' as const
  }
};

const App: React.FC = () => {
  const [images, setImages] = useState<ImageFile[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [settings, setSettings] = useState<CollageSettings>({
    columns: 2,
    rows: 3,
    gap: 20,
    padding: 40,
    backgroundColor: '#ffffff',
    targetRatio: '5:4',
    quality: 0.9,
    borderRadius: 0,
    borderWidth: 0,
    borderColor: '#ffffff',
    style: 'standard'
  });
  const [isDragging, setIsDragging] = useState(false);
  const [stickerSeed, setStickerSeed] = useState(Date.now());

  const selectedImage = images.find(img => img.id === selectedId);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const dragStartRef = useRef<{ x: number, y: number, initialX: number, initialY: number } | null>(null);

  const applyPreset = (preset: any) => {
    setSettings(prev => {
      const newSettings = { ...prev, ...preset };
      if (preset.columns) {
        newSettings.rows = Math.ceil(images.length / preset.columns);
      } else if (images.length > 0) {
        const avgRatio = images.reduce((sum, img) => sum + img.aspectRatio, 0) / images.length;
        const { cols, rows } = calculateBestGrid(images.length, avgRatio, newSettings.targetRatio);
        newSettings.columns = cols;
        newSettings.rows = rows;
      }
      return newSettings;
    });
    setStickerSeed(Date.now());
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    if (files.length === 0) return;

    const newImages: ImageFile[] = [];
    for (const file of files) {
      const url = URL.createObjectURL(file);
      try {
        const img = await loadImage(url);
        newImages.push({
          id: Math.random().toString(36).substr(2, 9),
          file, 
          preview: url, 
          width: img.width, 
          height: img.height, 
          aspectRatio: img.width / img.height,
          transform: { scale: 1, translateX: 0, translateY: 0 }
        });
      } catch (err) {
        console.error("Failed to load image", err);
      }
    }

    setImages(prev => {
      const updated = [...prev, ...newImages];
      if (updated.length > 0) {
        const avgRatio = updated.reduce((sum, img) => sum + img.aspectRatio, 0) / updated.length;
        const { cols, rows } = calculateBestGrid(updated.length, avgRatio, settings.targetRatio);
        setSettings(s => ({ ...s, columns: cols, rows }));
      }
      return updated;
    });
  };

  const updateImageTransform = (id: string, updates: Partial<ImageTransform>) => {
    setImages(prev => prev.map(img => 
      img.id === id ? { ...img, transform: { ...img.transform, ...updates } } : img
    ));
  };

  const resetTransform = (id: string) => {
    updateImageTransform(id, { scale: 1, translateX: 0, translateY: 0 });
  };

  const removeImage = (id: string) => {
    if (selectedId === id) setSelectedId(null);
    setImages(prev => prev.filter(img => img.id !== id));
  };

  // Line-line intersection helper
  const intersect = (x1: number, y1: number, x2: number, y2: number, x3: number, y3: number, x4: number, y4: number) => {
    const denom = (y4 - y3) * (x2 - x1) - (x4 - x3) * (y2 - y1);
    if (denom === 0) return { x: (x1 + x2 + x3 + x4) / 4, y: (y1 + y2 + y3 + y4) / 4 };
    const ua = ((x4 - x3) * (y1 - y3) - (y4 - y3) * (x1 - x3)) / denom;
    return {
      x: x1 + ua * (x2 - x1),
      y: y1 + ua * (y2 - y1)
    };
  };

  const drawComicBurst = (ctx: CanvasRenderingContext2D, x: number, y: number, radius: number, text: string, color: string) => {
    ctx.save();
    ctx.translate(x, y);
    ctx.rotate((Math.random() - 0.5) * 0.4);

    ctx.beginPath();
    const spikes = 14 + Math.floor(Math.random() * 6);
    for (let i = 0; i < spikes * 2; i++) {
      const r = i % 2 === 0 ? radius : radius * 0.65;
      const angle = (i * Math.PI) / spikes;
      ctx.lineTo(Math.cos(angle) * r, Math.sin(angle) * r);
    }
    ctx.closePath();
    ctx.fillStyle = color;
    ctx.fill();
    ctx.strokeStyle = 'black';
    ctx.lineWidth = radius * 0.1;
    ctx.stroke();

    ctx.font = `italic black ${radius * 0.45}px Impact, Arial Black, sans-serif`;
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.strokeStyle = 'white';
    ctx.lineWidth = radius * 0.05;
    ctx.strokeText(text, 0, 0);
    ctx.fillStyle = 'black';
    ctx.fillText(text, 0, 0);

    ctx.restore();
  };

  const drawHalftone = (ctx: CanvasRenderingContext2D, w: number, h: number) => {
    ctx.save();
    ctx.globalAlpha = 0.15;
    ctx.fillStyle = '#000000';
    const dotSize = 2;
    const spacing = 8;
    for (let x = 0; x < w; x += spacing) {
      for (let y = 0; y < h; y += spacing) {
        ctx.beginPath();
        ctx.arc(x, y, dotSize, 0, Math.PI * 2);
        ctx.fill();
      }
    }
    ctx.restore();
  };

  const drawCollage = useCallback(async () => {
    if (!canvasRef.current || images.length === 0) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dims = getDimensions(images, settings);
    canvas.width = dims.totalWidth;
    canvas.height = dims.totalHeight;

    ctx.fillStyle = settings.backgroundColor;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    const jitterFactor = settings.style === 'comic' ? 0.35 : 0; // Much larger angles
    const points: {x: number, y: number}[][] = [];

    const rng = (i: number) => {
      const x = Math.sin(stickerSeed + i) * 10000;
      return x - Math.floor(x);
    };

    // 1. Define splitters that span the entire canvas
    const verticalSplitters = [];
    for (let c = 0; c <= settings.columns; c++) {
      const basePx = settings.padding + c * (dims.cellWidth + settings.gap);
      if (c === 0 || c === settings.columns) {
        verticalSplitters[c] = { top: { x: basePx, y: 0 }, bottom: { x: basePx, y: dims.totalHeight } };
      } else {
        const offsetT = (rng(c * 7) - 0.5) * dims.cellWidth * jitterFactor;
        const offsetB = (rng(c * 13 + 100) - 0.5) * dims.cellWidth * jitterFactor;
        verticalSplitters[c] = { 
          top: { x: basePx + offsetT, y: 0 }, 
          bottom: { x: basePx + offsetB, y: dims.totalHeight } 
        };
      }
    }

    const horizontalSplitters = [];
    for (let r = 0; r <= settings.rows; r++) {
      const basePy = settings.padding + r * (dims.cellHeight + settings.gap);
      if (r === 0 || r === settings.rows) {
        horizontalSplitters[r] = { left: { x: 0, y: basePy }, right: { x: dims.totalWidth, y: basePy } };
      } else {
        const offsetL = (rng(r * 19 + 200) - 0.5) * dims.cellHeight * jitterFactor;
        const offsetR = (rng(r * 23 + 300) - 0.5) * dims.cellHeight * jitterFactor;
        horizontalSplitters[r] = { 
          left: { x: 0, y: basePy + offsetL }, 
          right: { x: dims.totalWidth, y: basePy + offsetR } 
        };
      }
    }

    // 2. Calculate intersections for grid vertices
    for (let r = 0; r <= settings.rows; r++) {
      points[r] = [];
      for (let c = 0; c <= settings.columns; c++) {
        const v = verticalSplitters[c];
        const h = horizontalSplitters[r];
        points[r][c] = intersect(v.top.x, v.top.y, v.bottom.x, v.bottom.y, h.left.x, h.left.y, h.right.x, h.right.y);
      }
    }

    // 3. Draw each panel
    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);
      const imgObj = images[i];

      const p1 = points[row][col];
      const p2 = points[row][col+1];
      const p3 = points[row+1][col+1];
      const p4 = points[row+1][col];

      try {
        const img = await loadImage(imgObj.preview);
        ctx.save();

        ctx.beginPath();
        if (settings.style === 'comic') {
          const g = settings.gap / 2;
          // Apply a bit of inset for the gap visually
          ctx.moveTo(p1.x + g, p1.y + g);
          ctx.lineTo(p2.x - g, p2.y + g);
          ctx.lineTo(p3.x - g, p3.y - g);
          ctx.lineTo(p4.x + g, p4.y - g);
        } else if (settings.borderRadius > 0 && (ctx as any).roundRect) {
          const rx = settings.padding + (col * (dims.cellWidth + settings.gap));
          const ry = settings.padding + (row * (dims.cellHeight + settings.gap));
          (ctx as any).roundRect(rx, ry, dims.cellWidth, dims.cellHeight, settings.borderRadius);
        } else {
          const rx = settings.padding + (col * (dims.cellWidth + settings.gap));
          const ry = settings.padding + (row * (dims.cellHeight + settings.gap));
          ctx.rect(rx, ry, dims.cellWidth, dims.cellHeight);
        }
        ctx.clip();

        const cellCenterX = (p1.x + p2.x + p3.x + p4.x) / 4;
        const cellCenterY = (p1.y + p2.y + p3.y + p4.y) / 4;

        const cellAspect = dims.cellWidth / dims.cellHeight;
        const imgAspect = img.width / img.height;
        let baseScale = imgAspect > cellAspect ? dims.cellHeight / img.height : dims.cellWidth / img.width;
        const finalScale = baseScale * imgObj.transform.scale;

        const drawWidth = img.width * finalScale;
        const drawHeight = img.height * finalScale;

        ctx.drawImage(
          img, 
          cellCenterX - drawWidth/2 + imgObj.transform.translateX, 
          cellCenterY - drawHeight/2 + imgObj.transform.translateY, 
          drawWidth, 
          drawHeight
        );

        if (settings.style === 'comic') {
          drawHalftone(ctx, dims.totalWidth, dims.totalHeight);
        }

        if (selectedId === imgObj.id) {
          ctx.restore();
          ctx.save();
          ctx.strokeStyle = '#6366f1';
          ctx.lineWidth = 12;
          ctx.setLineDash([20, 10]);
          ctx.beginPath();
          ctx.moveTo(p1.x, p1.y); ctx.lineTo(p2.x, p2.y); ctx.lineTo(p3.x, p3.y); ctx.lineTo(p4.x, p4.y);
          ctx.closePath();
          ctx.stroke();
        }

        ctx.restore();

        if (settings.borderWidth > 0) {
          ctx.strokeStyle = settings.borderColor;
          ctx.lineWidth = settings.borderWidth;
          ctx.lineJoin = 'miter';
          ctx.beginPath();
          ctx.moveTo(p1.x, p1.y); ctx.lineTo(p2.x, p2.y); ctx.lineTo(p3.x, p3.y); ctx.lineTo(p4.x, p4.y);
          ctx.closePath();
          ctx.stroke();
        }
      } catch (err) {
        console.error("Failed image draw", i, err);
      }
    }

    if (settings.style === 'comic' && images.length > 0) {
      const numStickers = 2 + Math.floor(rng(77) * 3);
      for (let s = 0; s < numStickers; s++) {
        const sx = settings.padding + rng(s + 500) * (dims.totalWidth - settings.padding * 2);
        const sy = settings.padding + rng(s + 1000) * (dims.totalHeight - settings.padding * 2);
        const word = COMIC_WORDS[Math.floor(rng(s + 2000) * COMIC_WORDS.length)];
        const color = STICKER_COLORS[Math.floor(rng(s + 3000) * STICKER_COLORS.length)];
        const size = 120 + rng(s + 4000) * 80;
        drawComicBurst(ctx, sx, sy, size, word, color);
      }
    }
  }, [images, settings, selectedId, stickerSeed]);

  useEffect(() => {
    drawCollage();
  }, [drawCollage]);

  const handleCanvasMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!canvasRef.current || images.length === 0) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;

    const scaleX = canvasRef.current.width / rect.width;
    const scaleY = canvasRef.current.height / rect.height;
    const x = (clientX - rect.left) * scaleX;
    const y = (clientY - rect.top) * scaleY;

    // Use standard cell-based detection for simplicity
    const dims = getDimensions(images, settings);
    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);
      const rx = settings.padding + (col * (dims.cellWidth + settings.gap));
      const ry = settings.padding + (row * (dims.cellHeight + settings.gap));

      if (x >= rx && x <= rx + dims.cellWidth && y >= ry && y <= ry + dims.cellHeight) {
        setSelectedId(images[i].id);
        setIsDragging(true);
        dragStartRef.current = { x, y, initialX: images[i].transform.translateX, initialY: images[i].transform.translateY };
        break;
      }
    }
  };

  const handleCanvasMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDragging || !dragStartRef.current || !selectedId) return;
    const rect = canvasRef.current!.getBoundingClientRect();
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;

    const scaleX = canvasRef.current!.width / rect.width;
    const scaleY = canvasRef.current!.height / rect.height;
    const x = (clientX - rect.left) * scaleX;
    const y = (clientY - rect.top) * scaleY;

    updateImageTransform(selectedId, {
      translateX: dragStartRef.current.initialX + (x - dragStartRef.current.x),
      translateY: dragStartRef.current.initialY + (y - dragStartRef.current.y)
    });
  };

  const handleCanvasMouseUp = () => {
    setIsDragging(false);
    dragStartRef.current = null;
  };

  const downloadCollage = () => {
    if (!canvasRef.current) return;
    const link = document.createElement('a');
    link.download = `comic-stitch-${Date.now()}.jpg`;
    link.href = canvasRef.current.toDataURL('image/jpeg', settings.quality);
    link.click();
  };

  return (
    <div className="min-h-screen flex flex-col lg:flex-row bg-[#0B0E14] text-slate-100 selection:bg-indigo-500/30">
      <aside className="w-full lg:w-80 bg-[#161B22] border-r border-slate-800 overflow-y-auto p-5 space-y-6 sticky top-0 h-screen hidden lg:block scrollbar-hide">
        <div className="flex items-center gap-3 mb-6">
          <div className="p-2 bg-indigo-500 rounded-xl shadow-lg shadow-indigo-500/20">
            <LayoutGrid className="w-5 h-5 text-white" />
          </div>
          <h1 className="text-lg font-black tracking-tighter uppercase text-white">Stitcher</h1>
        </div>

        <section className="space-y-3">
          <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-slate-500 flex items-center gap-2">
            <Zap className="w-3 h-3 text-amber-400 fill-amber-400" /> 風格預設 Presets
          </h2>
          <div className="grid grid-cols-1 gap-2">
            <button onClick={() => applyPreset(PRESETS.COMIC)} className={`flex items-center justify-between px-3 py-2.5 bg-slate-800/50 border rounded-xl transition group text-xs font-bold ${settings.style === 'comic' ? 'border-indigo-500 bg-slate-800' : 'border-slate-700 hover:border-slate-500'}`}>
              <div className="flex items-center gap-2">
                <Zap className="w-4 h-4 text-amber-400" />
                <span>強烈斜切美漫</span>
              </div>
              <div className="px-1.5 py-0.5 rounded bg-amber-500/10 text-amber-500 text-[8px]">PRO</div>
            </button>
            <button onClick={() => applyPreset(PRESETS.POLAROID)} className="flex items-center justify-between px-3 py-2.5 bg-slate-800/50 border border-slate-700 rounded-xl hover:border-indigo-500 transition group text-xs font-medium">
              <div className="flex items-center gap-2">
                <Square className="w-4 h-4 text-slate-400" />
                <span>正方形拍立得</span>
              </div>
            </button>
            <button onClick={() => applyPreset(PRESETS.VINTAGE_90S)} className="flex items-center justify-between px-3 py-2.5 bg-slate-800/50 border border-slate-700 rounded-xl hover:border-indigo-500 transition group text-xs font-medium">
              <div className="flex items-center gap-2">
                <ImageIcon className="w-4 h-4 text-slate-400" />
                <span>90s 拼貼感</span>
              </div>
            </button>
            <button onClick={() => applyPreset(PRESETS.FOUR_PANEL)} className="flex items-center justify-between px-3 py-2.5 bg-slate-800/50 border border-slate-700 rounded-xl hover:border-indigo-500 transition group text-xs font-medium">
              <div className="flex items-center gap-2">
                <Columns2 className="w-4 h-4 text-slate-400" />
                <span>直條四格</span>
              </div>
            </button>
          </div>
        </section>

        <section className="space-y-4 pt-2">
          <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-slate-500 flex items-center gap-2">
            <Settings2 className="w-3 h-3" /> 版面 Layout
          </h2>

          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-1">
              <label className="text-[10px] text-slate-500 uppercase font-bold">Cols 欄</label>
              <input type="number" value={settings.columns} onChange={e => setSettings(s => ({ ...s, columns: Math.max(1, parseInt(e.target.value) || 1) }))} className="w-full bg-[#0D1117] border border-slate-700 rounded-lg p-2 text-sm outline-none" />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] text-slate-500 uppercase font-bold">Rows 列</label>
              <input type="number" value={settings.rows} onChange={e => setSettings(s => ({ ...s, rows: Math.max(1, parseInt(e.target.value) || 1) }))} className="w-full bg-[#0D1117] border border-slate-700 rounded-lg p-2 text-sm outline-none" />
            </div>
          </div>

          <div className="space-y-3">
            <div>
              <div className="flex justify-between items-center mb-1">
                <label className="text-[10px] text-slate-500 uppercase font-bold">Gap 間距</label>
                <span className="text-[10px] font-mono text-indigo-400">{settings.gap}px</span>
              </div>
              <input type="range" min="0" max="100" value={settings.gap} onChange={e => setSettings(s => ({ ...s, gap: parseInt(e.target.value) }))} className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500" />
            </div>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] text-slate-500 uppercase font-bold">BG Color 背景色</label>
            <div className="flex gap-2 p-1.5 bg-[#0D1117] border border-slate-700 rounded-lg">
              <input type="color" value={settings.backgroundColor} onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))} className="w-8 h-8 bg-transparent border-none cursor-pointer rounded-md overflow-hidden" />
              <input type="text" value={settings.backgroundColor.toUpperCase()} onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))} className="flex-1 bg-transparent border-none text-xs font-mono focus:outline-none uppercase" />
            </div>
          </div>
        </section>

        {selectedImage && (
          <section className="p-4 bg-indigo-500/5 rounded-2xl border border-indigo-500/20 space-y-4 animate-in slide-in-from-right-4">
            <div className="flex items-center justify-between">
              <h2 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest flex items-center gap-2">
                <Move className="w-3 h-3" /> 圖層 Layer
              </h2>
              <button onClick={() => setSelectedId(null)} className="text-slate-500 hover:text-white"><X className="w-4 h-4" /></button>
            </div>
            <div className="space-y-3">
              <label className="text-[10px] text-slate-500 uppercase font-bold block">Scale 縮放</label>
              <input type="range" min="0.5" max="4" step="0.01" value={selectedImage.transform.scale} onChange={e => updateImageTransform(selectedImage.id, { scale: parseFloat(e.target.value) })} className="w-full h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-indigo-400" />
              <button onClick={() => resetTransform(selectedImage.id)} className="w-full py-2 bg-slate-800 hover:bg-slate-700 text-[10px] uppercase font-black text-slate-300 transition rounded-lg">Reset Position</button>
            </div>
          </section>
        )}

        {settings.style === 'comic' && (
          <button onClick={() => setStickerSeed(Date.now())} className="w-full py-3 bg-amber-500/10 hover:bg-amber-500/20 text-amber-500 text-[10px] uppercase font-bold rounded-xl border border-amber-500/20 transition flex items-center justify-center gap-2">
            <RotateCcw className="w-3 h-3" /> 重隨隨機斜切與裝飾
          </button>
        )}

        <div className="pt-6 border-t border-slate-800">
          <button onClick={downloadCollage} disabled={images.length === 0} className="w-full flex items-center justify-center gap-2 py-4 px-4 rounded-2xl bg-indigo-500 hover:bg-indigo-400 disabled:opacity-30 disabled:cursor-not-allowed font-black text-white transition shadow-xl shadow-indigo-500/20 uppercase tracking-widest text-sm">
            <Download className="w-5 h-5" /> Export
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col h-screen overflow-hidden bg-[#0D1117]">
        <header className="px-6 py-4 bg-[#161B22] border-b border-slate-800 flex justify-between items-center z-10">
          <div className="flex items-center gap-3">
            <LayoutGrid className="w-5 h-5 text-indigo-500 lg:hidden" />
            <span className="font-black tracking-tighter text-sm uppercase">Studio Canvas</span>
          </div>
          <div className="flex items-center gap-4">
             <label className="cursor-pointer">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <div className="flex items-center gap-2 px-6 py-2.5 bg-indigo-500 hover:bg-indigo-400 rounded-full text-xs font-black transition shadow-lg shadow-indigo-500/20">
                <Upload className="w-4 h-4" />
                <span>上傳照片</span>
              </div>
            </label>
          </div>
        </header>

        <div className="flex-1 overflow-auto p-4 lg:p-12 flex items-center justify-center relative bg-[#0D1117]">
          {images.length === 0 ? (
            <div className="text-center space-y-4 max-w-sm">
              <div className="w-16 h-16 bg-[#161B22] rounded-2xl flex items-center justify-center mx-auto border border-slate-700">
                <ImageIcon className="w-6 h-6 text-slate-600" />
              </div>
              <h3 className="text-md font-black text-white uppercase tracking-widest">Start Stitching</h3>
              <p className="text-slate-500 text-xs px-10">上傳多張 JPG，點擊切換美漫風格，全畫布邏輯自動生成斜切邊框。</p>
            </div>
          ) : (
            <div className="relative group max-h-full">
              <div className="shadow-[0_60px_120px_-20px_rgba(0,0,0,0.8)] rounded-sm overflow-hidden border border-white/5">
                <canvas 
                  ref={canvasRef} 
                  onMouseDown={handleCanvasMouseDown}
                  onMouseMove={handleCanvasMouseMove}
                  onMouseUp={handleCanvasMouseUp}
                  onMouseLeave={handleCanvasMouseUp}
                  onTouchStart={handleCanvasMouseDown}
                  onTouchMove={handleCanvasMouseMove}
                  onTouchEnd={handleCanvasMouseUp}
                  style={{ cursor: isDragging ? 'grabbing' : 'grab' }}
                  className="max-w-full max-h-[78vh] object-contain mx-auto select-none touch-none bg-black"
                />
              </div>
              <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                <button onClick={() => { setImages([]); setSelectedId(null); }} className="p-3 bg-red-500/90 hover:bg-red-500 text-white rounded-xl shadow-2xl transition backdrop-blur-md">
                  <Trash2 className="w-5 h-5" />
                </button>
              </div>
            </div>
          )}
        </div>

        {images.length > 0 && (
          <div className="h-28 bg-[#161B22]/95 backdrop-blur-xl border-t border-slate-800 p-4 flex gap-4 overflow-x-auto items-center scrollbar-hide">
            {images.map((img) => (
              <div key={img.id} className="relative flex-shrink-0 group">
                <button
                  onClick={() => setSelectedId(img.id)}
                  className={`relative block h-16 w-16 overflow-hidden rounded-xl border-2 transition-all duration-300 ${
                    selectedId === img.id ? 'border-indigo-500 scale-110' : 'border-slate-800 hover:border-slate-600'
                  }`}
                >
                  <img src={img.preview} alt="Thumb" className="h-full w-full object-cover" />
                </button>
                <button onClick={(e) => { e.stopPropagation(); removeImage(img.id); }} className="absolute -top-1.5 -right-1.5 p-1 bg-red-500 rounded-full text-white transition opacity-0 group-hover:opacity-100 scale-75">
                  <X className="w-3 h-3" />
                </button>
              </div>
            ))}
            <label className="flex-shrink-0 h-16 w-16 flex items-center justify-center border-2 border-dashed border-slate-800 rounded-xl hover:border-indigo-500 hover:bg-indigo-500/5 cursor-pointer transition">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <Upload className="w-4 h-4 text-slate-600" />
            </label>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;
